-- ═══════════════════════════════════════════════════════
-- Question bank import
-- Run in: Supabase → SQL Editor → New query → Run
--
-- Wrapped in a transaction: if any row fails, nothing is
-- inserted and the bank is left exactly as it was.
-- Running it twice inserts the questions twice, so run once.
-- ═══════════════════════════════════════════════════════

begin;

-- 11-community-epi-system.txt — 25 questions
with b as (
  insert into tests (title, topic, difficulty, duration_minutes)
  values ($x$Batch 11 — Community Health: epidemiology, biostatistics, health system$x$, $x$Community Health Nursing$x$, 'medium', 60)
  returning id
)
insert into questions (test_id, position, question, options, correct_index, explanation, topic, difficulty)
select b.id, v.pos::int, v.question, v.options::jsonb, v.ci::int, v.exp, v.topic, v.diff
from b, (values
  (0, $x$The proportion of new cases of a disease occurring in a defined population over a specified period is the$x$, $x$["Case fatality rate","Prevalence rate","Attack rate","Incidence rate"]$x$, 3, $x$Incidence counts new cases arising over a period and measures the risk of developing the disease. Prevalence counts all existing cases at a point in time and reflects both incidence and duration.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (1, $x$Point prevalence is best defined as the number of$x$, $x$["Deaths among diagnosed cases","Existing cases at a given point in time, per population at that point","New cases occurring during a period","Cases exposed to a specific source"]$x$, 1, $x$Point prevalence is all current cases, old and new, divided by the population at that moment. It rises when incidence increases or when cases live longer, and falls with cure or death.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (2, $x$In an outbreak investigation, the attack rate is calculated as the number of$x$, $x$["New cases per 1000 mid-year population per year","Exposed persons divided by cases","Cases divided by the total population at risk, over the outbreak period","Deaths divided by cases"]$x$, 2, $x$The attack rate is a form of incidence used in a defined epidemic over a limited time, expressed as cases per persons exposed, usually as a percentage. Comparing attack rates across exposures points to the likely source.$x$, $x$Community Health Nursing$x$, $x$hard$x$),
  (3, $x$The type of epidemiological study that begins with the outcome and looks backward for exposure is a$x$, $x$["Randomised controlled trial","Cohort study","Cross-sectional study","Case-control study"]$x$, 3, $x$A case-control study compares people with the disease to those without, looking back at past exposures, and yields an odds ratio. It is efficient for rare diseases and for those with a long latent period.$x$, $x$Community Health Nursing$x$, $x$hard$x$),
  (4, $x$A cohort study measures association using the$x$, $x$["Relative risk","Correlation coefficient","Odds ratio","Prevalence ratio"]$x$, 0, $x$A cohort follows exposed and unexposed groups forward to see who develops disease, giving incidence in each and therefore relative risk. Case-control studies, which cannot measure incidence directly, use the odds ratio instead.$x$, $x$Community Health Nursing$x$, $x$hard$x$),
  (5, $x$The gold standard study design for evaluating a new treatment is the$x$, $x$["Case report","Randomised controlled trial","Ecological study","Case series"]$x$, 1, $x$Random allocation balances known and unknown confounders between groups, so differences in outcome can be attributed to the intervention. Blinding and allocation concealment further protect against bias.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (6, $x$The positive predictive value of a screening test is the probability that a person with a positive result$x$, $x$["Will be missed by the test","Truly has the disease","Truly does not have the disease","Was correctly exposed"]$x$, 1, $x$Positive predictive value depends on the test's sensitivity and specificity and, crucially, on the prevalence of the disease. In a low-prevalence population even a good test throws up many false positives, lowering the predictive value.$x$, $x$Community Health Nursing$x$, $x$hard$x$),
  (7, $x$A screening test that gives the same result on repeated testing is said to be$x$, $x$["Valid","Sensitive","Specific","Reliable"]$x$, 3, $x$Reliability is consistency on repetition, whereas validity is the ability to measure the truth. A test can be highly reliable yet consistently wrong, so both properties are assessed separately.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (8, $x$Lead time bias in screening refers to$x$, $x$["Over-diagnosis of harmless disease","Detecting disease earlier without changing the actual outcome, so survival only appears longer","Errors in recording the time of death","Selecting healthier volunteers for screening"]$x$, 1, $x$Screening advances the moment of diagnosis, so survival measured from diagnosis looks longer even if death occurs at the same time. Sound evaluation of a screening programme therefore uses mortality, not survival time.$x$, $x$Community Health Nursing$x$, $x$hard$x$),
  (9, $x$The standardised death rate is used to$x$, $x$["Count only deaths in hospital","Compare mortality between populations with different age structures","Measure infant deaths alone","Record cause-specific mortality only"]$x$, 1, $x$Crude death rates cannot be compared fairly when populations differ in age, since age strongly affects death. Standardisation applies each population's rates to a common reference age structure, removing that distortion.$x$, $x$Community Health Nursing$x$, $x$hard$x$),
  (10, $x$The under-five mortality rate is expressed per$x$, $x$["1000 mid-year population","1000 children under five","100000 live births","1000 live births"]$x$, 3, $x$The under-five mortality rate is deaths before the fifth birthday per 1000 live births, a key indicator of child health and of the effectiveness of maternal and child services. It is distinct from the child death rate, which uses the population aged 1 to 4.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (11, $x$The neonatal period covers the first$x$, $x$["42 days of life","7 days of life","24 hours of life","28 days of life"]$x$, 3, $x$The neonatal period is the first 28 days, subdivided into early neonatal, the first 7 days, and late neonatal. Most neonatal deaths occur in the first week, which is why early care matters so much.$x$, $x$Community Health Nursing$x$, $x$easy$x$),
  (12, $x$The general fertility rate uses as its denominator the number of$x$, $x$["Total population","Women in the reproductive age group, usually 15 to 49 years","Live births","Married women only"]$x$, 1, $x$Unlike the crude birth rate, which uses the whole population, the general fertility rate restricts the denominator to women aged 15 to 49, giving a more refined measure of fertility.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (13, $x$A total fertility rate of about 2.1 in a population is significant because it represents$x$, $x$["The replacement level of fertility","Rapid population growth","A declining and ageing population immediately","Zero births"]$x$, 0, $x$A total fertility rate near 2.1 children per woman just replaces the parents while allowing for childhood mortality, so the population eventually stabilises. India reached around this level nationally, though it varies by state.$x$, $x$Community Health Nursing$x$, $x$hard$x$),
  (14, $x$The dependency ratio compares the population aged under 15 and over 65 to those$x$, $x$["Living in urban areas","Who are employed only","Who are literate","In the working ages, roughly 15 to 64"]$x$, 3, $x$The dependency ratio expresses the non-working young and old against the economically productive ages, indicating the burden of support. A youthful population and an ageing one both raise it, for different reasons.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (15, $x$In the demographic cycle, the stage marked by a falling death rate while the birth rate stays high, producing rapid growth, is$x$, $x$["Early expanding","Low stationary","High stationary","Late expanding"]$x$, 0, $x$In the early expanding stage improved sanitation, nutrition and medicine cut deaths while births remain high, so the population grows fastest. In the late expanding stage the birth rate too begins to fall.$x$, $x$Community Health Nursing$x$, $x$hard$x$),
  (16, $x$A community health centre in India is designed to serve a population of approximately$x$, $x$["5000","30000","120000","500000"]$x$, 2, $x$A community health centre covers about 120,000 people in the plains and 80,000 in hilly or tribal areas, acting as a first referral unit with specialists and beds. Below it sit the primary health centre and the sub-centre.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (17, $x$The first referral unit providing specialist care such as caesarean section and blood transfusion in rural India is the$x$, $x$["Primary health centre","Sub-centre","Community health centre","Anganwadi"]$x$, 2, $x$The community health centre is designated as the first referral unit, staffed with specialists in surgery, medicine, obstetrics and paediatrics, with an operation theatre, laboratory and blood storage. The primary health centre refers upward to it.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (18, $x$The most peripheral institution and the first point of contact between the primary health care system and the community is the$x$, $x$["Sub-centre","District hospital","Community health centre","Primary health centre"]$x$, 0, $x$The sub-centre, staffed by an auxiliary nurse midwife and a male health worker, is the most peripheral contact point, focused on maternal and child health, family welfare, immunisation and control of communicable disease.$x$, $x$Community Health Nursing$x$, $x$easy$x$),
  (19, $x$The auxiliary nurse midwife at a sub-centre is primarily responsible for$x$, $x$["Maternal and child health, immunisation and family welfare services","Laboratory diagnosis of malaria only","District-level administration","Performing major surgery"]$x$, 0, $x$The ANM delivers antenatal and postnatal care, conducts and refers deliveries, gives immunisations, promotes family planning and treats minor ailments. She is the backbone of maternal and child health at the periphery.$x$, $x$Community Health Nursing$x$, $x$easy$x$),
  (20, $x$In India, the multipurpose health worker scheme integrates the functions of$x$, $x$["Doctors and specialists","Hospital administrators","Previously separate unipurpose workers such as malaria, family planning and smallpox staff","Private practitioners"]$x$, 2, $x$The multipurpose worker scheme, following the Kartar Singh committee, merged the many single-purpose field workers into male and female multipurpose workers, so one worker delivers a range of services to each family rather than several visiting separately.$x$, $x$Community Health Nursing$x$, $x$hard$x$),
  (21, $x$Primary health care was declared as the key to attaining Health for All at the international conference held at$x$, $x$["Geneva","Bangkok","Alma-Ata","Ottawa"]$x$, 2, $x$The 1978 Alma-Ata declaration proclaimed primary health care as the route to Health for All. The later Ottawa Charter of 1986 developed the framework for health promotion.$x$, $x$Community Health Nursing$x$, $x$easy$x$),
  (22, $x$Health promotion, as described in the Ottawa Charter, is best understood as$x$, $x$["Building more hospitals","Providing free medicines","Treating disease early","The process of enabling people to increase control over and improve their health"]$x$, 3, $x$The Ottawa Charter defines health promotion as enabling people to gain control over the determinants of health, through healthy public policy, supportive environments, community action, personal skills and reoriented services.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (23, $x$The measure of the average number of years a person is expected to live, widely used to summarise a population's health, is$x$, $x$["Total fertility rate","Crude death rate","Infant mortality rate","Life expectancy at birth"]$x$, 3, $x$Life expectancy at birth is the average number of years a newborn would live under current mortality conditions, a summary indicator sensitive to deaths at all ages, especially in infancy.$x$, $x$Community Health Nursing$x$, $x$easy$x$),
  (24, $x$The disability-adjusted life year, or DALY, combines$x$, $x$["The number of hospital beds and doctors","Years of life lost to premature death and years lived with disability","Only years of life lost to death","Income and literacy"]$x$, 1, $x$One DALY is one lost year of healthy life, summing years lost to premature mortality and years lived with disability weighted for severity. It allows the total burden of a disease, fatal and non-fatal, to be compared.$x$, $x$Community Health Nursing$x$, $x$hard$x$)
) as v(pos, question, options, ci, exp, topic, diff);

-- 12-community-programmes.txt — 25 questions
with b as (
  insert into tests (title, topic, difficulty, duration_minutes)
  values ($x$Batch 12 — Community Health: national programmes, MCH, environment, nutrition$x$, $x$Community Health Nursing$x$, 'medium', 60)
  returning id
)
insert into questions (test_id, position, question, options, correct_index, explanation, topic, difficulty)
select b.id, v.pos::int, v.question, v.options::jsonb, v.ci::int, v.exp, v.topic, v.diff
from b, (values
  (0, $x$The national tuberculosis programme in India now aims to end TB by$x$, $x$["2025","2030","2040","2050"]$x$, 0, $x$The National TB Elimination Programme targets ending TB in India by 2025, five years ahead of the global Sustainable Development Goal of 2030. It relies on early diagnosis, assured treatment, patient support and active case finding.$x$, $x$Community Health Nursing$x$, $x$hard$x$),
  (1, $x$The first-line treatment for a new case of pulmonary tuberculosis uses$x$, $x$["Antibiotics for one week","A combination of at least four drugs in the intensive phase","A single drug for six months","Surgery"]$x$, 1, $x$Standard treatment begins with isoniazid, rifampicin, pyrazinamide and ethambutol in the intensive phase, then continues with fewer drugs. Multiple drugs prevent the selection of resistant organisms, and the full course must be completed.$x$, $x$Community Health Nursing$x$, $x$hard$x$),
  (2, $x$Under the national programme, leprosy is confirmed as multibacillary when there are$x$, $x$["A single skin lesion","Only nerve thickening","No skin lesions","More than five skin lesions"]$x$, 3, $x$Leprosy is classified for treatment by lesion count: up to five lesions is paucibacillary and more than five is multibacillary, which needs longer multidrug therapy. The classification guides the duration of treatment.$x$, $x$Community Health Nursing$x$, $x$hard$x$),
  (3, $x$The vector of dengue, which breeds in clean stored water, is$x$, $x$["Culex mosquito","Anopheles mosquito","Housefly","Aedes aegypti"]$x$, 3, $x$Aedes aegypti, a day-biting mosquito that breeds in clean water in containers, coolers and discarded tyres, transmits dengue, chikungunya, Zika and yellow fever. Source reduction by removing breeding sites is the mainstay of control.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (4, $x$The warning signs of dengue that indicate progression to severe disease include$x$, $x$["Mild fever only","A single episode of headache","Severe abdominal pain, persistent vomiting and bleeding","Improved appetite"]$x$, 2, $x$Warning signs such as severe abdominal pain, persistent vomiting, mucosal bleeding, lethargy and a rapidly falling platelet count herald plasma leakage and shock. Recognising them prompts urgent hospital care and fluid management.$x$, $x$Community Health Nursing$x$, $x$hard$x$),
  (5, $x$In the national immunisation schedule, the pentavalent vaccine protects against diphtheria, pertussis, tetanus, hepatitis B and$x$, $x$["Polio","Tuberculosis","Haemophilus influenzae type b","Measles"]$x$, 2, $x$The pentavalent vaccine combines DPT with hepatitis B and Haemophilus influenzae type b, given at 6, 10 and 14 weeks. Combining antigens reduces the number of injections and improves coverage.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (6, $x$A fully immunised child under the national schedule has received all due vaccines by the age of$x$, $x$["1 year","6 weeks","5 years","6 months"]$x$, 0, $x$A child is counted as fully immunised when BCG, three doses of pentavalent and OPV, and the first measles-rubella dose have been received by one year of age. Coverage by one year is a standard programme indicator.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (7, $x$Pulse polio immunisation is based on the strategy of$x$, $x$["Giving oral polio vaccine to all children under five on fixed national immunisation days","Treating cases after paralysis","Injecting vaccine once in a lifetime","Vaccinating only sick children"]$x$, 0, $x$Pulse polio delivers oral polio vaccine to every child under five on national immunisation days regardless of prior doses, interrupting transmission by rapidly raising community immunity. It underpinned India's polio-free certification in 2014.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (8, $x$Iron and folic acid supplementation in pregnancy is given primarily to prevent$x$, $x$["Hypertension","Urinary infection","Gestational diabetes","Nutritional anaemia"]$x$, 3, $x$Anaemia is very common in pregnancy and raises the risk of preterm birth, low birth weight and maternal death. Routine iron and folic acid, with deworming, is a core antenatal intervention, and folic acid also prevents neural tube defects.$x$, $x$Community Health Nursing$x$, $x$easy$x$),
  (9, $x$The most sensitive indicator of the overall health status of a community is generally taken to be the$x$, $x$["Infant mortality rate","Sex ratio","Literacy rate","Crude birth rate"]$x$, 0, $x$The infant mortality rate responds to nutrition, maternal health, sanitation, immunisation and access to care, so it captures the overall conditions of a society and is widely used as a summary health indicator.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (10, $x$The permissible upper limit of fluoride in drinking water, above which dental and skeletal fluorosis occur, is about$x$, $x$["0.5 mg per litre","1.0 to 1.5 mg per litre","5 mg per litre","10 mg per litre"]$x$, 1, $x$Fluoride around 1 mg per litre protects against dental caries, but above roughly 1.5 mg per litre it mottles the teeth and, at higher and prolonged levels, damages bone. Both too little and too much are undesirable.$x$, $x$Community Health Nursing$x$, $x$hard$x$),
  (11, $x$The most important indicator of recent faecal contamination of water is the presence of$x$, $x$["Fluoride","Chlorine","Total dissolved solids","Escherichia coli"]$x$, 3, $x$Escherichia coli is a normal gut organism, so its presence in water signals recent faecal contamination and the possible presence of pathogens. It is the standard bacteriological indicator of drinking water safety.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (12, $x$In biomedical waste segregation, human anatomical waste and soiled waste requiring incineration are placed in the$x$, $x$["White puncture-proof container","Blue container","Yellow container","Red container"]$x$, 2, $x$Under the biomedical waste rules, yellow is for anatomical and infectious soiled waste destined for incineration, red for contaminated recyclable plastics, white for sharps and blue for glassware and metallic implants.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (13, $x$The recommended method for final disposal of the placenta and other anatomical hospital waste is$x$, $x$["Flushing down the drain","Open dumping","Discarding with general refuse","Deep burial or incineration as infectious waste"]$x$, 3, $x$Anatomical waste is infectious and is treated as yellow-category biomedical waste, disposed of by incineration or, where that is unavailable, by deep burial in a secure pit. It must never enter the general waste stream.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (14, $x$Grade I protein energy malnutrition by the Indian Academy of Pediatrics classification corresponds to a weight for age of$x$, $x$["70 to 80 per cent of expected","50 to 60 per cent of expected","90 to 100 per cent of expected","Below 50 per cent of expected"]$x$, 0, $x$The IAP classification grades malnutrition by weight for age: 70 to 80 per cent is grade I, 60 to 70 grade II, 50 to 60 grade III and below 50 per cent grade IV. It is a simple field tool for identifying and grading undernutrition.$x$, $x$Community Health Nursing$x$, $x$hard$x$),
  (15, $x$Mid-upper arm circumference is used in the community to screen for acute malnutrition in children aged$x$, $x$["6 months to 5 years","Under 6 months","5 to 10 years","Over 10 years"]$x$, 0, $x$In children aged 6 to 59 months the mid-upper arm circumference changes little with age, so a fixed cut-off works: below 11.5 cm indicates severe acute malnutrition. It is quick, needs no scales and is ideal for field screening.$x$, $x$Community Health Nursing$x$, $x$hard$x$),
  (16, $x$Vitamin A deficiency is a leading preventable cause of$x$, $x$["Goitre","Deafness","Rickets","Childhood blindness"]$x$, 3, $x$Vitamin A deficiency causes night blindness progressing to xerophthalmia and irreversible corneal damage, and it also worsens infection. Prophylactic vitamin A given six-monthly to young children prevents it.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (17, $x$The addition of iodine to salt is the national strategy to prevent$x$, $x$["Fluorosis","Vitamin A deficiency","Iodine deficiency disorders such as goitre and cretinism","Anaemia"]$x$, 2, $x$Universal salt iodisation is the cornerstone of preventing iodine deficiency disorders, which range from goitre to the severe and irreversible mental and physical impairment of cretinism when deficiency occurs in pregnancy.$x$, $x$Community Health Nursing$x$, $x$easy$x$),
  (18, $x$The incubation period of measles, from exposure to the appearance of rash, is approximately$x$, $x$["30 days","1 to 2 days","10 to 14 days","3 months"]$x$, 2, $x$Measles has an incubation period of about 10 to 14 days. The patient is infectious from a few days before the rash until about four days after it appears, which is why isolation and prompt vaccination of contacts matter.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (19, $x$Chickenpox is caused by the$x$, $x$["Rubella virus","Varicella zoster virus","Measles virus","Mumps virus"]$x$, 1, $x$The varicella zoster virus causes chickenpox on first infection and, on reactivation years later, herpes zoster or shingles. Its lesions appear in successive crops, giving the characteristic mix of papules, vesicles and crusts.$x$, $x$Community Health Nursing$x$, $x$easy$x$),
  (20, $x$The most effective single strategy to interrupt the faeco-oral transmission of diseases such as cholera and typhoid is$x$, $x$["Bed nets","Mass antibiotic use","Vaccination alone","Improved sanitation and safe water supply"]$x$, 3, $x$Faeco-oral diseases spread through contaminated water and food, so safe water, sanitary excreta disposal, hand hygiene and food safety break the chain most effectively. Vaccines and treatment supplement, but do not replace, these environmental measures.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (21, $x$A sudden increase in cases of a disease clearly in excess of what is normally expected in a community is a/an$x$, $x$["Epidemic","Sporadic occurrence","Endemic","Pandemic across continents"]$x$, 0, $x$An epidemic is the occurrence of cases clearly above the expected number for that place and time. When such an epidemic spreads across several countries and continents it is called a pandemic.$x$, $x$Community Health Nursing$x$, $x$easy$x$),
  (22, $x$Convalescent carriers are individuals who$x$, $x$["Have never had the disease but harbour the organism","Are immune and non-infectious","Continue to shed the organism during recovery after clinical illness","Show symptoms permanently"]$x$, 2, $x$A convalescent carrier keeps excreting the organism during recovery, as in typhoid. Carriers may also be incubatory, shedding before symptoms, or healthy, never developing illness, and all can maintain transmission unnoticed.$x$, $x$Community Health Nursing$x$, $x$hard$x$),
  (23, $x$Passive immunity is conferred by$x$, $x$["Administering preformed antibodies such as immunoglobulin or antiserum","Giving a vaccine","A course of antibiotics","Natural infection"]$x$, 0, $x$Passive immunity supplies ready-made antibodies, as in anti-tetanus or anti-rabies immunoglobulin and in the transfer of maternal antibody to the fetus. It acts at once but is short-lived, unlike the durable protection of active immunisation.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (24, $x$The observation period for a person exposed to a suspected case, kept under surveillance for the maximum incubation period, is called$x$, $x$["Disinfection","Isolation","Quarantine","Notification"]$x$, 2, $x$Quarantine restricts the movement of apparently well people who have been exposed, for the longest usual incubation period, to watch for illness. Isolation, by contrast, separates those who are already sick to prevent spread.$x$, $x$Community Health Nursing$x$, $x$medium$x$)
) as v(pos, question, options, ci, exp, topic, diff);

-- 13-gap-fillers.txt — 23 questions
with b as (
  insert into tests (title, topic, difficulty, duration_minutes)
  values ($x$Batch 13 — filling thin filter cells: Mental Health (easy), and breadth across subjects$x$, $x$Mixed$x$, 'medium', 60)
  returning id
)
insert into questions (test_id, position, question, options, correct_index, explanation, topic, difficulty)
select b.id, v.pos::int, v.question, v.options::jsonb, v.ci::int, v.exp, v.topic, v.diff
from b, (values
  (0, $x$A state of calm alertness in which a person can attend, learn and solve problems best describes$x$, $x$["Panic","Depersonalisation","Mild anxiety","Severe anxiety"]$x$, 2, $x$Mild anxiety sharpens attention and can improve learning and performance. As anxiety rises to moderate, severe and panic levels, the field of perception narrows until the person can no longer function.$x$, $x$Mental Health Nursing$x$, $x$easy$x$),
  (1, $x$Empathy in the nurse-patient relationship means$x$, $x$["Feeling sorry for the patient","Agreeing with everything the patient says","Ignoring the patient's emotions","Understanding and sharing the patient's feelings while staying objective"]$x$, 3, $x$Empathy is entering into and understanding another's feelings while keeping enough objectivity to help. It differs from sympathy, which is feeling sorry for someone and can cloud professional judgement.$x$, $x$Mental Health Nursing$x$, $x$easy$x$),
  (2, $x$The best therapeutic response when a patient is silent during an interview is to$x$, $x$["Fill every pause with questions","End the session immediately","Change the subject at once","Allow the silence, showing attentive presence"]$x$, 3, $x$Silence is a valuable therapeutic technique that gives the patient time to think and to gather difficult feelings. Rushing to fill it can cut off important disclosures, whereas attentive presence conveys acceptance.$x$, $x$Mental Health Nursing$x$, $x$easy$x$),
  (3, $x$Good mental health is best described as$x$, $x$["A state of well-being in which a person copes with normal stresses, works productively and contributes to the community","Complete independence from others","The mere absence of mental illness","Never feeling sad or anxious"]$x$, 0, $x$WHO defines mental health as a state of well-being in which the individual realises their abilities, copes with normal stresses, works productively and contributes to their community. It is more than simply the absence of disorder.$x$, $x$Mental Health Nursing$x$, $x$easy$x$),
  (4, $x$A recurrent, unwanted thought that intrudes despite the person's efforts to resist it is a/an$x$, $x$["Delusion","Illusion","Obsession","Hallucination"]$x$, 2, $x$An obsession is an intrusive, repetitive thought the person recognises as their own and tries to resist, unlike a delusion, which is a fixed false belief held with conviction and without insight.$x$, $x$Mental Health Nursing$x$, $x$easy$x$),
  (5, $x$Rapport in a therapeutic relationship refers to$x$, $x$["A relationship of trust and mutual understanding","A prescription of medication","A physical examination","A legal contract"]$x$, 0, $x$Rapport is the sense of trust, harmony and understanding between nurse and patient. Establishing it early, through warmth, respect and genuineness, is the foundation on which all later therapeutic work rests.$x$, $x$Mental Health Nursing$x$, $x$easy$x$),
  (6, $x$The defence mechanism of denial involves$x$, $x$["Channelling urges into acceptable activity","Returning to childlike behaviour","Blaming others for one's own faults","Refusing to accept a painful reality"]$x$, 3, $x$Denial protects the person by refusing to acknowledge a distressing fact, as when a newly diagnosed patient insists the results must be wrong. It is common early in grief and usually gives way as the person adjusts.$x$, $x$Mental Health Nursing$x$, $x$easy$x$),
  (7, $x$A person's awareness of time, place and person is assessed as$x$, $x$["Memory","Insight","Judgement","Orientation"]$x$, 3, $x$Orientation to time, place and person is a basic part of the mental state examination and of consciousness. Disorientation, especially to time first, is an early sign of an acute confusional state.$x$, $x$Mental Health Nursing$x$, $x$easy$x$),
  (8, $x$The normal respiratory rate in a resting adult is$x$, $x$["6 to 10 breaths per minute","12 to 20 breaths per minute","25 to 30 breaths per minute","30 to 40 breaths per minute"]$x$, 1, $x$A healthy adult breathes 12 to 20 times per minute at rest. Below 12 is bradypnoea and above 20 is tachypnoea, both of which warrant assessment for an underlying cause.$x$, $x$Basic Sciences$x$, $x$easy$x$),
  (9, $x$The largest organ of the human body is the$x$, $x$["Skin","Lung","Liver","Brain"]$x$, 0, $x$The skin is the largest organ, forming a protective barrier and playing roles in temperature regulation, sensation, immunity and vitamin D synthesis. The liver is the largest internal solid organ.$x$, $x$Basic Sciences$x$, $x$easy$x$),
  (10, $x$The master gland of the endocrine system, which controls several other glands, is the$x$, $x$["Pancreas","Thyroid","Adrenal","Pituitary"]$x$, 3, $x$The pituitary is called the master gland because its hormones regulate the thyroid, adrenal cortex, gonads and more. It is itself directed by the hypothalamus, to which it is closely connected.$x$, $x$Basic Sciences$x$, $x$easy$x$),
  (11, $x$The universal recipient blood group, able to receive red cells from any ABO group, is$x$, $x$["AB positive","B positive","O positive","A positive"]$x$, 0, $x$Group AB has no anti-A or anti-B antibodies in the plasma, so it can receive red cells of any ABO group, making AB the universal recipient. Group O negative, lacking A, B and RhD antigens, is the universal red cell donor.$x$, $x$Basic Sciences$x$, $x$medium$x$),
  (12, $x$The vitamin synthesised by bacteria in the large intestine and needed for blood clotting is$x$, $x$["Vitamin B12","Vitamin A","Vitamin K","Vitamin C"]$x$, 2, $x$Gut bacteria produce vitamin K, which the liver needs to make clotting factors II, VII, IX and X. Newborns, whose gut is not yet colonised, are given vitamin K at birth to prevent haemorrhagic disease.$x$, $x$Basic Sciences$x$, $x$medium$x$),
  (13, $x$The first sign a nurse should act on when a patient's oxygen saturation is falling is$x$, $x$["To document it at the end of the shift","To remove the pulse oximeter","To assess the patient, check the airway and breathing, and give oxygen as needed","To wait for the next scheduled observation"]$x$, 2, $x$A falling saturation calls for immediate bedside assessment of airway, breathing and circulation and appropriate oxygen, not delay. Confirming the reading and looking at the whole patient comes before charting.$x$, $x$Nursing Foundations$x$, $x$easy$x$),
  (14, $x$The correct sequence for putting on personal protective equipment is$x$, $x$["Goggles, gloves, gown, mask","Mask, gloves, gown, goggles","Gown, mask, goggles, gloves","Gloves, gown, mask, goggles"]$x$, 2, $x$Protective equipment is donned gown first, then mask or respirator, then eye protection, and gloves last so they cover the gown cuffs. Removal reverses the principle, taking off the most contaminated items first while avoiding self-contamination.$x$, $x$Nursing Foundations$x$, $x$medium$x$),
  (15, $x$When a medication error reaches a patient, the nurse's first responsibility is to$x$, $x$["Assess the patient, ensure safety, report the error and document it honestly","Wait to see if any harm develops","Blame the pharmacy","Hide the error to avoid blame"]$x$, 0, $x$Patient safety comes first, so the nurse assesses and monitors the patient, informs the prescriber, and reports the incident truthfully. Open reporting supports learning and system improvement rather than concealment.$x$, $x$Nursing Foundations$x$, $x$medium$x$),
  (16, $x$A wound healing by primary intention is one that$x$, $x$["Is heavily infected","Heals only with a skin graft","Is left open to granulate from the base","Has clean, approximated edges, such as a sutured surgical incision"]$x$, 3, $x$Primary intention healing occurs when clean wound edges are brought together, as with sutures, giving quick healing and minimal scarring. Wounds left open to fill with granulation tissue heal by secondary intention.$x$, $x$Medical-Surgical Nursing$x$, $x$medium$x$),
  (17, $x$The earliest local sign of acute inflammation includes$x$, $x$["Dryness and scaling","Pallor and coldness","Numbness","Redness, heat, swelling and pain"]$x$, 3, $x$The classic signs of acute inflammation are redness, heat, swelling, pain and loss of function, caused by increased blood flow and vascular permeability. They reflect the body's protective response to injury or infection.$x$, $x$Medical-Surgical Nursing$x$, $x$easy$x$),
  (18, $x$A diabetic patient should be taught to inspect which part of the body daily to prevent serious complications?$x$, $x$["The elbows","The back","The feet","The scalp"]$x$, 2, $x$Diabetic neuropathy and poor circulation make foot ulcers and infection common and easily missed, so daily inspection, good footwear and prompt care of any lesion are essential to prevent amputation.$x$, $x$Medical-Surgical Nursing$x$, $x$medium$x$),
  (19, $x$The recommended position for a woman in the later stages of pregnancy to improve blood flow to the fetus is$x$, $x$["Standing","Prone","Left lateral","Supine, lying flat on the back"]$x$, 2, $x$Lying on the back late in pregnancy lets the heavy uterus compress the inferior vena cava, reducing venous return and fetal blood flow. The left lateral position relieves this pressure and improves circulation to the placenta.$x$, $x$Obstetrics & Child Health$x$, $x$medium$x$),
  (20, $x$The first breastfeed for a healthy newborn should ideally be initiated$x$, $x$["Within the first hour of birth","After the first bath","Only after the cord falls off","After 24 hours"]$x$, 0, $x$Early initiation of breastfeeding within the first hour gives the baby protective colostrum, promotes bonding, stimulates milk production and helps the uterus contract. It is a key element of newborn care.$x$, $x$Obstetrics & Child Health$x$, $x$easy$x$),
  (21, $x$The most common cause of neonatal death in India, alongside infection and birth asphyxia, is$x$, $x$["Prematurity and low birth weight","Injury","Congenital heart disease","Poisoning"]$x$, 0, $x$Prematurity and low birth weight, together with infections such as sepsis and pneumonia and with birth asphyxia, account for most neonatal deaths. Warmth, early feeding, hygiene and prompt treatment of infection address them.$x$, $x$Obstetrics & Child Health$x$, $x$hard$x$),
  (22, $x$The screening test routinely offered to all newborns to detect congenital hypothyroidism relies on measuring$x$, $x$["Bilirubin","Thyroid stimulating hormone","Haemoglobin","Blood glucose"]$x$, 1, $x$Congenital hypothyroidism causes irreversible intellectual disability if untreated, but is easily corrected with thyroxine if caught early. Newborn screening measures thyroid stimulating hormone, which is raised in the condition.$x$, $x$Obstetrics & Child Health$x$, $x$hard$x$)
) as v(pos, question, options, ci, exp, topic, diff);

-- 14-basic-sciences-2.txt — 30 questions
with b as (
  insert into tests (title, topic, difficulty, duration_minutes)
  values ($x$w1-basic — ingested draft, verify before trusting$x$, $x$Basic Sciences$x$, 'medium', 60)
  returning id
)
insert into questions (test_id, position, question, options, correct_index, explanation, topic, difficulty)
select b.id, v.pos::int, v.question, v.options::jsonb, v.ci::int, v.exp, v.topic, v.diff
from b, (values
  (0, $x$Which of the following is an example of a hinge joint?$x$, $x$["Wrist joint","Elbow joint","Atlanto-axial joint","Shoulder joint"]$x$, 1, $x$Hinge joints permit movement in a single plane of flexion and extension, and the elbow is a classic example. The shoulder is a ball-and-socket joint, the atlanto-axial is a pivot joint, and the wrist is a condyloid joint.$x$, $x$Basic Sciences$x$, $x$easy$x$),
  (1, $x$The structural and functional unit of compact bone is the$x$, $x$["Osteon or Haversian system","Lamella","Osteocyte","Trabecula"]$x$, 0, $x$The osteon, or Haversian system, is the structural unit of compact bone and consists of concentric lamellae surrounding a central Haversian canal. Trabeculae are the corresponding units of spongy cancellous bone.$x$, $x$Basic Sciences$x$, $x$medium$x$),
  (2, $x$In a myelinated nerve fibre the action potential jumps between the nodes of Ranvier. This rapid mode of conduction is called$x$, $x$["Antidromic conduction","Decremental conduction","Continuous conduction","Saltatory conduction"]$x$, 3, $x$In myelinated axons the myelin insulates the internodal segments, so the impulse leaps from one node of Ranvier to the next, called saltatory conduction. This greatly increases the speed of nerve conduction.$x$, $x$Basic Sciences$x$, $x$medium$x$),
  (3, $x$How many cervical vertebrae are present in the human vertebral column?$x$, $x$["4","5","7","12"]$x$, 2, $x$The vertebral column contains 7 cervical vertebrae, followed by 12 thoracic, 5 lumbar, the fused sacrum, and the coccyx. Almost all mammals, regardless of neck length, share the count of seven cervical vertebrae.$x$, $x$Basic Sciences$x$, $x$easy$x$),
  (4, $x$The neurotransmitter released at the neuromuscular junction of skeletal muscle is$x$, $x$["Noradrenaline","GABA","Acetylcholine","Dopamine"]$x$, 2, $x$Motor neurons release acetylcholine at the neuromuscular junction, where it binds nicotinic receptors on the muscle end plate to trigger contraction. Noradrenaline, dopamine and GABA act at other sites in the nervous system.$x$, $x$Basic Sciences$x$, $x$medium$x$),
  (5, $x$The chemical transmitter released by most postganglionic sympathetic nerve endings is$x$, $x$["Acetylcholine","Noradrenaline","Adrenaline","Serotonin"]$x$, 1, $x$Most postganglionic sympathetic fibres are adrenergic and release noradrenaline. Exceptions such as sweat glands are cholinergic, while all preganglionic sympathetic fibres and all parasympathetic fibres release acetylcholine.$x$, $x$Basic Sciences$x$, $x$hard$x$),
  (6, $x$The photoreceptors of the retina responsible for vision in dim light are the$x$, $x$["Ganglion cells","Cones","Rods","Bipolar cells"]$x$, 2, $x$Rods contain the pigment rhodopsin and are highly sensitive to low light, mediating night or scotopic vision but not colour. Cones function in bright light and are responsible for colour and sharp central vision.$x$, $x$Basic Sciences$x$, $x$easy$x$),
  (7, $x$The corticospinal or pyramidal tract of the spinal cord primarily carries$x$, $x$["Pain and temperature sensation","Proprioception and fine touch","Voluntary motor impulses","Autonomic fibres"]$x$, 2, $x$The corticospinal tract is a descending pathway carrying voluntary motor commands from the motor cortex to spinal motor neurons. Pain and temperature travel in the spinothalamic tract, and fine touch and proprioception in the dorsal columns.$x$, $x$Basic Sciences$x$, $x$hard$x$),
  (8, $x$Which part of the inner ear is concerned with hearing?$x$, $x$["Utricle","Cochlea","Saccule","Semicircular canals"]$x$, 1, $x$The cochlea houses the organ of Corti, which converts sound vibrations into nerve impulses for hearing. The semicircular canals, utricle and saccule are parts of the vestibular apparatus concerned with balance and equilibrium.$x$, $x$Basic Sciences$x$, $x$easy$x$),
  (9, $x$The first heart sound, S1 or lubb, is produced by the closure of the$x$, $x$["Mitral and tricuspid atrioventricular valves","Aortic and pulmonary semilunar valves","Aortic valve only","Pulmonary valve only"]$x$, 0, $x$S1 is caused by closure of the atrioventricular mitral and tricuspid valves at the onset of ventricular systole. The second heart sound S2 results from closure of the semilunar aortic and pulmonary valves.$x$, $x$Basic Sciences$x$, $x$medium$x$),
  (10, $x$In a normal electrocardiogram, the P wave represents$x$, $x$["Ventricular depolarization","Atrial repolarization","Atrial depolarization","Ventricular repolarization"]$x$, 2, $x$The P wave represents atrial depolarization, the QRS complex represents ventricular depolarization, and the T wave represents ventricular repolarization. Atrial repolarization is normally hidden within the QRS complex.$x$, $x$Basic Sciences$x$, $x$medium$x$),
  (11, $x$The volume of air remaining in the lungs after a maximal forced expiration is called the$x$, $x$["Residual volume","Inspiratory reserve volume","Tidal volume","Vital capacity"]$x$, 0, $x$Residual volume is the air that cannot be expelled even after a maximal expiration, keeping the alveoli partly inflated. It is about 1200 mL and, because it cannot be exhaled, cannot be measured by ordinary spirometry.$x$, $x$Basic Sciences$x$, $x$medium$x$),
  (12, $x$The largest fraction of carbon dioxide is transported in the blood as$x$, $x$["Bicarbonate ions","Dissolved CO2 in plasma","Carbon monoxide","Carbaminohaemoglobin"]$x$, 0, $x$About 70 per cent of carbon dioxide is carried as bicarbonate ions formed in red cells by carbonic anhydrase. Roughly 23 per cent travels bound to haemoglobin as carbaminohaemoglobin, and only about 7 per cent is dissolved in plasma.$x$, $x$Basic Sciences$x$, $x$medium$x$),
  (13, $x$Pepsin, secreted by the gastric glands, acts on which class of nutrients?$x$, $x$["Proteins","Carbohydrates","Fats","Nucleic acids"]$x$, 0, $x$Pepsin is a gastric protease secreted as inactive pepsinogen and activated by hydrochloric acid; it begins protein digestion by cleaving peptide bonds. Carbohydrate digestion begins with salivary amylase and fat digestion mainly in the intestine.$x$, $x$Basic Sciences$x$, $x$easy$x$),
  (14, $x$Dietary iron is absorbed mainly in which part of the gastrointestinal tract?$x$, $x$["Duodenum","Terminal ileum","Colon","Stomach"]$x$, 0, $x$Iron is absorbed chiefly in the duodenum and upper jejunum, favoured by the acidic environment and by conversion to the ferrous form. The terminal ileum is the principal site for absorption of vitamin B12 and bile salts.$x$, $x$Basic Sciences$x$, $x$medium$x$),
  (15, $x$Almost all of the glucose filtered at the glomerulus is reabsorbed in the$x$, $x$["Loop of Henle","Collecting duct","Proximal convoluted tubule","Distal convoluted tubule"]$x$, 2, $x$Glucose is completely reabsorbed in the proximal convoluted tubule by sodium-glucose cotransporters under normal conditions. Glucose appears in the urine only when the plasma level exceeds the renal threshold of about 180 mg/dL.$x$, $x$Basic Sciences$x$, $x$medium$x$),
  (16, $x$Which hormone, secreted by the alpha cells of the pancreatic islets, raises blood glucose?$x$, $x$["Somatostatin","Insulin","Amylin","Glucagon"]$x$, 3, $x$Glucagon is secreted by the alpha cells of the islets of Langerhans and raises blood glucose by promoting hepatic glycogenolysis and gluconeogenesis. It is functionally antagonistic to insulin, which is produced by the beta cells.$x$, $x$Basic Sciences$x$, $x$medium$x$),
  (17, $x$Which mineral is an essential component of the thyroid hormone thyroxine?$x$, $x$["Iodine","Zinc","Calcium","Iron"]$x$, 0, $x$Iodine is an essential constituent of thyroid hormones; thyroxine T4 contains four iodine atoms and triiodothyronine T3 contains three. Dietary iodine deficiency impairs their synthesis and leads to goitre.$x$, $x$Basic Sciences$x$, $x$easy$x$),
  (18, $x$Ovulation in the human menstrual cycle is triggered by a mid-cycle surge of$x$, $x$["Progesterone","Oestrogen","Luteinizing hormone","Follicle-stimulating hormone"]$x$, 2, $x$A sharp mid-cycle surge of luteinizing hormone from the anterior pituitary triggers rupture of the mature Graafian follicle and release of the ovum. This surge is itself induced by rising peak levels of oestrogen.$x$, $x$Basic Sciences$x$, $x$medium$x$),
  (19, $x$The urea cycle, which converts toxic ammonia into urea, occurs mainly in the$x$, $x$["Kidney","Brain","Muscle","Liver"]$x$, 3, $x$The urea cycle operates primarily in hepatocytes, converting ammonia derived from amino acid deamination into non-toxic urea. The urea is then carried by the blood to the kidneys, which excrete it in the urine.$x$, $x$Basic Sciences$x$, $x$hard$x$),
  (20, $x$Beta-oxidation of fatty acids, which yields acetyl-CoA, takes place in the$x$, $x$["Mitochondrial matrix","Nucleus","Cytoplasm or cytosol","Endoplasmic reticulum"]$x$, 0, $x$Beta-oxidation occurs in the mitochondrial matrix, where fatty acyl-CoA is progressively shortened to yield acetyl-CoA along with NADH and FADH2. Fatty acid synthesis, by contrast, takes place in the cytosol.$x$, $x$Basic Sciences$x$, $x$hard$x$),
  (21, $x$The key rate-limiting or regulatory enzyme of glycolysis is$x$, $x$["Aldolase","Phosphofructokinase-1","Hexokinase","Pyruvate kinase"]$x$, 1, $x$Phosphofructokinase-1 catalyses the committed, rate-limiting step of glycolysis, converting fructose-6-phosphate to fructose-1,6-bisphosphate. It is allosterically inhibited by ATP and citrate and activated by AMP.$x$, $x$Basic Sciences$x$, $x$hard$x$),
  (22, $x$Deficiency of vitamin C or ascorbic acid causes which disease?$x$, $x$["Rickets","Beriberi","Pellagra","Scurvy"]$x$, 3, $x$Vitamin C is required for collagen synthesis, and its deficiency causes scurvy, marked by bleeding gums, poor wound healing and perifollicular haemorrhages. Beriberi results from thiamine deficiency and pellagra from niacin deficiency.$x$, $x$Basic Sciences$x$, $x$easy$x$),
  (23, $x$The most important buffer system of the extracellular fluid or plasma is the$x$, $x$["Protein buffer","Phosphate buffer","Bicarbonate-carbonic acid buffer","Ammonia buffer"]$x$, 2, $x$The bicarbonate-carbonic acid system is the principal buffer of extracellular fluid because its components are readily regulated: carbon dioxide by the lungs and bicarbonate by the kidneys. Phosphate and protein buffers act mainly within cells.$x$, $x$Basic Sciences$x$, $x$hard$x$),
  (24, $x$Bacteria that are spherical in shape are called$x$, $x$["Vibrios","Spirilla","Bacilli","Cocci"]$x$, 3, $x$Cocci are spherical bacteria and may occur in pairs as diplococci, chains as streptococci, or clusters as staphylococci. Bacilli are rod-shaped, vibrios are comma-shaped, and spirilla are rigid spiral-shaped organisms.$x$, $x$Basic Sciences$x$, $x$easy$x$),
  (25, $x$After Gram staining, Gram-positive bacteria appear which colour under the microscope?$x$, $x$["Pink or red","Colourless","Green","Purple or violet"]$x$, 3, $x$Gram-positive bacteria have a thick peptidoglycan cell wall that retains the crystal violet-iodine complex, so they appear purple or violet. Gram-negative bacteria lose this stain, take up the safranin counterstain, and appear pink or red.$x$, $x$Basic Sciences$x$, $x$medium$x$),
  (26, $x$Which class of immunoglobulin can cross the human placenta to provide passive immunity to the fetus?$x$, $x$["IgA","IgM","IgE","IgG"]$x$, 3, $x$IgG is the only immunoglobulin that crosses the placenta, conferring natural passive immunity on the newborn. IgM is the largest antibody and the first produced in infection, while secretory IgA predominates in breast milk and mucosal secretions.$x$, $x$Basic Sciences$x$, $x$hard$x$),
  (27, $x$Which route of drug administration provides 100 per cent bioavailability and the most rapid onset of action?$x$, $x$["Oral","Intramuscular","Subcutaneous","Intravenous"]$x$, 3, $x$Intravenous administration delivers the drug directly into the bloodstream, giving complete bioavailability and the fastest onset because it bypasses absorption and first-pass metabolism. Oral drugs are subject to incomplete absorption and hepatic first-pass effect.$x$, $x$Basic Sciences$x$, $x$easy$x$),
  (28, $x$A drug that binds to a receptor and activates it to produce a biological response is called a/an$x$, $x$["Placebo","Enzyme inhibitor","Antagonist","Agonist"]$x$, 3, $x$An agonist binds to a receptor and activates it to produce an effect, mimicking the endogenous ligand. An antagonist binds but causes no activation and blocks agonist action, whereas a placebo contains no active pharmacological ingredient.$x$, $x$Basic Sciences$x$, $x$medium$x$),
  (29, $x$Propranolol is the prototype drug of which pharmacological class?$x$, $x$["ACE inhibitor","Calcium channel blocker","Diuretic","Beta-adrenergic blocker"]$x$, 3, $x$Propranolol is a non-selective beta-adrenergic receptor blocker used in hypertension, angina and arrhythmias. It antagonises catecholamine action at beta-1 and beta-2 receptors, reducing heart rate and myocardial contractility.$x$, $x$Basic Sciences$x$, $x$medium$x$)
) as v(pos, question, options, ci, exp, topic, diff);

-- 15-community-env-occ.txt — 30 questions
with b as (
  insert into tests (title, topic, difficulty, duration_minutes)
  values ($x$w1-community-a — ingested draft, verify before trusting$x$, $x$Community Health Nursing$x$, 'medium', 60)
  returning id
)
insert into questions (test_id, position, question, options, correct_index, explanation, topic, difficulty)
select b.id, v.pos::int, v.question, v.options::jsonb, v.ci::int, v.exp, v.topic, v.diff
from b, (values
  (0, $x$The most effective health education approach for changing the behaviour of an individual is$x$, $x$["Mass approach","Poster campaign","Group approach","Individual approach"]$x$, 3, $x$The individual or personal contact approach is most effective for behaviour change because it allows two-way discussion of personal problems and doubts. The mass approach reaches large numbers quickly but is least effective for changing individual behaviour.$x$, $x$Community Health Nursing$x$, $x$easy$x$),
  (1, $x$Which one of the following is a purely auditory aid used in health education?$x$, $x$["Flash card","Radio","Poster","Flannelgraph"]$x$, 1, $x$Radio, tape recorder and microphone are audio aids that appeal only to the sense of hearing. Poster, flannelgraph and flash card are non-projected visual aids that appeal to the sense of sight.$x$, $x$Community Health Nursing$x$, $x$easy$x$),
  (2, $x$Retention of learning in health education is maximum when the method used is$x$, $x$["Learning by doing with active participation","Viewing a poster","Reading a printed pamphlet","A lecture that is only heard"]$x$, 0, $x$According to Dale's cone of experience, active participation or learning by doing gives the greatest retention of learning. Passive methods such as hearing a lecture or reading a pamphlet produce much lower retention.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (3, $x$Silicosis is an occupational lung disease caused by inhalation of dust containing$x$, $x$["Cotton dust","Coal dust","Asbestos fibres","Free silica or silicon dioxide"]$x$, 3, $x$Silicosis is caused by inhalation of free silica, affecting workers in mining, quarrying, sandblasting and pottery. Asbestos causes asbestosis, cotton dust causes byssinosis and coal dust causes anthracosis.$x$, $x$Community Health Nursing$x$, $x$easy$x$),
  (4, $x$Byssinosis is an occupational disease associated with exposure to$x$, $x$["Lead fumes","Asbestos fibres","Cotton or flax dust","Silica dust"]$x$, 2, $x$Byssinosis, or Monday fever, occurs in textile workers exposed to cotton, flax or hemp dust, with chest tightness typically felt on the first working day after a break. Silica causes silicosis and asbestos causes asbestosis, not byssinosis.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (5, $x$Which malignancy is characteristically associated with occupational exposure to asbestos?$x$, $x$["Mesothelioma","Wilms tumour","Osteosarcoma","Retinoblastoma"]$x$, 0, $x$Asbestos exposure characteristically causes mesothelioma of the pleura or peritoneum, as well as bronchogenic carcinoma. Osteosarcoma, retinoblastoma and Wilms tumour have no established link with asbestos.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (6, $x$A characteristic early sign of chronic lead poisoning in adults is$x$, $x$["Koplik's spots on the buccal mucosa","Bitot's spots on the conjunctiva","A blue line on the gum margin, Burton's line","Hutchinson's teeth"]$x$, 2, $x$A blue-black lead line, Burton's line, at the gum margin is characteristic of chronic lead poisoning, along with anaemia, abdominal colic, basophilic stippling and wrist drop. Koplik's spots occur in measles and Bitot's spots in vitamin A deficiency.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (7, $x$The Employees State Insurance Act of 1948 provides all of the following benefits to insured workers except$x$, $x$["Maternity benefit","Sickness benefit","Disablement benefit","Old age pension"]$x$, 3, $x$The ESI scheme provides medical, sickness, maternity, disablement, dependant's and funeral benefits. Old-age pension is not an ESI benefit; retirement provision is covered under separate schemes such as the Employees Provident Fund.$x$, $x$Community Health Nursing$x$, $x$hard$x$),
  (8, $x$Noise-induced occupational hearing loss characteristically produces its earliest audiometric dip at a frequency of$x$, $x$["500 Hz","1000 Hz","4000 Hz","8000 Hz"]$x$, 2, $x$The earliest and most characteristic change in noise-induced hearing loss is a dip in the audiogram at 4000 Hz, the acoustic notch, which appears before the speech frequencies are affected. This precedes clinically obvious deafness and is useful for early detection.$x$, $x$Community Health Nursing$x$, $x$hard$x$),
  (9, $x$The committee that reviewed school health services in India in 1960 to 1961 was headed by$x$, $x$["Dr M S Chadah","Shrimati Renuka Ray","Dr A L Mudaliar","Sir Joseph Bhore"]$x$, 1, $x$The School Health Committee of 1960 to 1961 was chaired by Shrimati Renuka Ray and assessed the health and nutrition of school children in India. Bhore, Mudaliar and Chadah chaired other well-known health committees.$x$, $x$Community Health Nursing$x$, $x$hard$x$),
  (10, $x$The recommended minimum floor space per pupil in a school classroom by Indian standards is approximately$x$, $x$["4 square feet","6 square feet","10 square feet","20 square feet"]$x$, 2, $x$Standards recommend about 10 square feet, roughly one square metre, of floor space per pupil, with not more than about 40 pupils per class, to prevent overcrowding. Adequate space also improves ventilation and reduces cross-infection.$x$, $x$Community Health Nursing$x$, $x$hard$x$),
  (11, $x$The primary objective of the mid-day meal programme in schools is to$x$, $x$["Improve nutritional status and school attendance","Reduce school fees","Provide employment to cooks","Reduce the teacher's workload"]$x$, 0, $x$The mid-day meal programme aims to improve the nutritional status of children and to increase enrolment, retention and attendance while reducing classroom hunger. It supplies a defined share of the daily calorie and protein requirement.$x$, $x$Community Health Nursing$x$, $x$easy$x$),
  (12, $x$In demography, an elderly or aged person in India is generally defined as one who has attained the age of$x$, $x$["45 years","50 years","55 years","60 years"]$x$, 3, $x$In India a person aged 60 years and above is considered elderly or a senior citizen. The rising proportion of the elderly increases the community burden of chronic and degenerative diseases.$x$, $x$Community Health Nursing$x$, $x$easy$x$),
  (13, $x$The National Programme for the Health Care of the Elderly in India was launched in the year$x$, $x$["1995","1982","2010 to 2011","2017"]$x$, 2, $x$The National Programme for the Health Care of the Elderly was launched in 2010 to 2011 to provide dedicated, accessible and affordable healthcare services to the elderly at various levels of the health system. It emphasises preventive, curative and rehabilitative geriatric care.$x$, $x$Community Health Nursing$x$, $x$hard$x$),
  (14, $x$The commonest cause of accidental injury among the elderly in the community, requiring preventive attention, is$x$, $x$["Drowning","Poisoning","Burns","Falls"]$x$, 3, $x$Falls are the most common cause of injury in the elderly because of impaired vision, poor balance, muscle weakness and environmental hazards. Prevention includes good lighting, grab bars, non-slip floors and removal of loose rugs.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (15, $x$In mass-casualty triage using colour coding, a victim tagged RED indicates$x$, $x$["Delayed priority, can safely wait","Immediate priority, life-threatening but salvageable","Minor injuries, the walking wounded","Dead or moribund"]$x$, 1, $x$RED denotes the first or immediate priority: serious, life-threatening injuries that are salvageable with prompt treatment. YELLOW is delayed, GREEN is minor or walking wounded, and BLACK is dead or expectant.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (16, $x$In disaster triage colour coding, which colour is assigned to victims who are dead or beyond salvageable help?$x$, $x$["Yellow","Red","Green","Black"]$x$, 3, $x$BLACK tags identify the dead or those whose injuries are so severe that survival is not expected even with treatment, the expectant category. GREEN is minor injury, YELLOW is delayed and RED is immediate priority.$x$, $x$Community Health Nursing$x$, $x$easy$x$),
  (17, $x$The phase of the disaster management cycle that includes activities carried out before a disaster to reduce its impact, such as building codes and early warning systems, is$x$, $x$["Response phase","Recovery phase","Rehabilitation phase","Mitigation and preparedness phase"]$x$, 3, $x$Mitigation and preparedness are pre-disaster phases aimed at reducing impact and readying the community through warning systems, drills and disaster-resistant construction. Response occurs during impact and recovery or rehabilitation afterwards.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (18, $x$In the immediate response phase after a sudden natural disaster such as an earthquake, the first priority of health management is$x$, $x$["Immunisation of the population against tetanus","Search, rescue and first aid to casualties","Mass chemoprophylaxis to prevent epidemics","Rehabilitation and rebuilding of houses"]$x$, 1, $x$The immediate priority after a disaster is search, rescue, first aid and emergency medical care of the injured. Mass immunisation and blanket chemoprophylaxis are not indicated in the acute phase, and rehabilitation belongs to a later stage.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (19, $x$A latrine is considered sanitary primarily when it$x$, $x$["Is located inside the dwelling house","Is constructed of concrete","Prevents contamination of soil and water and excludes flies","Is fitted with a water flush"]$x$, 2, $x$A sanitary latrine must dispose of excreta so that it cannot contaminate soil, water or food and is inaccessible to flies and other vectors. The construction material, indoor location and presence of a flush are not the defining criteria.$x$, $x$Community Health Nursing$x$, $x$easy$x$),
  (20, $x$In a Ventilated Improved Pit latrine, the vent pipe is fitted mainly to$x$, $x$["Supply water to the pit","Support the superstructure","Increase the capacity of the pit","Control odour and trap flies"]$x$, 3, $x$The vent pipe of a VIP latrine, usually painted dark and topped with fly-proof netting, creates an air draught that removes odour and traps escaping flies, which are drawn towards the light at the screened top. This makes it superior to a simple pit latrine.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (21, $x$In a septic tank, the liquid effluent after retention is usually disposed of by$x$, $x$["A soak pit or subsurface dispersion trench","Collection in sealed drums","Spraying directly on vegetables","Direct discharge into a river"]$x$, 0, $x$The effluent leaving a septic tank is still rich in bacteria and is disposed of through a soak pit or dispersion trenches, where it percolates and is purified by the soil. Direct discharge to surface water or crops is unsafe because pathogens survive.$x$, $x$Community Health Nursing$x$, $x$hard$x$),
  (22, $x$The method of solid-waste disposal in which organic matter is decomposed by microorganisms to yield manure is$x$, $x$["Incineration","Controlled tipping","Composting","Sanitary landfill"]$x$, 2, $x$Composting is a controlled aerobic decomposition of organic refuse, and sometimes night soil, by microorganisms into a humus-like manure. Incineration burns waste, while sanitary landfill and controlled tipping bury it in the earth.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (23, $x$Waste water from kitchens, bathrooms and washing that does not contain human excreta is termed$x$, $x$["Sullage","Effluent","Sewage","Sludge"]$x$, 0, $x$Sullage is waste water from kitchen, bathroom and washing that is free of human faecal matter, whereas sewage contains human excreta. Sludge is the semi-solid residue produced during sewage treatment.$x$, $x$Community Health Nursing$x$, $x$easy$x$),
  (24, $x$The classic London smog disaster of 1952, which caused thousands of deaths, was mainly due to high atmospheric levels of$x$, $x$["Ozone and nitrogen dioxide","Methane and ammonia","Carbon monoxide and lead","Sulphur dioxide and smoke particulates"]$x$, 3, $x$The 1952 London smog was a reducing or sulphurous smog caused by high levels of sulphur dioxide and smoke from coal burning under a temperature inversion. Photochemical or Los Angeles type smog, in contrast, involves ozone and oxides of nitrogen.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (25, $x$The air pollutant that has a high affinity for haemoglobin and causes tissue hypoxia by forming carboxyhaemoglobin is$x$, $x$["Sulphur dioxide","Ozone","Nitrogen dioxide","Carbon monoxide"]$x$, 3, $x$Carbon monoxide, produced by incomplete combustion in vehicle exhaust and tobacco smoke, binds haemoglobin far more strongly than oxygen, forming carboxyhaemoglobin and causing tissue hypoxia. Sulphur dioxide and ozone act mainly as respiratory irritants.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (26, $x$Prolonged occupational or community exposure to noise above which of the following levels is generally regarded as hazardous to hearing?$x$, $x$["85 to 90 dB","150 dB","45 dB","30 dB"]$x$, 0, $x$Continuous exposure above about 85 to 90 dB over an eight-hour day can cause noise-induced hearing loss, and 85 dB is taken as the safe limit. Very high levels such as 150 dB cause instantaneous damage, but everyday hazardous exposure begins near 85 to 90 dB.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (27, $x$According to the accepted overcrowding standard based on floor space, a room with 110 square feet or more of floor area should not be occupied by more than$x$, $x$["1 person","2 persons","4 persons","6 persons"]$x$, 1, $x$The standard permits 2 persons in a room of 110 square feet or more, 1.5 persons for 90 to 110 square feet and 1 person for 70 to 90 square feet. An infant under one year is not counted, and a child aged one to ten years is counted as half a person.$x$, $x$Community Health Nursing$x$, $x$hard$x$),
  (28, $x$The type of ventilation that uses natural forces such as wind and temperature difference without any mechanical device is called$x$, $x$["Mechanical or artificial ventilation","Air conditioning","Exhaust ventilation","Natural ventilation"]$x$, 3, $x$Natural ventilation relies on wind pressure, temperature-difference-induced convection or stack effect and diffusion to change indoor air without machinery. Mechanical, exhaust and air-conditioning systems all require powered devices to move air.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (29, $x$In modern sewage treatment, the activated sludge process is a form of$x$, $x$["Preliminary screening","Tertiary chemical disinfection","Primary or physical treatment","Secondary or biological treatment"]$x$, 3, $x$The activated sludge process is a secondary or biological treatment in which aerobic microorganisms oxidise dissolved organic matter in aerated tanks. Primary treatment is physical sedimentation, while final disinfection such as chlorination is a later step.$x$, $x$Community Health Nursing$x$, $x$hard$x$)
) as v(pos, question, options, ci, exp, topic, diff);

-- 16-community-disease-prog.txt — 30 questions
with b as (
  insert into tests (title, topic, difficulty, duration_minutes)
  values ($x$w1-community-b — ingested draft, verify before trusting$x$, $x$Community Health Nursing$x$, 'medium', 60)
  returning id
)
insert into questions (test_id, position, question, options, correct_index, explanation, topic, difficulty)
select b.id, v.pos::int, v.question, v.options::jsonb, v.ci::int, v.exp, v.topic, v.diff
from b, (values
  (0, $x$The primary vector responsible for rural malaria transmission in India is which mosquito species?$x$, $x$["Phlebotomus argentipes","Anopheles culicifacies","Aedes aegypti","Culex quinquefasciatus"]$x$, 1, $x$Anopheles culicifacies is the principal vector of rural malaria in India, breeding in clean stagnant water. Culex transmits filariasis, Aedes transmits dengue and chikungunya, and Phlebotomus the sandfly transmits kala-azar.$x$, $x$Community Health Nursing$x$, $x$easy$x$),
  (1, $x$Kala-azar or visceral leishmaniasis under the NVBDCP is transmitted by the bite of which vector?$x$, $x$["Phlebotomus argentipes, the sandfly","Aedes mosquito","Anopheles mosquito","Culex mosquito"]$x$, 0, $x$Kala-azar is transmitted by the female sandfly Phlebotomus argentipes, which breeds in cracks and crevices with high humidity. Man is the only reservoir in Indian kala-azar, making it a target for elimination.$x$, $x$Community Health Nursing$x$, $x$easy$x$),
  (2, $x$The overwhelming majority of lymphatic filariasis cases in India are caused by which parasite?$x$, $x$["Onchocerca volvulus","Brugia malayi","Wuchereria bancrofti","Brugia timori"]$x$, 2, $x$About 99 per cent of the filariasis burden in India is due to Wuchereria bancrofti, transmitted by Culex quinquefasciatus. Mass drug administration with DEC plus albendazole is the control strategy.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (3, $x$In the epidemiology of Japanese encephalitis, the pig acts as the$x$, $x$["Definitive host","Mechanical vector","Amplifier host","Dead-end host"]$x$, 2, $x$Pigs are the main amplifier host of Japanese encephalitis, developing high viraemia without illness and multiplying the virus for onward Culex transmission. Man is only a dead-end incidental host.$x$, $x$Community Health Nursing$x$, $x$hard$x$),
  (4, $x$The causative organism of leprosy is$x$, $x$["Mycobacterium avium","Mycobacterium leprae","Mycobacterium bovis","Mycobacterium tuberculosis"]$x$, 1, $x$Leprosy is caused by Mycobacterium leprae, an acid-fast bacillus with a very long generation time and a predilection for skin and peripheral nerves. The NLEP treats it with multidrug therapy.$x$, $x$Community Health Nursing$x$, $x$easy$x$),
  (5, $x$Under the National Leprosy Eradication Programme, the standard duration of multidrug therapy for multibacillary leprosy is$x$, $x$["9 months","12 months","24 months","6 months"]$x$, 1, $x$Multibacillary leprosy is treated with rifampicin, clofazimine and dapsone for 12 months, while paucibacillary disease needs only 6 months. Multidrug therapy rapidly renders patients non-infectious and prevents disability.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (6, $x$The commonest cause of blindness in India, targeted under the National Programme for Control of Blindness, is$x$, $x$["Trachoma","Refractive errors","Cataract","Glaucoma"]$x$, 2, $x$Cataract accounts for roughly two thirds of blindness in India and is the leading avoidable cause. The programme emphasises high-volume cataract surgery with intraocular lens implantation to clear the backlog.$x$, $x$Community Health Nursing$x$, $x$easy$x$),
  (7, $x$The National Mental Health Programme in India was launched in which year?$x$, $x$["1975","1982","1985","1992"]$x$, 1, $x$The National Mental Health Programme was launched in 1982 to ensure the availability of minimum mental healthcare and to integrate it into general health services. The District Mental Health Programme was added in 1996.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (8, $x$NPCDCS is a national programme for the prevention and control of$x$, $x$["Nutritional deficiency disorders","Communicable diseases only","Cancer, diabetes, cardiovascular diseases and stroke","Maternal and child health disorders"]$x$, 2, $x$NPCDCS stands for the National Programme for Prevention and Control of Cancer, Diabetes, Cardiovascular Diseases and Stroke. It addresses the rising burden of non-communicable disease through screening, early diagnosis and health promotion.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (9, $x$In the RMNCH+A strategy, the additional plus A component refers to$x$, $x$["Anaemia control","Antenatal care","Aged or geriatric care","Adolescent health"]$x$, 3, $x$RMNCH+A stands for Reproductive, Maternal, Newborn, Child and Adolescent Health. Adding adolescents recognised this age group as a critical link in breaking the intergenerational cycle of ill health.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (10, $x$The principal objective of Mission Indradhanush is to$x$, $x$["Reduce iron-deficiency anaemia","Control avoidable blindness","Achieve full immunisation of children and pregnant women","Eradicate malaria from endemic districts"]$x$, 2, $x$Mission Indradhanush, launched in 2014, aims to rapidly raise full immunisation coverage to at least 90 per cent by reaching unimmunised and partially immunised children and pregnant women.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (11, $x$The National AIDS Control Programme, under which NACO functions, was launched in which year?$x$, $x$["1982","1985","1987","1992"]$x$, 3, $x$The National AIDS Control Programme was launched in 1992, and NACO was established the same year to coordinate India's HIV response. It runs surveillance, blood safety, condom promotion and antiretroviral treatment services.$x$, $x$Community Health Nursing$x$, $x$hard$x$),
  (12, $x$In India, a population census is conducted at intervals of every$x$, $x$["5 years","10 years","15 years","20 years"]$x$, 1, $x$The Indian census is a decennial, every ten years, complete enumeration of the population and is the oldest single source of demographic data. It provides denominators for calculating vital and health rates.$x$, $x$Community Health Nursing$x$, $x$easy$x$),
  (13, $x$The Sample Registration System in India obtains reliable birth and death rates using which method?$x$, $x$["Single continuous enumeration","Decennial census enumeration","Dual record system","Hospital record compilation"]$x$, 2, $x$The SRS uses a dual record system: continuous enumeration by a resident part-time enumerator plus an independent half-yearly retrospective survey. Matching the two lists and verifying discrepancies yields dependable vital rates.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (14, $x$Registration of births and deaths was made compulsory throughout India under an Act passed in the year$x$, $x$["1948","1955","1969","1971"]$x$, 2, $x$The Registration of Births and Deaths Act of 1969 made civil registration compulsory across India. Despite this, registration completeness remains incomplete in many states, limiting the civil registration system as a source of vital statistics.$x$, $x$Community Health Nursing$x$, $x$hard$x$),
  (15, $x$The usual incubation period of typhoid fever is$x$, $x$["1 to 3 days","3 to 4 weeks","5 to 7 days","10 to 14 days"]$x$, 3, $x$Typhoid fever, caused by Salmonella typhi, has an incubation period of usually 10 to 14 days depending on the infecting dose. Transmission is faeco-oral through contaminated water and food.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (16, $x$The incubation period of cholera is characteristically$x$, $x$["2 to 6 weeks","10 to 14 days","15 to 45 days","A few hours to 5 days"]$x$, 3, $x$Cholera has a very short incubation period ranging from a few hours to five days, usually one to two days. This short interval explains the explosive nature of waterborne cholera outbreaks caused by Vibrio cholerae.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (17, $x$Hepatitis A is transmitted mainly by which route?$x$, $x$["Parenteral or blood transfusion","Faeco-oral","Sexual contact","Perinatal, mother to child"]$x$, 1, $x$Hepatitis A virus spreads by the faeco-oral route through contaminated food and water and is common where sanitation is poor. It causes a self-limiting illness and does not lead to a chronic carrier state.$x$, $x$Community Health Nursing$x$, $x$easy$x$),
  (18, $x$Which type of viral hepatitis carries the highest mortality when it occurs in pregnant women?$x$, $x$["Hepatitis B","Hepatitis A","Hepatitis C","Hepatitis E"]$x$, 3, $x$Hepatitis E, transmitted by the faeco-oral route, causes especially severe disease in pregnancy with fulminant hepatic failure and high case fatality, particularly in the third trimester. It is a major cause of water-borne epidemic hepatitis in India.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (19, $x$According to WHO categories of rabies exposure, a category III exposure includes$x$, $x$["Touching or feeding the animal","Minor scratches without bleeding","Nibbling of uncovered skin without a break","Transdermal bites or scratches, or contamination of a mucous membrane with saliva"]$x$, 3, $x$Category III exposures include single or multiple transdermal bites or scratches, licks on broken skin, and contamination of mucous membranes with saliva. These require immediate wound care, rabies immunoglobulin and a full anti-rabies vaccine course.$x$, $x$Community Health Nursing$x$, $x$hard$x$),
  (20, $x$The single most important first-aid measure immediately after an animal bite to prevent rabies is$x$, $x$["Suture the wound immediately","Apply turmeric, lime or other irritants","Cover the wound tightly with a bandage","Wash the wound with soap and running water for about 15 minutes"]$x$, 3, $x$Prompt thorough washing of the wound with soap and plenty of running water for around 15 minutes physically removes and inactivates much of the virus. Suturing should be avoided or delayed, and irritant applications are harmful.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (21, $x$Tetanus is caused by which organism?$x$, $x$["Corynebacterium diphtheriae","Clostridium perfringens","Clostridium tetani","Clostridium botulinum"]$x$, 2, $x$Tetanus is caused by Clostridium tetani, whose spores enter through wounds and produce the neurotoxin tetanospasmin causing muscle rigidity and spasms. It is preventable by tetanus toxoid immunisation and proper wound care.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (22, $x$India was certified polio-free by the WHO in which year?$x$, $x$["2011","2012","2014","2016"]$x$, 2, $x$India recorded its last wild poliovirus case in January 2011 and, after three years without transmission, the WHO South-East Asia Region including India was certified polio-free in March 2014. Pulse polio immunisation with OPV was central to this.$x$, $x$Community Health Nursing$x$, $x$hard$x$),
  (23, $x$The vector responsible for transmission of plague from rodents to humans is the$x$, $x$["Sandfly","Hard tick","Rat flea, Xenopsylla cheopis","Body louse"]$x$, 2, $x$Bubonic plague, caused by Yersinia pestis, is transmitted by the bite of the infected rat flea Xenopsylla cheopis. A blocked flea regurgitates bacilli into the bite wound, while pneumonic plague spreads directly by droplets between humans.$x$, $x$Community Health Nursing$x$, $x$hard$x$),
  (24, $x$Human brucellosis is most commonly acquired through$x$, $x$["Ingestion of unpasteurised milk or contact with infected animals","Airborne droplets only","Bite of an infected mosquito","Sexual transmission"]$x$, 0, $x$Brucellosis is a zoonosis acquired mainly by consuming raw milk or milk products and through occupational contact with infected cattle, sheep and goats. Pasteurisation of milk and animal vaccination are key preventive measures.$x$, $x$Community Health Nursing$x$, $x$hard$x$),
  (25, $x$Leptospirosis is transmitted to humans chiefly through$x$, $x$["Sexual contact","Inhalation of respiratory droplets","Contact with water or soil contaminated by infected animal urine","Bite of an infected mosquito"]$x$, 2, $x$Leptospirosis spreads when skin abrasions or mucous membranes contact water, mud or soil contaminated with the urine of infected animals, especially rodents. It is an occupational hazard for farmers and sewer workers and can cause Weil's disease.$x$, $x$Community Health Nursing$x$, $x$hard$x$),
  (26, $x$The characteristic incubation period of staphylococcal food poisoning is$x$, $x$["1 to 6 hours","3 to 5 days","12 to 24 hours","24 to 48 hours"]$x$, 0, $x$Staphylococcal food poisoning has a very short incubation of one to six hours because it is caused by a preformed heat-stable enterotoxin rather than active infection. Vomiting predominates and recovery is usually rapid.$x$, $x$Community Health Nursing$x$, $x$hard$x$),
  (27, $x$The toxin of Clostridium botulinum produces paralysis by acting at the$x$, $x$["Neuromuscular junction, blocking acetylcholine release","Renal tubules","Intestinal mucosa","Liver cells"]$x$, 0, $x$Botulinum toxin blocks the release of acetylcholine at the neuromuscular junction, producing descending flaccid paralysis, diplopia, dysphagia and respiratory failure. It is often linked to improperly preserved or canned foods.$x$, $x$Community Health Nursing$x$, $x$hard$x$),
  (28, $x$The usual incubation period of non-typhoidal Salmonella food poisoning is$x$, $x$["Less than 1 hour","12 to 24 hours","1 to 6 hours","5 to 7 days"]$x$, 1, $x$Salmonella food poisoning is an infection-type illness with an incubation of about 12 to 24 hours, presenting with fever, diarrhoea and abdominal cramps. It is commonly linked to poultry, eggs and inadequately cooked meat.$x$, $x$Community Health Nursing$x$, $x$hard$x$),
  (29, $x$Under the National Vitamin A Prophylaxis Programme, the first dose of vitamin A is given as$x$, $x$["200000 IU at 9 months of age","100000 IU at 9 months of age","200000 IU at 12 months of age","100000 IU at 6 months of age"]$x$, 1, $x$The first dose of vitamin A is 100000 IU given at 9 months along with measles vaccine. Subsequent doses of 200000 IU are given every six months up to five years of age to prevent nutritional blindness.$x$, $x$Community Health Nursing$x$, $x$medium$x$)
) as v(pos, question, options, ci, exp, topic, diff);

-- 17-medsurg-cardio-renal.txt — 30 questions
with b as (
  insert into tests (title, topic, difficulty, duration_minutes)
  values ($x$w1-medsurg-a — ingested draft, verify before trusting$x$, $x$Medical-Surgical Nursing$x$, 'medium', 60)
  returning id
)
insert into questions (test_id, position, question, options, correct_index, explanation, topic, difficulty)
select b.id, v.pos::int, v.question, v.options::jsonb, v.ci::int, v.exp, v.topic, v.diff
from b, (values
  (0, $x$Which feature is most characteristic of stable angina pectoris?$x$, $x$["Chest pain precipitated by exertion and relieved within minutes by rest or sublingual nitroglycerin","Crushing chest pain lasting more than 30 minutes and unrelieved by rest","Chest pain occurring only during sleep with persistent ST-segment elevation","Continuous chest pain that worsens progressively over several days"]$x$, 0, $x$Stable angina is predictable, provoked by increased myocardial oxygen demand such as exertion, and typically subsides within a few minutes with rest or nitroglycerin. Pain lasting beyond 20 to 30 minutes suggests myocardial infarction rather than stable angina.$x$, $x$Medical-Surgical Nursing$x$, $x$easy$x$),
  (1, $x$How does unstable angina differ from stable angina?$x$, $x$["It occurs at rest or has a new onset, increasing in frequency, duration or severity","It follows a fixed, predictable pattern brought on only by heavy exertion","It is always fully relieved within two minutes of taking nitroglycerin","It never requires hospitalisation or cardiac monitoring"]$x$, 0, $x$Unstable angina is part of acute coronary syndrome and occurs at rest, is of new onset, or shows a crescendo pattern of increasing frequency and severity. It signals an unstable atherosclerotic plaque and warrants urgent evaluation and continuous monitoring.$x$, $x$Medical-Surgical Nursing$x$, $x$medium$x$),
  (2, $x$In the first few hours following an acute myocardial infarction, the most common cause of death is$x$, $x$["Dressler syndrome","Ventricular fibrillation and other lethal dysrhythmias","Ventricular aneurysm formation","Slowly progressive chronic heart failure"]$x$, 1, $x$Lethal ventricular dysrhythmias, especially ventricular fibrillation, are the leading cause of death in the early hours after myocardial infarction. This is why continuous cardiac monitoring and immediate defibrillation capability are essential during this period.$x$, $x$Medical-Surgical Nursing$x$, $x$medium$x$),
  (3, $x$During phase I inpatient cardiac rehabilitation after myocardial infarction, appropriate nursing guidance is to$x$, $x$["Enforce strict, complete bed rest until the day of discharge","Progress gradually with low-level activities such as self-care and short supervised walks","Prohibit all self-care activities to conserve myocardial oxygen","Begin high-intensity aerobic training on the first day"]$x$, 1, $x$Phase I rehabilitation emphasises gradual, low-level activity such as self-care, sitting up, and short monitored walks while observing the patient's tolerance. Activity is advanced slowly based on the absence of symptoms, dysrhythmias and abnormal vital sign responses.$x$, $x$Medical-Surgical Nursing$x$, $x$medium$x$),
  (4, $x$ACE inhibitors improve survival in chronic heart failure mainly by$x$, $x$["Directly increasing the heart rate and contractility","Promoting sodium and water retention to raise preload","Reducing afterload and preventing maladaptive ventricular remodeling","Increasing systemic vascular resistance and afterload"]$x$, 2, $x$ACE inhibitors block the renin-angiotensin-aldosterone system, producing vasodilation that lowers afterload and reducing angiotensin II-driven ventricular remodeling. These effects decrease cardiac workload and improve long-term survival in heart failure.$x$, $x$Medical-Surgical Nursing$x$, $x$medium$x$),
  (5, $x$Primary or essential hypertension is best defined as elevated blood pressure that$x$, $x$["Is confined to the paediatric population","Results from an identifiable cause such as renal artery stenosis or phaeochromocytoma","Has no single identifiable underlying cause and accounts for most cases","Occurs only transiently during an acute illness"]$x$, 2, $x$Primary or essential hypertension has no identifiable secondary cause and represents roughly 90 to 95 per cent of all hypertension cases. Secondary hypertension, by contrast, results from a specific identifiable condition such as renal or endocrine disease.$x$, $x$Medical-Surgical Nursing$x$, $x$easy$x$),
  (6, $x$When managing a hypertensive emergency, the recommended goal for initial blood pressure reduction is to$x$, $x$["Lower the mean arterial pressure by no more than about 20 to 25 per cent in the first hour","Reduce the systolic pressure below 90 mmHg as quickly as possible","Avoid any reduction until end-organ damage is confirmed","Lower the blood pressure to completely normal values within 15 minutes"]$x$, 0, $x$In a hypertensive emergency the mean arterial pressure should be lowered gradually, by roughly 20 to 25 per cent within the first hour, then further over the following hours. Overly rapid reduction can precipitate cerebral, coronary or renal ischaemia due to impaired autoregulation.$x$, $x$Medical-Surgical Nursing$x$, $x$hard$x$),
  (7, $x$Which auscultatory finding is classic for mitral stenosis?$x$, $x$["A harsh crescendo-decrescendo systolic ejection murmur at the aortic area","A high-pitched blowing pansystolic murmur radiating to the axilla","A low-pitched rumbling mid-diastolic murmur at the apex, often with an opening snap","A continuous machinery-like murmur below the left clavicle"]$x$, 2, $x$Mitral stenosis produces a low-pitched, rumbling mid-diastolic murmur best heard at the apex, frequently preceded by an opening snap. A pansystolic murmur radiating to the axilla instead points to mitral regurgitation.$x$, $x$Medical-Surgical Nursing$x$, $x$medium$x$),
  (8, $x$A patient discharged with a newly implanted permanent pacemaker should be taught to$x$, $x$["Report dizziness, prolonged hiccups, or a pulse rate below the pacemaker's set rate","Avoid taking the pulse so as not to cause unnecessary anxiety","Undergo any MRI scan freely without informing staff about the device","Stop all physical activity permanently to protect the device"]$x$, 0, $x$Patients should check their pulse daily and report dizziness, syncope, persistent hiccups which may indicate lead-related diaphragmatic stimulation, or a rate below the set pacemaker rate. These may signal pacemaker malfunction requiring prompt evaluation.$x$, $x$Medical-Surgical Nursing$x$, $x$medium$x$),
  (9, $x$According to current basic life support guidelines, the recommended rate of chest compressions for an adult is$x$, $x$["40 to 60 compressions per minute","140 to 160 compressions per minute","100 to 120 compressions per minute","60 to 80 compressions per minute"]$x$, 2, $x$High-quality CPR requires a compression rate of 100 to 120 per minute for adults. Rates that are too slow or too fast reduce the effectiveness of the circulation generated during resuscitation.$x$, $x$Medical-Surgical Nursing$x$, $x$easy$x$),
  (10, $x$Cardiogenic shock is most accurately described as$x$, $x$["Hypovolaemia due to acute blood or fluid loss","Widespread vasodilation and maldistribution of blood flow from sepsis","A high-output state with warm, well-perfused extremities","Decreased cardiac output and tissue hypoperfusion despite adequate intravascular volume"]$x$, 3, $x$Cardiogenic shock results from failure of the heart to pump effectively, producing decreased cardiac output and tissue hypoperfusion even though circulating blood volume is adequate. It most often follows extensive myocardial infarction with significant left ventricular damage.$x$, $x$Medical-Surgical Nursing$x$, $x$hard$x$),
  (11, $x$The hallmark clinical sign of acute pericarditis is$x$, $x$["A fixed, widely split second heart sound","Muffled heart sounds with an otherwise silent precordium","Bilateral coarse crackles throughout both lung fields","A pericardial friction rub on auscultation"]$x$, 3, $x$A pericardial friction rub, a scratchy or grating sound, is the classic auscultatory finding in acute pericarditis. The associated chest pain is typically sharp and pleuritic, worsens when lying supine, and eases when the patient sits up and leans forward.$x$, $x$Medical-Surgical Nursing$x$, $x$medium$x$),
  (12, $x$Which nursing intervention is appropriate during the acute phase of deep vein thrombosis of the leg?$x$, $x$["Vigorously massage the calf to improve venous return","Elevate the affected limb and administer anticoagulant therapy as prescribed","Keep the affected leg dependent and encourage brisk walking","Apply firm heat and have the patient perform forceful leg exercises"]$x$, 1, $x$During acute DVT the affected extremity is elevated to reduce oedema and anticoagulation is given to prevent clot extension and embolisation. Massaging the calf is contraindicated because it can dislodge the thrombus and cause pulmonary embolism.$x$, $x$Medical-Surgical Nursing$x$, $x$medium$x$),
  (13, $x$In acute pulmonary embolism, the typical early arterial blood gas pattern is$x$, $x$["Metabolic acidosis with a normal PaO2","Metabolic alkalosis with hypoventilation","Hypoxaemia with respiratory alkalosis due to hyperventilation","Respiratory acidosis with a high PaCO2"]$x$, 2, $x$Pulmonary embolism causes hypoxaemia, and the resulting tachypnoea and hyperventilation blow off carbon dioxide, lowering the PaCO2 and producing respiratory alkalosis. This combination of hypoxaemia with respiratory alkalosis is the classic early blood gas picture.$x$, $x$Medical-Surgical Nursing$x$, $x$hard$x$),
  (14, $x$The correct isolation precaution for a patient with active pulmonary tuberculosis is$x$, $x$["Contact precautions with gown and gloves only","Airborne precautions in a negative-pressure room with a fitted N95 respirator","Droplet precautions with a surgical mask only","Standard precautions alone are sufficient"]$x$, 1, $x$Mycobacterium tuberculosis spreads via droplet nuclei that remain suspended in the air, so airborne precautions are required. The patient is placed in a negative-pressure room and staff wear a fit-tested N95 respirator when entering.$x$, $x$Medical-Surgical Nursing$x$, $x$easy$x$),
  (15, $x$Hospital-acquired or nosocomial pneumonia is defined as pneumonia that develops$x$, $x$["Exclusively outside of any healthcare facility","Within the first 12 hours of hospital admission","Only in patients who are immunosuppressed","48 hours or more after admission and was not incubating at the time of admission"]$x$, 3, $x$Hospital-acquired pneumonia is diagnosed when pneumonia appears 48 hours or more after admission and was not present or incubating on arrival. It is frequently caused by more resistant organisms than community-acquired pneumonia.$x$, $x$Medical-Surgical Nursing$x$, $x$medium$x$),
  (16, $x$A hallmark feature of acute respiratory distress syndrome is$x$, $x$["A slowly progressive course developing over many years","High lung compliance that makes ventilation easy","Severe refractory hypoxaemia that does not improve with supplemental oxygen","Hypoxaemia that corrects readily with low-flow nasal oxygen"]$x$, 2, $x$ARDS is characterised by refractory hypoxaemia caused by non-cardiogenic pulmonary oedema, alveolar collapse and impaired gas exchange that does not respond to increasing oxygen. It presents with bilateral infiltrates and markedly reduced lung compliance requiring ventilatory support.$x$, $x$Medical-Surgical Nursing$x$, $x$hard$x$),
  (17, $x$Immediately following a thoracentesis for pleural effusion, the priority nursing assessment is to$x$, $x$["Encourage the patient to cough as forcefully as possible","Keep the patient lying completely flat and immobile for 24 hours","Monitor for signs of pneumothorax such as sudden dyspnoea and decreased breath sounds","Withhold vital sign monitoring to allow the patient to rest"]$x$, 2, $x$Pneumothorax is a key complication of thoracentesis because the needle may inadvertently puncture the lung. The nurse watches for sudden dyspnoea, decreased or absent breath sounds, and tachycardia, and a post-procedure chest x-ray is obtained as ordered.$x$, $x$Medical-Surgical Nursing$x$, $x$medium$x$),
  (18, $x$A characteristic clinical feature of bronchiectasis is$x$, $x$["A brief dry cough with no sputum production","Complete absence of respiratory symptoms between infections","Chronic cough producing copious amounts of purulent, often foul-smelling sputum","Sudden pleuritic chest pain with no cough"]$x$, 2, $x$Bronchiectasis involves permanent abnormal dilation of the bronchi with impaired mucus clearance, leading to a chronic cough that produces large volumes of purulent, frequently foul-smelling sputum. Recurrent respiratory infections and haemoptysis are also common.$x$, $x$Medical-Surgical Nursing$x$, $x$medium$x$),
  (19, $x$The nasal cannula is best described as an oxygen delivery device that$x$, $x$["Is a high-flow system that fully meets the patient's entire inspiratory demand","Is a low-flow device delivering roughly 24 to 44 per cent oxygen at 1 to 6 L/min","Can safely deliver 100 per cent oxygen at 15 L/min","Delivers a precise, fixed fraction of inspired oxygen regardless of breathing pattern"]$x$, 1, $x$The nasal cannula is a low-flow device that delivers approximately 24 to 44 per cent oxygen at flow rates of 1 to 6 litres per minute. The actual inspired concentration varies with the patient's respiratory rate and tidal volume.$x$, $x$Medical-Surgical Nursing$x$, $x$easy$x$),
  (20, $x$During the oliguric phase of acute kidney injury, the nurse should monitor most closely for$x$, $x$["Hypernatraemia with rapid weight loss","Hypokalaemia and profound dehydration","Metabolic alkalosis with a low potassium level","Hyperkalaemia and fluid volume overload"]$x$, 3, $x$In the oliguric phase of acute kidney injury, reduced urine output causes retention of fluid, potassium and metabolic acids, producing fluid overload, hyperkalaemia and metabolic acidosis. Hyperkalaemia is especially dangerous because of its risk of fatal cardiac dysrhythmias.$x$, $x$Medical-Surgical Nursing$x$, $x$medium$x$),
  (21, $x$The most common complication of peritoneal dialysis is$x$, $x$["Haemolysis of red blood cells","Peritonitis","Air embolism","Dialysis disequilibrium syndrome"]$x$, 1, $x$Peritonitis is the most common and serious complication of peritoneal dialysis, usually resulting from contamination during exchanges. Cloudy dialysate outflow is often the earliest sign, and strict aseptic technique is essential to prevent it.$x$, $x$Medical-Surgical Nursing$x$, $x$hard$x$),
  (22, $x$A patient with an acute renal calculus reports severe colicky flank pain. The priority nursing actions are to$x$, $x$["Provide prescribed analgesia and strain all urine to detect passage of the stone","Restrict fluid intake to reduce urine formation","Enforce strict bed rest and avoid all movement","Withhold analgesia until the stone has passed spontaneously"]$x$, 0, $x$Renal colic is intensely painful, so prompt administration of prescribed analgesia is a priority, along with straining all urine to catch the stone for laboratory analysis. Adequate fluid intake and ambulation are also encouraged to help promote stone passage.$x$, $x$Medical-Surgical Nursing$x$, $x$medium$x$),
  (23, $x$Benign prostatic hyperplasia most commonly presents with$x$, $x$["Sudden severe flank pain radiating to the groin","Lower urinary tract symptoms such as hesitancy, weak stream, frequency and nocturia","Complete and permanent absence of any urinary symptoms","Painless gross haematuria as the only symptom"]$x$, 1, $x$Benign prostatic hyperplasia enlarges the prostate and obstructs the bladder outlet, producing lower urinary tract symptoms including hesitancy, a weak urinary stream, frequency, urgency and nocturia. Untreated obstruction can progress to urinary retention and recurrent infection.$x$, $x$Medical-Surgical Nursing$x$, $x$medium$x$),
  (24, $x$To reduce the risk of catheter-associated urinary tract infection, the nurse should$x$, $x$["Place the drainage bag on the bed beside the patient during transfers","Keep the drainage bag below bladder level and maintain a closed drainage system","Routinely open the system to irrigate and check the urine flow each shift","Clamp the catheter for several hours each shift to promote bladder training"]$x$, 1, $x$Keeping the drainage bag below the level of the bladder prevents backflow of urine, and maintaining a closed drainage system limits the entry of organisms. These are core measures for preventing catheter-associated urinary tract infection.$x$, $x$Medical-Surgical Nursing$x$, $x$easy$x$),
  (25, $x$Hyponatraemia is defined as a serum sodium concentration below$x$, $x$["145 mEq/L","155 mEq/L","125 mEq/L","135 mEq/L"]$x$, 3, $x$Hyponatraemia is defined as a serum sodium level below 135 mEq/L, the lower limit of the normal 135 to 145 mEq/L range. Severe or rapidly developing hyponatraemia causes cerebral oedema, producing headache, confusion and seizures.$x$, $x$Medical-Surgical Nursing$x$, $x$easy$x$),
  (26, $x$Which intervention most rapidly protects the myocardium against the effects of severe hyperkalaemia?$x$, $x$["Intravenous calcium gluconate","An oral potassium-sparing diuretic","An oral potassium supplement","A slow infusion of potassium chloride"]$x$, 0, $x$Intravenous calcium gluconate is given first in severe hyperkalaemia because it stabilises the cardiac cell membrane and antagonises the effect of potassium on the heart. It does not lower serum potassium, so insulin with glucose or other measures are added to shift or remove potassium.$x$, $x$Medical-Surgical Nursing$x$, $x$hard$x$),
  (27, $x$Which pair of clinical signs suggests hypocalcaemia?$x$, $x$["A positive Murphy sign and rebound tenderness","A positive Homans sign and Kernig sign","A positive Trousseau sign and Chvostek sign","A positive Cullen sign and Grey Turner sign"]$x$, 2, $x$Hypocalcaemia increases neuromuscular excitability, producing a positive Trousseau sign of carpopedal spasm when a blood pressure cuff is inflated and a positive Chvostek sign of facial twitching when the facial nerve is tapped. Severe hypocalcaemia can cause tetany, laryngospasm and seizures.$x$, $x$Medical-Surgical Nursing$x$, $x$hard$x$),
  (28, $x$An arterial blood gas shows pH 7.30, PaCO2 55 mmHg, and HCO3 24 mEq/L. This indicates$x$, $x$["Metabolic alkalosis","Uncompensated metabolic acidosis","Uncompensated respiratory acidosis","Respiratory alkalosis"]$x$, 2, $x$The low pH indicates acidosis, the elevated PaCO2 identifies a respiratory cause, and the normal bicarbonate shows that no metabolic compensation has occurred. Together these values represent uncompensated respiratory acidosis, typically due to alveolar hypoventilation.$x$, $x$Medical-Surgical Nursing$x$, $x$hard$x$),
  (29, $x$An arterial blood gas shows pH 7.50, HCO3 32 mEq/L, and PaCO2 40 mmHg. This indicates$x$, $x$["Respiratory acidosis","Respiratory alkalosis","Metabolic acidosis","Metabolic alkalosis"]$x$, 3, $x$The elevated pH indicates alkalosis and the raised bicarbonate identifies a metabolic origin, while the normal PaCO2 shows the lungs have not yet compensated. These findings represent an uncompensated metabolic alkalosis.$x$, $x$Medical-Surgical Nursing$x$, $x$hard$x$)
) as v(pos, question, options, ci, exp, topic, diff);

-- 18-medsurg-endo-neuro.txt — 30 questions
with b as (
  insert into tests (title, topic, difficulty, duration_minutes)
  values ($x$w1-medsurg-b — ingested draft, verify before trusting$x$, $x$Medical-Surgical Nursing$x$, 'medium', 60)
  returning id
)
insert into questions (test_id, position, question, options, correct_index, explanation, topic, difficulty)
select b.id, v.pos::int, v.question, v.options::jsonb, v.ci::int, v.exp, v.topic, v.diff
from b, (values
  (0, $x$Which finding is most characteristic of hyperthyroidism (Graves' disease)?$x$, $x$["Cold, dry skin with bradycardia","Constipation and lethargy","Exophthalmos and heat intolerance","Weight gain despite poor appetite"]$x$, 2, $x$Graves' disease produces a hypermetabolic state with exophthalmos, heat intolerance, weight loss despite good appetite, tachycardia, and warm moist skin. The other options describe hypothyroidism.$x$, $x$Medical-Surgical Nursing$x$, $x$easy$x$),
  (1, $x$A patient develops thyroid storm after thyroidectomy. Which finding is the hallmark of this crisis?$x$, $x$["Temperature 35 C with slow pulse","Temperature 41 C with heart rate 160/min","Serum sodium 118 mEq/L","Blood glucose 40 mg/dL"]$x$, 1, $x$Thyroid storm is a life-threatening exacerbation of hyperthyroidism marked by extreme hyperpyrexia, severe tachycardia or tachyarrhythmias, and altered mental status. It requires urgent cooling, beta-blockers, and antithyroid drugs.$x$, $x$Medical-Surgical Nursing$x$, $x$hard$x$),
  (2, $x$Which set of findings would the nurse expect in a patient with myxoedema coma?$x$, $x$["Hyperglycaemia and Kussmaul respirations","Hypothermia, hyponatraemia, and depressed level of consciousness","Fever, tachycardia, and hypertension","Exophthalmos, tremor, and diarrhoea"]$x$, 1, $x$Myxoedema coma is severe decompensated hypothyroidism presenting with hypothermia, hyponatraemia, hypoventilation, bradycardia, and reduced consciousness. It is a medical emergency treated with IV thyroid hormone and supportive care.$x$, $x$Medical-Surgical Nursing$x$, $x$medium$x$),
  (3, $x$Which clinical feature is most characteristic of Cushing's syndrome?$x$, $x$["Hyperpigmentation with hypotension","Weight loss and hypoglycaemia","Cold intolerance and periorbital oedema","Truncal obesity with a moon face and buffalo hump"]$x$, 3, $x$Excess cortisol in Cushing's syndrome causes central truncal obesity, moon face, buffalo hump, purple striae, hyperglycaemia, and hypertension. Hyperpigmentation with hypotension instead suggests adrenal insufficiency.$x$, $x$Medical-Surgical Nursing$x$, $x$medium$x$),
  (4, $x$Which statement correctly describes type 1 diabetes mellitus?$x$, $x$["It never leads to ketoacidosis","It results from autoimmune destruction of pancreatic beta cells and requires insulin","It is typically managed with diet and oral hypoglycaemics alone","It is caused primarily by insulin resistance in obese adults"]$x$, 1, $x$Type 1 diabetes results from autoimmune destruction of insulin-producing beta cells, causing absolute insulin deficiency and lifelong insulin dependence. Type 2 is characterised by insulin resistance and relative deficiency, often in adults.$x$, $x$Medical-Surgical Nursing$x$, $x$easy$x$),
  (5, $x$A patient with diabetes insipidus is most likely to show which findings?$x$, $x$["Hyponatraemia with weight gain","Concentrated urine with fluid retention","Large volumes of dilute urine with low urine specific gravity","Oliguria with high urine osmolality"]$x$, 2, $x$Diabetes insipidus results from ADH deficiency or resistance, producing polyuria of dilute urine with low specific gravity, intense thirst, and risk of hypernatraemia and dehydration. Careful fluid balance and desmopressin are key to management.$x$, $x$Medical-Surgical Nursing$x$, $x$medium$x$),
  (6, $x$Which nursing intervention is appropriate for a patient with syndrome of inappropriate antidiuretic hormone (SIADH)?$x$, $x$["Administer intravenous 5% dextrose freely","Give desmopressin to reduce urine output","Restrict fluids and monitor serum sodium","Encourage a high fluid intake"]$x$, 2, $x$SIADH causes excess ADH, water retention, dilutional hyponatraemia, and concentrated urine. Management centres on fluid restriction, monitoring serum sodium, and sometimes hypertonic saline; giving free water or desmopressin would worsen it.$x$, $x$Medical-Surgical Nursing$x$, $x$hard$x$),
  (7, $x$Which nursing action is most appropriate for a patient with cirrhosis and ascites?$x$, $x$["Position the patient flat to ease breathing","Measure abdominal girth and daily weight","Restrict protein completely in all patients","Encourage a high-sodium diet"]$x$, 1, $x$Monitoring abdominal girth and daily weight tracks fluid accumulation in ascites. Care includes sodium and fluid restriction, semi-Fowler's positioning to ease breathing, and diuretics; protein is moderated only if encephalopathy develops.$x$, $x$Medical-Surgical Nursing$x$, $x$medium$x$),
  (8, $x$A cirrhotic patient with bleeding oesophageal varices is admitted. What is the nurse's priority?$x$, $x$["Encourage vigorous coughing","Maintain airway and manage the haemorrhage","Provide a high-fibre diet immediately","Position the patient supine and flat"]$x$, 1, $x$Ruptured oesophageal varices cause massive upper GI bleeding, so airway protection and haemodynamic support are the priority. Management includes fluid and blood replacement, vasoactive drugs like octreotide, endoscopic banding, and balloon tamponade if needed.$x$, $x$Medical-Surgical Nursing$x$, $x$hard$x$),
  (9, $x$Which laboratory finding best supports a diagnosis of acute pancreatitis?$x$, $x$["Markedly elevated serum amylase and lipase","Elevated serum ammonia","Elevated serum bilirubin only","Decreased serum lipase"]$x$, 0, $x$Acute pancreatitis is confirmed by markedly raised serum amylase and, more specifically, lipase. Nursing care emphasises pain control, keeping the patient NPO to rest the pancreas, IV fluids, and monitoring for hypocalcaemia and shock.$x$, $x$Medical-Surgical Nursing$x$, $x$hard$x$),
  (10, $x$Which feature distinguishes Crohn's disease from ulcerative colitis?$x$, $x$["It involves only the mucosal layer","It is limited to the rectum and colon","It causes transmural inflammation with skip lesions anywhere in the GI tract","It always spares the small intestine"]$x$, 2, $x$Crohn's disease causes transmural inflammation with discontinuous skip lesions that may involve any part of the GI tract from mouth to anus. Ulcerative colitis is continuous, mucosal, and confined to the rectum and colon.$x$, $x$Medical-Surgical Nursing$x$, $x$medium$x$),
  (11, $x$Which precaution is most important when caring for a patient with hepatitis B?$x$, $x$["Wearing a mask for all contact","Strict fluid restriction","Standard precautions with careful handling of blood and body fluids","Airborne isolation in a negative-pressure room"]$x$, 2, $x$Hepatitis B is transmitted through blood and body fluids, so standard precautions with safe handling of needles and body fluids are essential. Hepatitis A and E spread by the faecal-oral route and require attention to hand hygiene and sanitation.$x$, $x$Medical-Surgical Nursing$x$, $x$medium$x$),
  (12, $x$Which symptom is most characteristic of acute cholecystitis?$x$, $x$["Right upper quadrant pain after a fatty meal","Painless jaundice with weight gain","Burning epigastric pain relieved by food","Lower left quadrant pain with diarrhoea"]$x$, 0, $x$Acute cholecystitis typically causes right upper quadrant pain, often after a fatty meal, with nausea and a positive Murphy's sign. Gallstones are the usual cause, and pain may radiate to the right shoulder or scapula.$x$, $x$Medical-Surgical Nursing$x$, $x$easy$x$),
  (13, $x$Which finding would the nurse expect in a patient with mechanical small bowel obstruction?$x$, $x$["Abdominal distension with vomiting and high-pitched bowel sounds","Increased frequency of normal bowel movements","Soft non-tender abdomen with normal appetite","Passage of large formed stools"]$x$, 0, $x$Mechanical bowel obstruction produces colicky pain, abdominal distension, vomiting, obstipation, and early high-pitched then later absent bowel sounds. Management includes NPO status, nasogastric decompression, and fluid and electrolyte replacement.$x$, $x$Medical-Surgical Nursing$x$, $x$medium$x$),
  (14, $x$Which statement about stroke management is correct?$x$, $x$["CT scanning is unnecessary before treatment","Thrombolytic therapy is used only for ischaemic stroke within the time window","All strokes are treated with immediate anticoagulation","Haemorrhagic stroke is treated with thrombolytics"]$x$, 1, $x$Thrombolytic therapy is indicated only for ischaemic stroke within the eligible time window and after haemorrhage is excluded by CT. Giving thrombolytics in haemorrhagic stroke would be catastrophic, so imaging always precedes treatment.$x$, $x$Medical-Surgical Nursing$x$, $x$easy$x$),
  (15, $x$A patient with a right-hemisphere stroke has left homonymous hemianopia. Which rehabilitation approach is appropriate?$x$, $x$["Restrict the patient to bed to prevent falls","Teach the patient to scan toward the affected side and approach from the unaffected side initially","Speak only from the affected left side","Avoid teaching because the deficit is permanent"]$x$, 1, $x$With homonymous hemianopia the patient loses half the visual field, so teaching deliberate head-scanning toward the affected side improves safety. Initially placing objects and approaching from the intact side reduces neglect-related injury.$x$, $x$Medical-Surgical Nursing$x$, $x$medium$x$),
  (16, $x$Which group of signs is characteristic of Parkinson's disease?$x$, $x$["Intention tremor with scanning speech and nystagmus","Resting pill-rolling tremor, bradykinesia, rigidity, and shuffling gait","Ascending flaccid paralysis","Sudden hemiparesis and aphasia"]$x$, 1, $x$Parkinson's disease features the classic triad of resting pill-rolling tremor, bradykinesia, and cogwheel rigidity, along with a stooped posture and shuffling festinating gait. It results from dopamine depletion in the substantia nigra.$x$, $x$Medical-Surgical Nursing$x$, $x$medium$x$),
  (17, $x$Which statement best describes multiple sclerosis?$x$, $x$["It is a chronic demyelinating disease with a relapsing-remitting course","It is caused by dopamine deficiency","It causes permanent flaccid paralysis within hours","It is an acute bacterial infection of the meninges"]$x$, 0, $x$Multiple sclerosis is a chronic autoimmune demyelinating disease of the central nervous system, often following a relapsing-remitting pattern. Symptoms include fatigue, visual disturbances, weakness, and impaired coordination, and heat can worsen them.$x$, $x$Medical-Surgical Nursing$x$, $x$medium$x$),
  (18, $x$A patient with myasthenia gravis develops worsening weakness. Which feature suggests myasthenic crisis rather than cholinergic crisis?$x$, $x$["Excessive salivation, diarrhoea, and muscle fasciculations","Improvement of weakness after giving more anticholinesterase","Weakness that worsens because of insufficient anticholinesterase medication","Constricted pupils with abdominal cramps"]$x$, 2, $x$Myasthenic crisis is severe weakness from undermedication or a trigger, improving with anticholinesterase and needing airway support. Cholinergic crisis results from overmedication, causing muscarinic effects such as salivation, diarrhoea, and fasciculations.$x$, $x$Medical-Surgical Nursing$x$, $x$hard$x$),
  (19, $x$Which assessment is the priority in a patient with Guillain-Barre syndrome?$x$, $x$["Checking pupillary size every shift","Monitoring blood glucose hourly","Monitoring respiratory function and vital capacity","Assessing for a rigid, board-like abdomen"]$x$, 2, $x$Guillain-Barre syndrome causes an ascending paralysis that can involve the respiratory muscles, so serial vital capacity and respiratory monitoring are the priority. Declining vital capacity signals impending respiratory failure requiring ventilatory support.$x$, $x$Medical-Surgical Nursing$x$, $x$hard$x$),
  (20, $x$Which finding supports a diagnosis of bacterial meningitis?$x$, $x$["Flaccid ascending paralysis","Resting tremor and rigidity","Nuchal rigidity with positive Kernig's and Brudzinski's signs","Painless loss of vision"]$x$, 2, $x$Bacterial meningitis presents with fever, severe headache, photophobia, and nuchal rigidity, with positive Kernig's and Brudzinski's signs. Droplet precautions, prompt antibiotics, and neurological monitoring are essential nursing priorities.$x$, $x$Medical-Surgical Nursing$x$, $x$medium$x$),
  (21, $x$Which precaution is essential when a nurse administers cytotoxic chemotherapy?$x$, $x$["Wear chemotherapy-rated gloves and gown and use a spill kit for spills","Dispose of drug waste in the regular bin","No special protective equipment is required","Recap and reuse needles to reduce waste"]$x$, 0, $x$Cytotoxic drugs are hazardous, so nurses must use chemotherapy-rated gloves and gowns, prepare drugs in a biological safety cabinet, and manage spills with a designated spill kit. Waste and sharps go into labelled cytotoxic containers.$x$, $x$Medical-Surgical Nursing$x$, $x$medium$x$),
  (22, $x$Which instruction is correct for a patient receiving external beam radiation therapy?$x$, $x$["Expose the irradiated skin to direct sunlight to promote healing","Scrub the skin markings off daily","Do not wash off skin markings and avoid lotions, powders, and sun exposure to the site","Apply heating pads to the treatment site"]$x$, 2, $x$Radiation skin markings must be preserved to ensure accurate targeting, so the site is gently patted, not scrubbed. Patients should avoid lotions, powders, heat, friction, and sun exposure over the treated area to prevent skin breakdown.$x$, $x$Medical-Surgical Nursing$x$, $x$medium$x$),
  (23, $x$According to the CAUTION warning signs of cancer, which of the following should prompt evaluation?$x$, $x$["Transient muscle soreness after exercise","Occasional mild tension headache","Brief seasonal sneezing","A sore that does not heal or unusual bleeding or discharge"]$x$, 3, $x$The CAUTION mnemonic highlights early cancer warning signs, including a change in bowel or bladder habits, a sore that does not heal, unusual bleeding or discharge, a lump, indigestion or dysphagia, an obvious change in a wart or mole, and a nagging cough.$x$, $x$Medical-Surgical Nursing$x$, $x$easy$x$),
  (24, $x$Which is the primary goal of palliative and end-of-life care?$x$, $x$["Pursuing aggressive curative treatment at all costs","Restricting family presence during the dying process","Withholding all analgesia to preserve alertness","Providing comfort and relief of symptoms such as pain and dyspnoea"]$x$, 3, $x$Palliative care focuses on comfort and quality of life, relieving distressing symptoms such as pain, dyspnoea, and nausea rather than curing disease. It supports the patient and family holistically, including emotional and spiritual needs.$x$, $x$Medical-Surgical Nursing$x$, $x$medium$x$),
  (25, $x$An incomplete fracture in which the bone bends and cracks, common in children, is called a$x$, $x$["Pathological fracture","Greenstick fracture","Compound fracture","Comminuted fracture"]$x$, 1, $x$A greenstick fracture is an incomplete break where the bone bends and cracks, typical of children whose bones are more pliable. A comminuted fracture shatters into fragments, and a compound or open fracture breaks through the skin.$x$, $x$Medical-Surgical Nursing$x$, $x$easy$x$),
  (26, $x$Which nursing action is appropriate for a patient with a newly applied plaster cast?$x$, $x$["Insert a knitting needle to scratch inside the cast","Cover the wet cast with a blanket to speed drying","Rest the wet cast on a hard flat surface","Elevate the limb and perform neurovascular checks"]$x$, 3, $x$A new cast is elevated to reduce swelling, and frequent neurovascular checks of colour, warmth, pulses, capillary refill, movement, and sensation detect compromise early. The cast should dry uncovered, be handled with the palms, and nothing should be inserted inside it.$x$, $x$Medical-Surgical Nursing$x$, $x$medium$x$),
  (27, $x$Which feature is more characteristic of rheumatoid arthritis than osteoarthritis?$x$, $x$["Involvement of weight-bearing joints from wear and tear","Symmetric joint involvement with morning stiffness lasting more than one hour and systemic symptoms","Heberden's nodes at the distal interphalangeal joints","Asymmetric joint involvement with brief morning stiffness"]$x$, 1, $x$Rheumatoid arthritis is a systemic autoimmune disease causing symmetric joint inflammation, prolonged morning stiffness over an hour, fatigue, and fever. Osteoarthritis is a degenerative wear-and-tear disorder with asymmetric involvement and brief stiffness.$x$, $x$Medical-Surgical Nursing$x$, $x$hard$x$),
  (28, $x$Which intervention helps prevent and manage osteoporosis?$x$, $x$["Avoiding all physical activity","Strict bed rest to protect fragile bones","A high-caffeine, high-alcohol diet","Adequate calcium and vitamin D intake with weight-bearing exercise"]$x$, 3, $x$Osteoporosis is characterised by low bone density and increased fracture risk, so prevention relies on adequate calcium and vitamin D, weight-bearing exercise, and fall prevention. Smoking, excess alcohol, caffeine, and inactivity worsen bone loss.$x$, $x$Medical-Surgical Nursing$x$, $x$easy$x$),
  (29, $x$Which statement about osteomyelitis is correct?$x$, $x$["It never requires surgical debridement","It is best treated with a short single dose of oral antibiotics","It is a bone infection usually requiring prolonged intravenous antibiotic therapy","It is a non-infectious degeneration of cartilage"]$x$, 2, $x$Osteomyelitis is an infection of bone, most often bacterial, presenting with pain, fever, swelling, and warmth over the site. Treatment involves prolonged intravenous antibiotics and sometimes surgical debridement of necrotic sequestrum tissue.$x$, $x$Medical-Surgical Nursing$x$, $x$hard$x$)
) as v(pos, question, options, ci, exp, topic, diff);

-- 19-obg-child-2.txt — 28 questions
with b as (
  insert into tests (title, topic, difficulty, duration_minutes)
  values ($x$w1-obg-child — ingested draft, verify before trusting$x$, $x$Obstetrics & Child Health$x$, 'medium', 60)
  returning id
)
insert into questions (test_id, position, question, options, correct_index, explanation, topic, difficulty)
select b.id, v.pos::int, v.question, v.options::jsonb, v.ci::int, v.exp, v.topic, v.diff
from b, (values
  (0, $x$During which phase of the endometrial cycle does progesterone from the corpus luteum convert the lining into a secretory glandular structure ready for implantation?$x$, $x$["Secretory phase","Proliferative phase","Menstrual phase","Regenerative phase"]$x$, 0, $x$After ovulation the corpus luteum secretes progesterone, which transforms the proliferative endometrium into a secretory one with tortuous glands and glycogen stores. This prepares the lining to receive the blastocyst for implantation.$x$, $x$Obstetrics & Child Health$x$, $x$medium$x$),
  (1, $x$Fertilisation of the ovum by the sperm most commonly takes place in which part of the fallopian tube?$x$, $x$["Ampulla","Isthmus","Infundibulum","Interstitial part"]$x$, 0, $x$The ampulla is the widest and longest segment of the tube, where the sperm normally meets and fertilises the ovum. The resulting zygote then travels toward the uterine cavity over the next few days for implantation.$x$, $x$Obstetrics & Child Health$x$, $x$easy$x$),
  (2, $x$Implantation of the blastocyst into the uterine endometrium normally occurs about how many days after fertilisation?$x$, $x$["1 to 2 days","14 to 15 days","10 to 11 days","6 to 7 days"]$x$, 3, $x$The blastocyst reaches the uterine cavity around day 4 to 5 and begins to implant in the secretory endometrium about 6 to 7 days after fertilisation. The process of implantation is usually completed by about day 10 to 11.$x$, $x$Obstetrics & Child Health$x$, $x$medium$x$),
  (3, $x$The physiological fall in haemoglobin concentration during pregnancy is chiefly explained by which of the following?$x$, $x$["Increased red cell destruction","A greater rise in plasma volume than in red cell mass","Reduced erythropoietin secretion","Chronic iron deficiency"]$x$, 1, $x$Plasma volume increases by about 45 to 50 per cent whereas red cell mass rises only around 20 to 30 per cent, producing a dilutional or physiological anaemia. This apparent fall in haemoglobin is maximal near 30 to 32 weeks of gestation.$x$, $x$Obstetrics & Child Health$x$, $x$medium$x$),
  (4, $x$All of the following are recognised antenatal danger signs that warrant urgent evaluation except$x$, $x$["Reduced or absent fetal movements","Severe persistent headache with blurred vision","Vaginal bleeding","Mild bilateral ankle oedema in the third trimester"]$x$, 3, $x$Mild dependent ankle oedema is a common and benign finding in late pregnancy due to venous stasis. Vaginal bleeding, severe headache with visual disturbance, and reduced fetal movements are true danger signs requiring immediate assessment.$x$, $x$Obstetrics & Child Health$x$, $x$medium$x$),
  (5, $x$Under the DIPSI single-step protocol used in India, gestational diabetes is diagnosed when the two-hour plasma glucose after a 75 gram oral glucose load is at least$x$, $x$["140 mg/dL","110 mg/dL","200 mg/dL","160 mg/dL"]$x$, 0, $x$In the DIPSI test a 75 gram glucose load is given irrespective of the last meal and plasma glucose is measured at two hours. A value of 140 mg/dL or more diagnoses gestational diabetes, making it a convenient single-step field test.$x$, $x$Obstetrics & Child Health$x$, $x$hard$x$),
  (6, $x$According to ICMR grading of anaemia in pregnancy, a haemoglobin level of 7 to 10 g/dL is classified as$x$, $x$["Mild anaemia","Moderate anaemia","Severe anaemia","Very severe anaemia"]$x$, 1, $x$ICMR grades anaemia as mild at 10 to 10.9 g/dL, moderate at 7 to 10 g/dL, severe at 4 to 6.9 g/dL and very severe below 4 g/dL. Moderate anaemia usually requires oral or, if not tolerated, parenteral iron therapy.$x$, $x$Obstetrics & Child Health$x$, $x$medium$x$),
  (7, $x$A woman with severe hyperemesis gravidarum develops confusion, nystagmus and ataxia. This complication results from deficiency of which vitamin?$x$, $x$["Vitamin D","Vitamin B1 or thiamine","Vitamin B12","Vitamin C"]$x$, 1, $x$Prolonged vomiting depletes thiamine and can precipitate Wernicke's encephalopathy, presenting with the triad of confusion, ophthalmoplegia or nystagmus, and ataxia. Thiamine must therefore be given before any glucose-containing infusion.$x$, $x$Obstetrics & Child Health$x$, $x$hard$x$),
  (8, $x$Twin-to-twin transfusion syndrome, in which one fetus becomes a donor and the other a recipient, occurs only in which type of twin pregnancy?$x$, $x$["Dizygotic","Monochorionic","Any dichorionic pregnancy","Dichorionic diamniotic"]$x$, 1, $x$This syndrome arises from placental vascular anastomoses shared by monochorionic twins who have a single placenta, causing unequal blood distribution. Dichorionic and dizygotic twins have separate placentas and are not affected.$x$, $x$Obstetrics & Child Health$x$, $x$hard$x$),
  (9, $x$Polyhydramnios is diagnosed when the total liquor volume exceeds approximately$x$, $x$["500 mL","1000 mL","1500 mL","2000 mL"]$x$, 3, $x$Normal amniotic fluid at term is about 500 to 1500 mL; polyhydramnios is defined as more than 2000 mL or an amniotic fluid index above 25 cm. It is associated with fetal anomalies, maternal diabetes and multiple pregnancy.$x$, $x$Obstetrics & Child Health$x$, $x$medium$x$),
  (10, $x$Marked oligohydramnios detected in the second trimester is most classically associated with which fetal anomaly?$x$, $x$["Anencephaly","Bilateral renal agenesis","Duodenal atresia","Oesophageal atresia"]$x$, 1, $x$Fetal urine is the main source of liquor in the second half of pregnancy, so bilateral renal agenesis, or Potter syndrome, causes severe oligohydramnios. Anencephaly and the atresias are instead linked with polyhydramnios.$x$, $x$Obstetrics & Child Health$x$, $x$hard$x$),
  (11, $x$In which type of breech presentation are the hips flexed and both knees extended, making it the commonest variety?$x$, $x$["Frank breech","Complete breech","Footling breech","Knee presentation"]$x$, 0, $x$In frank or extended breech the thighs are flexed on the abdomen while the legs are extended over the trunk, with the buttocks presenting. It is the commonest breech type, seen especially in primigravidae with good uterine tone.$x$, $x$Obstetrics & Child Health$x$, $x$easy$x$),
  (12, $x$The type of episiotomy most widely practised in India, chosen because it is less likely to extend into the anal sphincter, is the$x$, $x$["Lateral episiotomy","Mediolateral episiotomy","J-shaped episiotomy","Median or midline episiotomy"]$x$, 1, $x$The mediolateral incision is directed away from the anus, reducing the risk of third and fourth degree extension into the sphincter and rectum. The median type heals better but carries a higher risk of anal extension.$x$, $x$Obstetrics & Child Health$x$, $x$medium$x$),
  (13, $x$Ventouse or vacuum extraction is generally avoided in a fetus of less than 34 weeks gestation mainly because of the risk of$x$, $x$["Erb's palsy","Subgaleal or intracranial haemorrhage","Facial nerve palsy","Fractured clavicle"]$x$, 1, $x$The preterm skull is soft and its vessels are fragile, so vacuum application increases the risk of subgaleal and intraventricular haemorrhage. For this reason forceps or caesarean section are preferred in very preterm deliveries.$x$, $x$Obstetrics & Child Health$x$, $x$hard$x$),
  (14, $x$The oral levonorgestrel emergency contraceptive pill is most effective when taken within how long after unprotected intercourse?$x$, $x$["Within 7 days","Within 2 weeks","Within 72 hours","Within 10 days"]$x$, 2, $x$Levonorgestrel emergency contraception should be taken as early as possible and within 72 hours of unprotected sex, with efficacy declining as time passes. It works mainly by inhibiting or delaying ovulation, not by disrupting an established pregnancy.$x$, $x$Obstetrics & Child Health$x$, $x$easy$x$),
  (15, $x$Menopause is confirmed clinically only after menstruation has ceased continuously for at least$x$, $x$["6 months","12 months","3 months","24 months"]$x$, 1, $x$Menopause is defined retrospectively as amenorrhoea for 12 consecutive months in the absence of any other cause. The average age of natural menopause in India is around 45 to 50 years, somewhat earlier than in Western populations.$x$, $x$Obstetrics & Child Health$x$, $x$easy$x$),
  (16, $x$On a standard growth chart, the single most useful indicator of an emerging nutritional problem in a child is$x$, $x$["The heights of the parents","The child's recorded length at birth","The direction and trend of the weight-for-age curve over time","A single weight reading below the 50th percentile"]$x$, 2, $x$Serial plotting matters far more than any single reading; a weight curve that flattens or falls, crossing percentile lines downward, signals growth faltering. One point below the median may be perfectly normal for that individual child.$x$, $x$Obstetrics & Child Health$x$, $x$medium$x$),
  (17, $x$The mature pincer grasp, using the tip of the thumb and index finger to pick up a small object, is normally acquired by about$x$, $x$["4 months","6 months","9 to 10 months","15 months"]$x$, 2, $x$The neat pincer grasp develops around 9 to 10 months, following the immature palmar grasp at about 6 months and raking at 7 to 8 months. Its appearance reflects normal fine-motor and neurological maturation.$x$, $x$Obstetrics & Child Health$x$, $x$medium$x$),
  (18, $x$Which of the following is a true contraindication to administering a live vaccine such as BCG or oral polio?$x$, $x$["Mild fever with cough and cold","Breastfeeding","Malnutrition","Severe immunodeficiency, such as symptomatic HIV or AIDS"]$x$, 3, $x$Live vaccines are contraindicated in severe immunodeficiency because the attenuated organism may itself cause disease. Minor illness, malnutrition and breastfeeding are not contraindications and represent common missed-opportunity myths.$x$, $x$Obstetrics & Child Health$x$, $x$hard$x$),
  (19, $x$Under IMNCI, a child with diarrhoea who is restless or irritable, has sunken eyes, drinks eagerly, and whose skin pinch goes back slowly is classified as having$x$, $x$["Severe dehydration","Persistent diarrhoea","Some dehydration","No dehydration"]$x$, 2, $x$The combination of restlessness, sunken eyes, eager drinking and a slow skin pinch indicates some dehydration, managed with ORS under Treatment Plan B. Severe dehydration instead shows lethargy, inability to drink and a very slowly returning skin pinch.$x$, $x$Obstetrics & Child Health$x$, $x$medium$x$),
  (20, $x$In the IMNCI classification of a child aged 2 months to 5 years with cough, the presence of lower chest wall indrawing indicates$x$, $x$["Bronchial asthma","Severe pneumonia or very severe disease requiring referral","No pneumonia, cough or cold","Pneumonia to be treated at home"]$x$, 1, $x$Lower chest wall indrawing is a danger sign that classifies the illness as severe pneumonia, requiring a first dose of antibiotic and urgent referral. This is more serious than the classification based on raised respiratory rate alone.$x$, $x$Obstetrics & Child Health$x$, $x$hard$x$),
  (21, $x$Which intestinal helminth is the most important parasitic cause of iron-deficiency anaemia in children through chronic intestinal blood loss?$x$, $x$["Enterobius vermicularis or pinworm","Hookworm, Ancylostoma or Necator","Taenia saginata","Ascaris lumbricoides"]$x$, 1, $x$Hookworms attach to the intestinal mucosa and suck blood, producing chronic occult blood loss and iron-deficiency anaemia. Pinworm mainly causes perianal itching and Ascaris may cause obstruction, but neither typically causes significant anaemia.$x$, $x$Obstetrics & Child Health$x$, $x$medium$x$),
  (22, $x$In the inpatient management of a child with severe acute malnutrition, the most immediately life-threatening complications to prevent during the stabilisation phase are$x$, $x$["Constipation","Excess protein intake","Slow weight gain","Hypoglycaemia and hypothermia"]$x$, 3, $x$During stabilisation, hypoglycaemia, hypothermia and dehydration are the main killers, so frequent F-75 feeds and warmth are essential. High-calorie catch-up feeding is deliberately delayed to avoid precipitating refeeding syndrome and cardiac failure.$x$, $x$Obstetrics & Child Health$x$, $x$hard$x$),
  (23, $x$A newborn with a cleft lip and palate mainly has difficulty with feeding because of$x$, $x$["Lack of hunger","Complete oesophageal obstruction","Absence of the swallowing reflex","Inability to generate adequate suction"]$x$, 3, $x$The oro-nasal communication prevents an effective seal and negative pressure, so the baby cannot suck efficiently and may regurgitate through the nose or aspirate. Special cleft feeders, spoon or paladai feeding and an upright position help until surgical repair.$x$, $x$Obstetrics & Child Health$x$, $x$medium$x$),
  (24, $x$Down syndrome, the commonest chromosomal cause of intellectual disability, results from$x$, $x$["Monosomy X","Trisomy 21","Trisomy 13","Trisomy 18"]$x$, 1, $x$Down syndrome is caused by an extra chromosome 21, or trisomy 21, most often from meiotic non-disjunction and commoner with advanced maternal age. Typical features include hypotonia, a flat facial profile, upslanting palpebral fissures and a single palmar crease.$x$, $x$Obstetrics & Child Health$x$, $x$easy$x$),
  (25, $x$Peri-conceptional supplementation of which vitamin markedly reduces the risk of neural tube defects such as spina bifida?$x$, $x$["Vitamin A","Vitamin B12","Vitamin K","Folic acid"]$x$, 3, $x$Adequate folic acid before conception and in early pregnancy prevents failure of neural tube closure, lowering the risk of spina bifida and anencephaly. A daily dose of about 400 micrograms is advised, with higher doses for high-risk women.$x$, $x$Obstetrics & Child Health$x$, $x$medium$x$),
  (26, $x$Regarding a simple febrile convulsion, which statement is correct?$x$, $x$["It usually lasts more than 30 minutes","It commonly leaves permanent neurological damage","It typically occurs in infants under 3 months of age","It occurs between 6 months and 5 years and is generally benign"]$x$, 3, $x$Simple febrile convulsions occur between 6 months and 5 years, are brief at under 15 minutes, generalised, and do not recur within 24 hours. They carry an excellent prognosis with no lasting brain damage, and management centres on controlling fever and parental reassurance.$x$, $x$Obstetrics & Child Health$x$, $x$hard$x$),
  (27, $x$In a child who has swallowed a corrosive substance such as an acid or alkali, the first-aid measure that is contraindicated is$x$, $x$["Inducing vomiting","Removing any contaminated clothing","Taking the child urgently to hospital","Keeping the child calm"]$x$, 0, $x$Inducing vomiting after corrosive ingestion is dangerous because it re-exposes the oesophagus to the caustic agent and risks aspiration and perforation. The child should be kept calm and taken urgently to hospital with the container or label for identification.$x$, $x$Obstetrics & Child Health$x$, $x$easy$x$)
) as v(pos, question, options, ci, exp, topic, diff);

-- 20-foundations-vitals.txt — 24 questions
with b as (
  insert into tests (title, topic, difficulty, duration_minutes)
  values ($x$w2-foundations-a — ingested draft, verify before trusting$x$, $x$Nursing Foundations$x$, 'medium', 60)
  returning id
)
insert into questions (test_id, position, question, options, correct_index, explanation, topic, difficulty)
select b.id, v.pos::int, v.question, v.options::jsonb, v.ci::int, v.exp, v.topic, v.diff
from b, (values
  (0, $x$What is the average normal oral body temperature of a healthy adult?$x$, $x$["35 C, or 95 F","37 C, or 98.6 F","39 C, or 102.2 F","34 C, or 93.2 F"]$x$, 1, $x$The average normal oral temperature is 37 C, or 98.6 F, with an accepted range of about 36.5 to 37.5 C. Readings above this range suggest fever, while lower readings suggest hypothermia.$x$, $x$Nursing Foundations$x$, $x$easy$x$),
  (1, $x$The generally accepted normal blood pressure value for a healthy adult is approximately$x$, $x$["160/100 mmHg","140/90 mmHg","90/60 mmHg","120/80 mmHg"]$x$, 3, $x$Normal adult blood pressure is about 120/80 mmHg, where 120 is the systolic and 80 the diastolic pressure. Persistently raised values such as 140/90 mmHg indicate hypertension.$x$, $x$Nursing Foundations$x$, $x$easy$x$),
  (2, $x$While recording blood pressure, which Korotkoff sound marks the systolic pressure?$x$, $x$["Phase IV, abrupt muffling of sound","Phase V, disappearance of sound","Phase I, the first clear tapping sound","Phase II, a swishing sound"]$x$, 2, $x$The systolic pressure is read at Phase I, the first clear tapping sound heard as the cuff is deflated. It represents the pressure at which blood first spurts through the artery.$x$, $x$Nursing Foundations$x$, $x$medium$x$),
  (3, $x$In an adult, which Korotkoff phase is taken as the diastolic blood pressure?$x$, $x$["Phase III","Phase I","Phase V","Phase II"]$x$, 2, $x$In adults, diastolic pressure corresponds to Phase V, the point at which sounds disappear completely. Phase IV, or muffling, is used to record diastolic pressure in children and some pregnant women.$x$, $x$Nursing Foundations$x$, $x$hard$x$),
  (4, $x$A fever in which the temperature fluctuates over 24 hours but never returns to the normal baseline is called$x$, $x$["Relapsing fever","Constant or sustained fever","Intermittent fever","Remittent fever"]$x$, 3, $x$In remittent fever the temperature rises and falls but always remains above normal, never touching baseline. This contrasts with intermittent fever, in which the temperature returns to normal between spikes.$x$, $x$Nursing Foundations$x$, $x$hard$x$),
  (5, $x$The primary physiological effect of applying a cold pack to an acute sprain is$x$, $x$["Vasodilation with increased blood flow","Increased local tissue metabolism","Vasoconstriction with reduced blood flow and swelling","Increased capillary permeability"]$x$, 2, $x$Cold application produces vasoconstriction, which reduces blood flow, swelling and inflammation and also numbs pain. It is therefore useful within the first 24 to 48 hours of an acute injury.$x$, $x$Nursing Foundations$x$, $x$medium$x$),
  (6, $x$The main therapeutic effect of a warm or hot application on tissues is$x$, $x$["Decreased tissue metabolism","Vasodilation with increased blood flow","Vasoconstriction with reduced blood flow","Numbing of nerve endings only"]$x$, 1, $x$Heat causes vasodilation, increasing blood flow and delivery of oxygen and nutrients while relaxing muscles. It is used to relieve chronic pain, promote suppuration and reduce stiffness.$x$, $x$Nursing Foundations$x$, $x$easy$x$),
  (7, $x$Which route of temperature measurement most closely reflects core body temperature and reads highest?$x$, $x$["Axillary","Oral","Rectal","Tympanic surface"]$x$, 2, $x$The rectal route best reflects core body temperature and reads roughly 0.5 C higher than oral. The axillary route is the least accurate, reading about 0.5 C lower than the oral value.$x$, $x$Nursing Foundations$x$, $x$hard$x$),
  (8, $x$The apical pulse in an adult is best auscultated at the$x$, $x$["Fifth intercostal space at the left midclavicular line","Second intercostal space at the right sternal border","Epigastric region","Sternal angle, or angle of Louis"]$x$, 0, $x$The apical pulse is heard at the point of maximal impulse, the fifth intercostal space at the left midclavicular line. It is the most reliable site for assessing the heart rate, especially in infants.$x$, $x$Nursing Foundations$x$, $x$medium$x$),
  (9, $x$During a bed bath, the patient's eyes should be cleaned$x$, $x$["From the inner to the outer canthus, using a clean section of cloth for each eye","From the outer to the inner canthus","Using the same cloth surface for both eyes","By applying soap directly onto the eyeball"]$x$, 0, $x$The eyes are wiped from the inner to the outer canthus using a separate clean part of the cloth for each eye. This prevents debris from entering the lacrimal duct and avoids cross-contamination between eyes.$x$, $x$Nursing Foundations$x$, $x$medium$x$),
  (10, $x$The safest position for giving mouth care to an unconscious patient is$x$, $x$["Side-lying or lateral with the head turned to one side","Trendelenburg position","High Fowler's position","Supine and flat"]$x$, 0, $x$An unconscious patient is placed side-lying with the head turned to one side so that fluid and secretions drain out of the mouth. This prevents aspiration because protective airway reflexes are absent.$x$, $x$Nursing Foundations$x$, $x$medium$x$),
  (11, $x$A pressure injury appearing as intact skin with localised non-blanchable erythema over a bony prominence is classified as$x$, $x$["Stage 1","Stage 3","Stage 4","Stage 2"]$x$, 0, $x$Stage 1 pressure injury is intact skin showing non-blanchable redness, without an open wound. Redness that blanches on pressure indicates reactive hyperaemia rather than a stage 1 injury.$x$, $x$Nursing Foundations$x$, $x$hard$x$),
  (12, $x$On an intake and output chart, which of the following is recorded under output?$x$, $x$["Intravenous fluids infused","Urine, vomitus and wound drainage","Nasogastric tube feeding administered","Oral fluids and ice chips taken"]$x$, 1, $x$Output includes all measurable fluid losses such as urine, vomitus, wound or drain output and liquid stool. Intravenous fluids, oral fluids and tube feeds are all recorded as intake.$x$, $x$Nursing Foundations$x$, $x$medium$x$),
  (13, $x$The Sims, or semi-prone, position is most commonly used for$x$, $x$["Enema administration and rectal examination","Vaginal delivery","Lumbar puncture","Abdominal surgery"]$x$, 0, $x$Sims is a left side-lying position with the upper knee flexed, used for enema administration and rectal examination and to promote drainage in unconscious patients. It relaxes the anal sphincter and eases insertion.$x$, $x$Nursing Foundations$x$, $x$easy$x$),
  (14, $x$The lithotomy position is characterised by the patient being$x$, $x$["In left side-lying with the upper knee flexed","Lying prone on the abdomen","Positioned with the head lower than the feet","Supine with hips and knees flexed, thighs abducted, and legs supported in stirrups"]$x$, 3, $x$Lithotomy places the patient supine with the hips flexed, thighs abducted and legs held in stirrups. It is used for perineal, vaginal and rectal procedures and for childbirth.$x$, $x$Nursing Foundations$x$, $x$medium$x$),
  (15, $x$Movement of a limb away from the midline of the body is termed$x$, $x$["Abduction","Internal rotation","Adduction","Flexion"]$x$, 0, $x$Abduction is movement of a body part away from the body's midline, whereas adduction is movement toward the midline. These terms are used to describe range-of-motion exercises.$x$, $x$Nursing Foundations$x$, $x$medium$x$),
  (16, $x$A carminative enema is administered primarily to$x$, $x$["Provide nutrition and calories","Relieve flatus and abdominal distension","Instil medication for a systemic effect","Lower a high body temperature"]$x$, 1, $x$A carminative enema stimulates peristalsis and the expulsion of flatus, relieving gaseous abdominal distension. This differs from a cleansing enema, which empties the bowel of faeces.$x$, $x$Nursing Foundations$x$, $x$medium$x$),
  (17, $x$The most important principle when inserting an indwelling urinary catheter is to use$x$, $x$["No particular technique","The largest available catheter size","Strict sterile, or surgical asepsis, technique","Clean, or medical asepsis, technique"]$x$, 2, $x$Urinary catheterisation demands strict surgical asepsis because the bladder is normally sterile and the procedure bypasses the body's natural defences. This prevents catheter-associated urinary tract infection.$x$, $x$Nursing Foundations$x$, $x$medium$x$),
  (18, $x$A basic principle when applying a roller bandage to a limb is to bandage$x$, $x$["From proximal to distal","Covering the fingers and toes completely for warmth","As tightly as possible to keep it from slipping","From distal to proximal with even pressure, leaving the extremities exposed"]$x$, 3, $x$A limb is bandaged from distal to proximal with even, firm pressure to promote venous return and prevent congestion. The fingers or toes are left exposed so circulation can be monitored.$x$, $x$Nursing Foundations$x$, $x$medium$x$),
  (19, $x$Which statement correctly distinguishes antisepsis from disinfection?$x$, $x$["Both are applied only to inanimate objects","Both are applied only to living tissue","Antisepsis destroys all bacterial spores while disinfection does not","An antiseptic is applied to living tissue while a disinfectant is applied to inanimate objects"]$x$, 3, $x$An antiseptic is used on living tissue such as skin and mucous membranes, whereas a disinfectant is used on inanimate objects and surfaces. Neither reliably kills all bacterial spores, which requires sterilisation.$x$, $x$Nursing Foundations$x$, $x$medium$x$),
  (20, $x$High-level disinfection is defined as a process that destroys$x$, $x$["Only vegetative bacteria","Only viruses and fungi","All microorganisms except large numbers of bacterial spores","Absolutely all microorganisms, including all spores"]$x$, 2, $x$High-level disinfection kills all microorganisms except high numbers of bacterial spores and is used for semicritical items such as endoscopes. Complete destruction of all spores requires sterilisation, not disinfection.$x$, $x$Nursing Foundations$x$, $x$hard$x$),
  (21, $x$An essential safety measure during oxygen therapy is to$x$, $x$["Display no-smoking signs and keep the area away from open flames","Apply petroleum-based lubricants around the tubing","Permit smoking near the oxygen source","Use woollen blankets and synthetic fabrics near the patient"]$x$, 0, $x$Oxygen supports combustion, so open flames, sparks and smoking must be prohibited and warning signs displayed. Oil or petroleum-based products near oxygen equipment are also avoided because they are flammable.$x$, $x$Nursing Foundations$x$, $x$easy$x$),
  (22, $x$A fundamental safety principle when applying a physical restraint is to$x$, $x$["Leave the restrained patient unchecked for the full shift","Secure the restraint to a movable side rail","Apply the restraint as tightly as possible","Tie it with a quick-release knot to the bed frame and check circulation frequently"]$x$, 3, $x$Restraints are secured with a quick-release knot to a fixed part of the bed frame, never a movable rail, and must allow two fingers of space. The nurse checks circulation, skin and comfort at frequent intervals and releases the restraint periodically.$x$, $x$Nursing Foundations$x$, $x$medium$x$),
  (23, $x$Which nursing theory centres on the patient's ability to perform self-care and the nurse's role in meeting self-care deficits?$x$, $x$["Henderson's 14 basic needs","Roy's adaptation model","Orem's self-care deficit theory","Maslow's hierarchy of needs"]$x$, 2, $x$Dorothea Orem's self-care deficit theory holds that people normally meet their own self-care needs, and nursing is required when a deficit exists. The nurse provides wholly or partly compensatory care until the patient regains independence.$x$, $x$Nursing Foundations$x$, $x$easy$x$)
) as v(pos, question, options, ci, exp, topic, diff);

-- 21-foundations-drugs-law.txt — 29 questions
with b as (
  insert into tests (title, topic, difficulty, duration_minutes)
  values ($x$w2-foundations-b — ingested draft, verify before trusting$x$, $x$Nursing Foundations$x$, 'medium', 60)
  returning id
)
insert into questions (test_id, position, question, options, correct_index, explanation, topic, difficulty)
select b.id, v.pos::int, v.question, v.options::jsonb, v.ci::int, v.exp, v.topic, v.diff
from b, (values
  (0, $x$The name of a drug that is not owned by any company and is used universally in pharmacopoeias is called the$x$, $x$["Generic name","Trade name","Brand name","Chemical name"]$x$, 0, $x$The generic, or non-proprietary, name is the official name approved by pharmacopoeia and is not owned by any company. Brand or trade names are proprietary names assigned by individual manufacturers for marketing.$x$, $x$Nursing Foundations$x$, $x$easy$x$),
  (1, $x$Under the Drugs and Cosmetics Rules in India, prescription-only medicines that must be sold on the prescription of a registered medical practitioner belong to$x$, $x$["Schedule H","Schedule W","Schedule C","Schedule G"]$x$, 0, $x$Schedule H lists prescription-only medicines that must be dispensed against a registered practitioner's prescription. Schedule X drugs carry stricter controls such as special licences and duplicate prescriptions.$x$, $x$Nursing Foundations$x$, $x$medium$x$),
  (2, $x$The nurse's correct responsibility for narcotic, or controlled, drugs on a ward is$x$, $x$["Keeping them under double lock with a narcotic register counted each shift","Storing them in an open medication trolley for quick access","Recording administration only at the end of each week","Discarding unused doses without a witness"]$x$, 0, $x$Controlled drugs must be stored under double lock and counted every shift, with each dose entered in a narcotic register. Any wastage of a controlled drug must be witnessed and countersigned by a second nurse.$x$, $x$Nursing Foundations$x$, $x$medium$x$),
  (3, $x$A patient on oral tetracycline should avoid taking it with milk or antacids because$x$, $x$["They increase gastric acid and inactivate the drug","They cause the drug to be metabolised too rapidly","They speed up renal excretion of the drug","They form insoluble chelates that reduce drug absorption"]$x$, 3, $x$Tetracyclines bind divalent and trivalent cations such as calcium, magnesium, iron and aluminium found in milk, antacids and iron salts. These form insoluble chelates that greatly reduce absorption of the drug from the gut.$x$, $x$Nursing Foundations$x$, $x$hard$x$),
  (4, $x$An effect of a drug that is noxious, unintended, and occurs at normal therapeutic doses is best defined as$x$, $x$["An adverse drug reaction","A placebo effect","A therapeutic effect","A side effect"]$x$, 0, $x$The WHO defines an adverse drug reaction as a response that is noxious and unintended occurring at doses normally used in humans. A side effect is any unintended secondary effect, which may be harmless or even beneficial.$x$, $x$Nursing Foundations$x$, $x$easy$x$),
  (5, $x$Which intramuscular injection site is now preferred in adults because it is free of major nerves and large blood vessels?$x$, $x$["Vastus lateralis muscle","Dorsogluteal muscle","Ventrogluteal muscle","Deltoid muscle"]$x$, 2, $x$The ventrogluteal site has a thick muscle mass and is free of large nerves and vessels, making it the preferred IM site in adults. The dorsogluteal site is avoided because of the risk of sciatic nerve injury.$x$, $x$Nursing Foundations$x$, $x$hard$x$),
  (6, $x$Which insulin has the most rapid onset of action, about 15 minutes, and is given immediately before meals?$x$, $x$["Insulin lispro","Insulin glargine","Regular, or soluble, insulin","NPH, or isophane, insulin"]$x$, 0, $x$Insulin lispro is a rapid-acting analogue with an onset of about 15 minutes, a peak at 30 to 90 minutes and a short duration. Regular insulin is short-acting, NPH is intermediate-acting, and glargine is long-acting.$x$, $x$Nursing Foundations$x$, $x$medium$x$),
  (7, $x$Which of the following intravenous solutions is hypotonic?$x$, $x$["Ringer's lactate","5 per cent dextrose in 0.9 per cent saline","0.45 per cent sodium chloride","0.9 per cent sodium chloride"]$x$, 2, $x$Half-normal saline, 0.45 per cent sodium chloride, is hypotonic, having lower osmolarity than plasma, so water shifts into the cells. Normal saline and Ringer's lactate are isotonic, while dextrose-saline mixtures are hypertonic.$x$, $x$Nursing Foundations$x$, $x$medium$x$),
  (8, $x$Which intravenous solution is the only one that should be used to prime the line and run with a blood transfusion?$x$, $x$["0.45 per cent sodium chloride","Ringer's lactate","0.9 per cent normal saline","5 per cent dextrose in water"]$x$, 2, $x$Only 0.9 per cent normal saline is compatible with blood products. Dextrose solutions cause red cells to clump and haemolyse, and the calcium in Ringer's lactate can trigger clotting within the tubing.$x$, $x$Nursing Foundations$x$, $x$easy$x$),
  (9, $x$A patient is to receive 1000 mL of IV fluid over 8 hours using a set with a drop factor of 15 drops per mL. The correct flow rate is approximately$x$, $x$["21 drops per minute","31 drops per minute","42 drops per minute","63 drops per minute"]$x$, 1, $x$Flow rate in drops per minute equals volume multiplied by the drop factor divided by the time in minutes. Thus 1000 times 15 divided by 8 times 60 gives 15000 over 480, which is approximately 31 drops per minute.$x$, $x$Nursing Foundations$x$, $x$hard$x$),
  (10, $x$The recommended first aid for a conscious adult with complete airway obstruction, or choking, is$x$, $x$["Abdominal thrusts, the Heimlich manoeuvre","A blind finger sweep of the mouth","Immediate chest compressions","Repeated back blows only"]$x$, 0, $x$For a conscious adult with complete airway obstruction, abdominal thrusts, the Heimlich manoeuvre, create an artificial cough to expel the object. Blind finger sweeps are avoided as they may push the object deeper.$x$, $x$Nursing Foundations$x$, $x$easy$x$),
  (11, $x$The correct immediate first aid for a thermal burn is to$x$, $x$["Break the blisters to release fluid","Cool the area with running water for about 20 minutes","Apply ice directly to the burn","Apply butter or toothpaste to the burn"]$x$, 1, $x$A thermal burn should be cooled with cool running water for about 20 minutes to limit tissue damage and relieve pain. Ice, butter and toothpaste are avoided, and blisters should not be broken as this risks infection.$x$, $x$Nursing Foundations$x$, $x$easy$x$),
  (12, $x$When splinting a suspected long-bone fracture, the splint should immobilise$x$, $x$["The joint above the fracture only","The joint below the fracture only","Only the fracture site","The joints above and below the fracture"]$x$, 3, $x$A splint must immobilise the joints both above and below the fracture to prevent movement of the broken bone ends. This reduces pain, controls bleeding, and prevents further soft-tissue and neurovascular damage.$x$, $x$Nursing Foundations$x$, $x$medium$x$),
  (13, $x$The first priority in managing a near-drowning victim who is not breathing is to$x$, $x$["Perform abdominal thrusts to drain water from the lungs","Warm the patient with blankets before anything else","Open the airway and give rescue breaths","Induce vomiting to clear swallowed water"]$x$, 2, $x$In near-drowning the first priority is to open the airway and provide rescue breaths, because hypoxia is the main threat to life. Attempting to drain water from the lungs delays ventilation and is not recommended.$x$, $x$Nursing Foundations$x$, $x$hard$x$),
  (14, $x$The appropriate first aid for a person who has fainted, or had syncope, is to$x$, $x$["Make the person walk around immediately","Sit the person upright and give water","Give a stimulant drink such as coffee","Lay the person flat and elevate the legs"]$x$, 3, $x$A person who has fainted should be laid flat with the legs elevated to promote venous return and cerebral blood flow. Keeping them upright can prolong the faint, and nothing should be given by mouth while consciousness is impaired.$x$, $x$Nursing Foundations$x$, $x$easy$x$),
  (15, $x$The correct first aid position for a patient with epistaxis, or nosebleed, is to$x$, $x$["Blow the nose forcefully to clear clots","Tilt the head backward and pinch the bony bridge","Sit up, lean forward and pinch the soft part of the nose","Lie flat and swallow the blood"]$x$, 2, $x$For epistaxis the patient should sit up and lean slightly forward while pinching the soft part of the nose for about ten minutes. Leaning forward prevents blood from being swallowed, which can cause nausea and vomiting.$x$, $x$Nursing Foundations$x$, $x$medium$x$),
  (16, $x$The ethical principle that upholds a competent patient's right to make their own decisions about care is$x$, $x$["Autonomy","Justice","Non-maleficence","Beneficence"]$x$, 0, $x$Autonomy respects a competent patient's right to make informed decisions about their own treatment, including the right to refuse care. It forms the ethical basis of informed consent in nursing practice.$x$, $x$Nursing Foundations$x$, $x$easy$x$),
  (17, $x$A nurse who raises the side rails to prevent a confused patient from falling is primarily applying the principle of$x$, $x$["Veracity","Non-maleficence","Autonomy","Fidelity"]$x$, 1, $x$Non-maleficence means to do no harm. Raising side rails to protect a confused patient from injury is an application of this principle by actively preventing foreseeable harm to a vulnerable patient.$x$, $x$Nursing Foundations$x$, $x$medium$x$),
  (18, $x$Which of the following must be proven to establish nursing negligence?$x$, $x$["Only that the patient was dissatisfied with care","Duty, breach of duty, causation and damages","That the nurse intended to cause harm","That the nurse was inadequately paid"]$x$, 1, $x$To establish negligence four elements must be proven: a duty of care owed to the patient, a breach of that duty, causation linking the breach to harm, and actual damages suffered. Intent to harm is not required for negligence.$x$, $x$Nursing Foundations$x$, $x$hard$x$),
  (19, $x$A nurse discussing a named patient's diagnosis with a friend outside work has violated the principle of$x$, $x$["Confidentiality","Justice","Beneficence","Autonomy"]$x$, 0, $x$Confidentiality requires that patient information be shared only with those involved in the patient's care and with consent. Disclosing a named patient's diagnosis to an outsider breaches confidentiality and professional ethics.$x$, $x$Nursing Foundations$x$, $x$medium$x$),
  (20, $x$The statutory body that regulates nursing education and maintains uniform standards of nursing in India is the$x$, $x$["Indian Nursing Council","International Council of Nurses","Trained Nurses Association of India","State Medical Council"]$x$, 0, $x$The Indian Nursing Council, established under the Indian Nursing Council Act of 1947, is the statutory body that regulates nursing education and maintains uniform standards. The Trained Nurses Association is a professional body and the International Council of Nurses is the global body.$x$, $x$Nursing Foundations$x$, $x$easy$x$),
  (21, $x$In the acronym POSDCORB describing management functions, the letter D stands for$x$, $x$["Delegating","Directing","Deciding","Developing"]$x$, 1, $x$POSDCORB, coined by Luther Gulick, stands for Planning, Organising, Staffing, Directing, Coordinating, Reporting and Budgeting. The letter D therefore represents the directing function of management.$x$, $x$Nursing Foundations$x$, $x$medium$x$),
  (22, $x$When a registered nurse delegates a task to a nursing assistant, the nurse retains$x$, $x$["Accountability for ensuring the delegated task is done safely","No further responsibility once the task is delegated","The right to delegate assessment of an unstable patient","Responsibility only if the task is unpaid"]$x$, 0, $x$Although a task may be delegated, the registered nurse remains accountable for ensuring it is appropriate and safely performed. Tasks requiring nursing judgment, such as assessing an unstable patient, cannot be delegated.$x$, $x$Nursing Foundations$x$, $x$medium$x$),
  (23, $x$Which leadership style is characterised by minimal manager involvement, giving staff complete freedom to make decisions?$x$, $x$["Democratic","Laissez-faire","Autocratic","Bureaucratic"]$x$, 1, $x$The laissez-faire, or permissive, style involves minimal manager involvement and leaves staff free to make their own decisions. Autocratic leaders decide alone, while democratic leaders involve the group in decision-making.$x$, $x$Nursing Foundations$x$, $x$medium$x$),
  (24, $x$A study that explores patients' lived experiences of chronic pain through in-depth interviews and produces narrative data is an example of$x$, $x$["Quantitative research","Quasi-experimental research","Experimental research","Qualitative research"]$x$, 3, $x$Qualitative research explores meanings, experiences and perceptions using narrative data from methods such as interviews and observation. Quantitative research instead measures variables numerically and analyses them statistically.$x$, $x$Nursing Foundations$x$, $x$medium$x$),
  (25, $x$Blood group, being A, B, AB or O, is an example of which level of measurement?$x$, $x$["Nominal","Interval","Ratio","Ordinal"]$x$, 0, $x$Blood group is a nominal, or categorical, variable because its values are only names or labels with no inherent order or numeric value. Ordinal data have rank order, while interval and ratio data are numeric.$x$, $x$Nursing Foundations$x$, $x$medium$x$),
  (26, $x$The standard deviation of a data set is a measure of$x$, $x$["The central value of the data","The most frequently occurring value","The middle value of the data set","The dispersion of values around the mean"]$x$, 3, $x$The standard deviation measures the dispersion or spread of individual values around the mean; a larger value indicates greater variability. The mean, mode and median are measures of central tendency, not spread.$x$, $x$Nursing Foundations$x$, $x$hard$x$),
  (27, $x$In hypothesis testing, a p-value of 0.01 with alpha set at 0.05 indicates that the result is$x$, $x$["Impossible to interpret","Statistically significant","Not statistically significant","Entirely due to sampling error"]$x$, 1, $x$A p-value of 0.01 is smaller than the alpha level of 0.05, so the null hypothesis is rejected and the result is statistically significant. It indicates the finding is unlikely to have occurred by chance alone.$x$, $x$Nursing Foundations$x$, $x$hard$x$),
  (28, $x$A researcher selects every 10th patient from an admission list to form a sample. This sampling technique is$x$, $x$["Systematic sampling","Cluster sampling","Simple random sampling","Stratified sampling"]$x$, 0, $x$Systematic sampling selects every kth element, here every 10th, from an ordered list after a random start. It differs from stratified sampling, which uses subgroups, and cluster sampling, which uses natural groups.$x$, $x$Nursing Foundations$x$, $x$medium$x$)
) as v(pos, question, options, ci, exp, topic, diff);

-- 22-mental-disorders.txt — 30 questions
with b as (
  insert into tests (title, topic, difficulty, duration_minutes)
  values ($x$w2-mental — ingested draft, verify before trusting$x$, $x$Mental Health Nursing$x$, 'medium', 60)
  returning id
)
insert into questions (test_id, position, question, options, correct_index, explanation, topic, difficulty)
select b.id, v.pos::int, v.question, v.options::jsonb, v.ci::int, v.exp, v.topic, v.diff
from b, (values
  (0, $x$Who first described the first-rank symptoms of schizophrenia?$x$, $x$["Eugen Bleuler","Sigmund Freud","Kurt Schneider","Emil Kraepelin"]$x$, 2, $x$Kurt Schneider described the first-rank symptoms of schizophrenia, including thought broadcasting, insertion and withdrawal, third-person auditory hallucinations, delusional perception and passivity phenomena. Bleuler coined the term schizophrenia and Kraepelin used dementia praecox.$x$, $x$Mental Health Nursing$x$, $x$easy$x$),
  (1, $x$In catatonia, the state in which a patient's limbs can be moulded into a posture that is then held for long periods with a plastic, wax-like resistance is called$x$, $x$["Stereotypy","Negativism","Waxy flexibility or cerea flexibilitas","Echopraxia"]$x$, 2, $x$Waxy flexibility, or cerea flexibilitas, is a catatonic feature in which imposed postures are maintained for prolonged periods against a plastic, wax-like resistance. Echopraxia is meaningless imitation of movements, whereas negativism is a motiveless resistance to instructions.$x$, $x$Mental Health Nursing$x$, $x$medium$x$),
  (2, $x$The experience in which a patient believes his thoughts are escaping his mind and becoming known to others is termed$x$, $x$["Thought withdrawal","Thought broadcasting","Thought block","Thought insertion"]$x$, 1, $x$In thought broadcasting the patient believes that their private thoughts leave the mind and are transmitted to or experienced by other people. Thought insertion is the belief that thoughts are placed by an external agency, while withdrawal is the belief that thoughts are being taken away.$x$, $x$Mental Health Nursing$x$, $x$medium$x$),
  (3, $x$Flight of ideas is most characteristically seen in$x$, $x$["Major depression","Generalised anxiety disorder","Acute mania","Dementia"]$x$, 2, $x$Flight of ideas is a rapid, accelerated stream of thought and speech in which ideas are connected by logical, rhyming or clang associations, and it is most characteristic of acute mania. It reflects the pressured speech and heightened psychomotor activity of the manic state.$x$, $x$Mental Health Nursing$x$, $x$easy$x$),
  (4, $x$A severely depressed patient insists that his intestines have rotted away and that he is already dead. This nihilistic delusion, when systematised, is characteristic of$x$, $x$["Othello syndrome","Capgras syndrome","Cotard syndrome","De Clerambault syndrome"]$x$, 2, $x$Nihilistic delusions involve beliefs of non-existence or that oneself, one's organs or the world have ceased to exist or are decaying. When severe and systematised in depression this is termed Cotard syndrome. Othello syndrome is delusional jealousy and De Clerambault syndrome is erotomania.$x$, $x$Mental Health Nursing$x$, $x$hard$x$),
  (5, $x$A patient who firmly believes he is a billionaire endowed with special divine powers to rule the world is exhibiting a$x$, $x$["Delusion of control","Delusion of reference","Persecutory delusion","Grandiose delusion"]$x$, 3, $x$Grandiose delusions are false beliefs of inflated worth, power, wealth, identity or special abilities, and are commonly seen in mania and schizophrenia. A persecutory delusion, by contrast, is the belief that one is being harmed, spied upon or conspired against.$x$, $x$Mental Health Nursing$x$, $x$easy$x$),
  (6, $x$The essential feature required to diagnose bipolar affective disorder is$x$, $x$["At least one episode of mania or hypomania","Persistent low mood only","Continuous free-floating anxiety","Chronic auditory hallucinations"]$x$, 0, $x$Bipolar affective disorder is characterised by two or more episodes of significantly disturbed mood and activity, with at least one being manic or hypomanic, usually alternating with depressive episodes. The presence of a manic or hypomanic episode distinguishes it from unipolar recurrent depression.$x$, $x$Mental Health Nursing$x$, $x$medium$x$),
  (7, $x$Which of the following is a biological or somatic symptom of major depression?$x$, $x$["Early morning awakening with diurnal variation of mood","Flight of ideas","Grandiosity","Pressured speech"]$x$, 0, $x$Biological or somatic symptoms of depression include early morning awakening, diurnal variation of mood that is worse in the morning, anorexia, weight loss, loss of libido and psychomotor retardation. Grandiosity, pressured speech and flight of ideas are features of mania.$x$, $x$Mental Health Nursing$x$, $x$hard$x$),
  (8, $x$The hallmark of generalised anxiety disorder is$x$, $x$["Intrusive obsessions and compulsions","Fear of a single specific object","Persistent free-floating worry about everyday events","Recurrent unexpected panic attacks"]$x$, 2, $x$Generalised anxiety disorder is characterised by persistent, excessive, free-floating worry about multiple everyday events that is not restricted to any particular situation and lasts most days for at least six months. It is accompanied by restlessness, muscle tension and autonomic arousal.$x$, $x$Mental Health Nursing$x$, $x$easy$x$),
  (9, $x$Which feature best describes a panic attack?$x$, $x$["Persistent sadness lasting two weeks","Fear confined only to social situations","Sudden intense fear with palpitations, choking and fear of dying, peaking within minutes","Gradual worry building over several weeks"]$x$, 2, $x$A panic attack is a discrete episode of sudden, intense fear or discomfort that peaks within minutes, with somatic symptoms such as palpitations, sweating, trembling, chest pain, choking, dizziness and fear of dying or losing control. Recurrent unexpected attacks with anticipatory anxiety define panic disorder.$x$, $x$Mental Health Nursing$x$, $x$medium$x$),
  (10, $x$Agoraphobia is best defined as$x$, $x$["Fear of social embarrassment","Fear of closed spaces only","Fear of open spaces, crowds or situations from which escape may be difficult","Fear of heights"]$x$, 2, $x$Agoraphobia is anxiety about being in places or situations such as crowds, open spaces, public transport or being outside the home alone, from which escape might be difficult or help unavailable if panic occurs. Sufferers often avoid these situations and may become housebound.$x$, $x$Mental Health Nursing$x$, $x$medium$x$),
  (11, $x$A characteristic feature of post-traumatic stress disorder is$x$, $x$["Re-experiencing the trauma through flashbacks and nightmares","Grandiose delusions","Waxy flexibility","Manic excitement"]$x$, 0, $x$PTSD follows exposure to a severely threatening or catastrophic event and is characterised by intrusive re-experiencing such as flashbacks and nightmares, avoidance of reminders, emotional numbing and hyperarousal with hypervigilance and exaggerated startle. Symptoms usually arise within six months of the trauma.$x$, $x$Mental Health Nursing$x$, $x$medium$x$),
  (12, $x$A young woman develops sudden paralysis of both legs after an emotional conflict, no neurological cause is found, and she appears strikingly unconcerned about her disability. This relative lack of concern is called$x$, $x$["Depersonalisation","Alexithymia","La belle indifference","Anhedonia"]$x$, 2, $x$Conversion or dissociative motor disorder presents with neurological-like symptoms such as paralysis, aphonia or blindness that lack an organic basis and are linked to psychological stress. The characteristic bland, inappropriate lack of concern about the deficit is termed la belle indifference.$x$, $x$Mental Health Nursing$x$, $x$hard$x$),
  (13, $x$A man suddenly travels away from home, cannot recall his identity, assumes a new one, and later has amnesia for the episode. This is$x$, $x$["Trance and possession disorder","Dissociative fugue","Depersonalisation disorder","Dissociative stupor"]$x$, 1, $x$Dissociative fugue involves an unexpected, seemingly purposeful journey away from home combined with loss of memory for one's past and sometimes assumption of a new identity, with amnesia for the fugue period after recovery. It is usually precipitated by severe psychosocial stress.$x$, $x$Mental Health Nursing$x$, $x$medium$x$),
  (14, $x$Schizoid, schizotypal and paranoid personality disorders belong to which cluster?$x$, $x$["Cluster A, odd or eccentric","Cluster D","Cluster C, anxious or fearful","Cluster B, dramatic or erratic"]$x$, 0, $x$Cluster A comprises paranoid, schizoid and schizotypal personality disorders, described as odd or eccentric. Cluster B, including antisocial, borderline, histrionic and narcissistic, is dramatic or erratic, and Cluster C, including avoidant, dependent and obsessive-compulsive, is anxious or fearful.$x$, $x$Mental Health Nursing$x$, $x$medium$x$),
  (15, $x$Which cluster of features is most characteristic of borderline personality disorder?$x$, $x$["Grandiosity and lack of empathy","Suspiciousness and social withdrawal","Perfectionism and rigidity","Unstable relationships, impulsivity, fear of abandonment and self-harm"]$x$, 3, $x$Borderline personality disorder is marked by pervasive instability of relationships, self-image and affect, with impulsivity, frantic efforts to avoid abandonment, recurrent self-harm or suicidal behaviour, chronic emptiness and the defence of splitting. It falls within Cluster B.$x$, $x$Mental Health Nursing$x$, $x$hard$x$),
  (16, $x$Which of the following is a core feature of the alcohol dependence syndrome?$x$, $x$["Drinking only in response to hallucinations","A strong compulsion or craving to drink with impaired control over use","Complete inability to tolerate any alcohol","Occasional social drinking without craving"]$x$, 1, $x$The dependence syndrome described by Edwards and Gross includes a strong compulsion or craving to drink, impaired control over use, a stereotyped drinking pattern, tolerance, withdrawal relieved by further drinking, primacy of drinking over other activities and continued use despite harm.$x$, $x$Mental Health Nursing$x$, $x$easy$x$),
  (17, $x$Which set of signs is typical of opioid withdrawal?$x$, $x$["Lacrimation, rhinorrhoea, yawning, dilated pupils and piloerection","Grand-mal seizures with delirium tremens","Pinpoint pupils and respiratory depression","Waxy flexibility and mutism"]$x$, 0, $x$Opioid withdrawal produces a flu-like, autonomic-overactivity picture with lacrimation, rhinorrhoea, yawning, sweating, dilated pupils, piloerection, muscle aches, cramps and diarrhoea. Pinpoint pupils with respiratory depression instead indicate opioid intoxication or overdose.$x$, $x$Mental Health Nursing$x$, $x$medium$x$),
  (18, $x$The need for progressively larger doses of a drug to achieve the effect originally produced by a smaller dose is called$x$, $x$["Tolerance","Withdrawal","Craving","Dependence"]$x$, 0, $x$Tolerance is a state in which increasing doses are required to obtain the effect once achieved by a lower dose. Withdrawal is the physical and psychological reaction on stopping the drug, whereas dependence is the compulsive, maladaptive pattern of use that encompasses both.$x$, $x$Mental Health Nursing$x$, $x$hard$x$),
  (19, $x$A core feature of autism spectrum disorder is$x$, $x$["Onset after 10 years of age","Grandiose delusions","Normal reciprocal social interaction","Impaired social communication with restricted, repetitive behaviours"]$x$, 3, $x$Autism spectrum disorder is a neurodevelopmental condition with onset in early childhood, characterised by persistent deficits in social communication and interaction together with restricted, repetitive patterns of behaviour, interests or activities. It is often associated with intellectual disability and delayed language.$x$, $x$Mental Health Nursing$x$, $x$medium$x$),
  (20, $x$The three core symptom domains of attention-deficit hyperactivity disorder are$x$, $x$["Inattention, hyperactivity and impulsivity","Low mood, anhedonia and fatigue","Obsessions, compulsions and rituals","Delusions, hallucinations and disorganisation"]$x$, 0, $x$ADHD is defined by a persistent, developmentally inappropriate pattern of inattention, hyperactivity and impulsivity that begins before age 12 and impairs functioning across more than one setting. Stimulants such as methylphenidate are first-line pharmacotherapy.$x$, $x$Mental Health Nursing$x$, $x$easy$x$),
  (21, $x$Non-organic or functional enuresis is generally diagnosed only when involuntary bed-wetting persists beyond the age of$x$, $x$["2 years","3 years","5 years","10 years"]$x$, 2, $x$Non-organic enuresis is involuntary voiding of urine, by day or night, that is abnormal for the child's mental age and is diagnosed only after 5 years once organic causes are excluded. Management includes the enuresis alarm and, when needed, imipramine or desmopressin.$x$, $x$Mental Health Nursing$x$, $x$medium$x$),
  (22, $x$The characteristic neuropathological findings in Alzheimer disease are$x$, $x$["Multiple cortical infarcts","Beta-amyloid senile plaques and neurofibrillary tangles","Lewy bodies in the substantia nigra","Pick bodies in the frontal lobe"]$x$, 1, $x$Alzheimer disease shows extracellular beta-amyloid senile plaques and intracellular neurofibrillary tangles of hyperphosphorylated tau, along with cortical atrophy and a cholinergic deficit. This underlies the use of cholinesterase inhibitors such as donepezil for symptomatic treatment.$x$, $x$Mental Health Nursing$x$, $x$hard$x$),
  (23, $x$Fluoxetine is the prototype of which class of antidepressants?$x$, $x$["Monoamine oxidase inhibitors","Mood stabilisers","Tricyclic antidepressants","Selective serotonin reuptake inhibitors"]$x$, 3, $x$Fluoxetine is the prototype selective serotonin reuptake inhibitor, a class that acts by blocking presynaptic reuptake of serotonin. SSRIs are first-line for depression and anxiety disorders because they are safer in overdose and better tolerated than tricyclics or MAOIs.$x$, $x$Mental Health Nursing$x$, $x$easy$x$),
  (24, $x$Which of the following is an atypical or second-generation antipsychotic?$x$, $x$["Risperidone","Trifluoperazine","Haloperidol","Chlorpromazine"]$x$, 0, $x$Atypical or second-generation antipsychotics such as risperidone, olanzapine, clozapine and quetiapine act on both dopamine and serotonin receptors and cause fewer extrapyramidal effects. Haloperidol, chlorpromazine and trifluoperazine are typical first-generation agents with a higher extrapyramidal risk.$x$, $x$Mental Health Nursing$x$, $x$medium$x$),
  (25, $x$A patient on haloperidol develops high fever, severe lead-pipe muscle rigidity, altered consciousness and markedly raised creatine phosphokinase. The most likely diagnosis is$x$, $x$["Neuroleptic malignant syndrome","Tardive dyskinesia","Lithium toxicity","Serotonin syndrome"]$x$, 0, $x$Neuroleptic malignant syndrome is a rare, life-threatening reaction to antipsychotic dopamine blockade, marked by hyperthermia, severe lead-pipe rigidity, autonomic instability, altered mental status and greatly elevated creatine phosphokinase. Management includes stopping the drug, cooling, supportive care and dantrolene or bromocriptine.$x$, $x$Mental Health Nursing$x$, $x$hard$x$),
  (26, $x$A patient taking an SSRI is also given tramadol and develops agitation, fever, sweating, tremor, hyperreflexia and myoclonus. This picture suggests$x$, $x$["Serotonin syndrome","Opioid withdrawal","Neuroleptic malignant syndrome","Anticholinergic toxicity"]$x$, 0, $x$Serotonin syndrome results from excess serotonergic activity, often when serotonergic drugs are combined such as an SSRI with tramadol, an MAOI or a triptan, and features neuromuscular excitation, autonomic instability and altered mental status. Unlike NMS it develops rapidly and causes hyperreflexia and clonus rather than lead-pipe rigidity.$x$, $x$Mental Health Nursing$x$, $x$hard$x$),
  (27, $x$Systematic desensitisation, used mainly for phobias, is based on the principle of$x$, $x$["Aversive conditioning","Graded exposure paired with relaxation, or reciprocal inhibition","Free association","Flooding with the feared object"]$x$, 1, $x$Systematic desensitisation, developed by Joseph Wolpe, treats phobic anxiety by pairing a graded hierarchy of feared stimuli with deep muscle relaxation so that relaxation reciprocally inhibits the anxiety response. The patient advances up the hierarchy only after mastering each less-feared step.$x$, $x$Mental Health Nursing$x$, $x$medium$x$),
  (28, $x$When a therapist unconsciously redirects their own feelings and past relationship patterns onto the patient, this is called$x$, $x$["Transference","Projection","Countertransference","Sublimation"]$x$, 2, $x$Countertransference refers to the therapist's unconscious emotional reactions and displaced feelings directed toward the patient, whereas transference is the patient's unconscious transfer of feelings from significant past figures onto the therapist. Recognising countertransference helps the nurse maintain a therapeutic and objective relationship.$x$, $x$Mental Health Nursing$x$, $x$medium$x$),
  (29, $x$According to Kubler-Ross, the first stage of the grief and dying process is$x$, $x$["Bargaining","Anger","Acceptance","Denial"]$x$, 3, $x$Elisabeth Kubler-Ross described five stages of grief: denial, anger, bargaining, depression and acceptance. Denial is typically the first reaction and acts as a protective buffer against the shock of loss, though the stages need not occur in a fixed sequence.$x$, $x$Mental Health Nursing$x$, $x$easy$x$)
) as v(pos, question, options, ci, exp, topic, diff);

-- 23-community-policy.txt — 28 questions
with b as (
  insert into tests (title, topic, difficulty, duration_minutes)
  values ($x$w2-community-c — ingested draft, verify before trusting$x$, $x$Community Health Nursing$x$, 'medium', 60)
  returning id
)
insert into questions (test_id, position, question, options, correct_index, explanation, topic, difficulty)
select b.id, v.pos::int, v.question, v.options::jsonb, v.ci::int, v.exp, v.topic, v.diff
from b, (values
  (0, $x$The Health Survey and Development Committee of 1946, which laid the foundation of India's rural health infrastructure, is popularly known as the$x$, $x$["Mudaliar Committee","Bhore Committee","Kartar Singh Committee","Srivastava Committee"]$x$, 1, $x$The Bhore Committee of 1946, or Health Survey and Development Committee, recommended integration of preventive and curative services and the establishment of primary health centres as the basic unit of rural health care.$x$, $x$Community Health Nursing$x$, $x$easy$x$),
  (1, $x$Which committee is also known as the Health Survey and Planning Committee of 1961 to 1962, constituted to review progress made since the Bhore Committee?$x$, $x$["Chadah Committee","Bhore Committee","Mudaliar Committee","Kartar Singh Committee"]$x$, 2, $x$The Mudaliar Committee of 1962 assessed the work done since the Bhore Committee. It recommended strengthening existing primary health centres and district hospitals rather than opening new ones, and improving the quality of services.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (2, $x$The committee that recommended integrating peripheral health workers into a single multipurpose worker cadre in 1973 was the$x$, $x$["Srivastava Committee","Mukherjee Committee","Chadah Committee","Kartar Singh Committee"]$x$, 3, $x$The Kartar Singh Committee of 1973, the Committee on Multipurpose Workers, recommended converting unipurpose peripheral workers such as ANMs and malaria and smallpox workers into integrated multipurpose health workers to improve efficiency.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (3, $x$The concept of the community health worker and Village Health Guide scheme in India originated from the recommendations of the$x$, $x$["Bhore Committee of 1946","Bajaj Committee of 1986","Mudaliar Committee of 1962","Srivastava Committee of 1975"]$x$, 3, $x$The Srivastava Committee of 1975, the Group on Medical Education and Support Manpower, recommended creating bands of para-professional and semi-professional workers from within the community, leading directly to the Village Health Guide scheme.$x$, $x$Community Health Nursing$x$, $x$hard$x$),
  (4, $x$The Chadah Committee of 1963 was constituted to advise on the maintenance phase of which national programme?$x$, $x$["National Leprosy Control Programme","National Malaria Eradication Programme","National Family Planning Programme","National Tuberculosis Programme"]$x$, 1, $x$The Chadah Committee of 1963 recommended that vigilance operations for the maintenance phase of the National Malaria Eradication Programme be carried out by basic health workers, one per 10,000 population, who would also undertake family planning and vital statistics work.$x$, $x$Community Health Nursing$x$, $x$hard$x$),
  (5, $x$India's first National Health Policy was formulated in the year$x$, $x$["2017","1983","1978","2002"]$x$, 1, $x$The first National Health Policy of India was adopted in 1983 with the goal of Health for All by 2000 AD. It was subsequently revised in 2002 and again in 2017 to reflect changing health priorities.$x$, $x$Community Health Nursing$x$, $x$easy$x$),
  (6, $x$The National Rural Health Mission was launched in India in the year$x$, $x$["2000","2005","2013","2018"]$x$, 1, $x$The National Rural Health Mission was launched in 2005 to provide accessible, affordable and quality health care to the rural population. In 2013 it was subsumed, with the National Urban Health Mission, under the umbrella National Health Mission.$x$, $x$Community Health Nursing$x$, $x$easy$x$),
  (7, $x$Ayushman Bharat of 2018 has two inter-related components: Health and Wellness Centres and$x$, $x$["National Urban Health Mission","Rashtriya Swasthya Bima Yojana","Pradhan Mantri Jan Arogya Yojana","Janani Suraksha Yojana"]$x$, 2, $x$Ayushman Bharat rests on two pillars: Health and Wellness Centres delivering comprehensive primary health care, and Pradhan Mantri Jan Arogya Yojana providing financial protection for secondary and tertiary hospitalisation.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (8, $x$Under Pradhan Mantri Jan Arogya Yojana, the health cover provided per eligible family per year is$x$, $x$["Rs 1 lakh","Rs 30,000","Rs 10 lakh","Rs 5 lakh"]$x$, 3, $x$PM-JAY provides a health cover of Rs 5 lakh per family per year for secondary and tertiary care hospitalisation to poor and vulnerable families. It is the world's largest government-funded health assurance scheme.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (9, $x$In the three-tier system of health care, a district hospital providing specialist services represents which level of care?$x$, $x$["Primary care","Secondary care","Quaternary care","Tertiary care"]$x$, 1, $x$Secondary care is provided by district hospitals and community health centres offering specialist services, to which primary-level institutions refer patients. Tertiary care denotes super-specialty care at medical colleges and regional or central institutes.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (10, $x$The World Health Organization was established on 7 April 1948 with its headquarters at$x$, $x$["Vienna","Geneva","Washington DC","New York"]$x$, 1, $x$WHO, established on 7 April 1948, has its headquarters in Geneva, Switzerland. The 7th of April is observed globally as World Health Day, and WHO's South-East Asia Regional Office is located in New Delhi.$x$, $x$Community Health Nursing$x$, $x$easy$x$),
  (11, $x$Which international agency is primarily concerned with promoting the health, nutrition and welfare of children?$x$, $x$["UNICEF","UNFPA","World Bank","ILO"]$x$, 0, $x$UNICEF, the United Nations Children's Fund, headquartered in New York, focuses on child survival, immunisation, nutrition and welfare. Its child survival strategy is popularly remembered by the acronym GOBI-FFF.$x$, $x$Community Health Nursing$x$, $x$easy$x$),
  (12, $x$The International Red Cross movement was founded by$x$, $x$["Florence Nightingale","Jean Henri Dunant","Edward Jenner","John Snow"]$x$, 1, $x$The Red Cross movement was founded by Jean Henri Dunant of Switzerland, inspired by the suffering he witnessed at the Battle of Solferino in 1859. He was a joint recipient of the first Nobel Peace Prize in 1901.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (13, $x$The Sustainable Development Goal that specifically addresses Good Health and Well-being is$x$, $x$["SDG 2","SDG 1","SDG 6","SDG 3"]$x$, 3, $x$SDG 3 seeks to ensure healthy lives and promote well-being for all at all ages. The 17 Sustainable Development Goals were adopted in 2015 with a target year of 2030, succeeding the Millennium Development Goals.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (14, $x$The Millennium Development Goals, adopted in the year 2000, comprised how many goals to be achieved by 2015?$x$, $x$["3","4","8","17"]$x$, 2, $x$The MDGs comprised 8 goals for the period 2000 to 2015. Three were directly health-related: reducing child mortality, improving maternal health, and combating HIV/AIDS, malaria and other diseases.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (15, $x$According to Park, an eligible couple refers to a currently married couple in which the wife is in the reproductive age group of$x$, $x$["20 to 40 years","13 to 50 years","18 to 49 years","15 to 45 years"]$x$, 3, $x$An eligible couple is a currently married couple in which the wife is of reproductive age, generally taken as 15 to 45 years. There are normally about 150 to 180 eligible couples per 1000 population, and they form the focus of family planning services.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (16, $x$The couple protection rate is defined as the percentage of eligible couples effectively protected against childbirth by$x$, $x$["spacing methods only","natural methods only","one or more approved contraceptive methods","sterilisation only"]$x$, 2, $x$Couple protection rate is the per cent of eligible couples effectively protected against childbirth by one or more approved methods of contraception. A rate above 60 per cent is regarded as necessary to reach near-replacement levels of fertility.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (17, $x$DMPA, or depot medroxyprogesterone acetate, a progestogen-only injectable contraceptive, is administered once every$x$, $x$["6 months","3 months","1 month","12 months"]$x$, 1, $x$DMPA is an injectable progestogen-only contraceptive given intramuscularly as 150 mg once every 3 months. NET-EN, or norethisterone enantate, another injectable, is given once every 2 months.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (18, $x$In the basal body temperature method of natural family planning, ovulation is indicated by$x$, $x$["a rise in temperature during menstruation","a rise in temperature of about 0.5 degree after ovulation","a fall in temperature of about 1 degree before ovulation","no change in body temperature throughout the cycle"]$x$, 1, $x$After ovulation, progesterone raises the basal body temperature by about 0.3 to 0.5 degree, and it remains elevated until the next menstruation. The infertile phase is taken to begin after three consecutive days of raised temperature.$x$, $x$Community Health Nursing$x$, $x$hard$x$),
  (19, $x$In India, the sex ratio is conventionally expressed as the number of$x$, $x$["males per 1000 females","females per 100 males","females per 1000 males","children per 1000 women"]$x$, 2, $x$In India, the sex ratio is defined as the number of females per 1000 males. According to the 2011 Census, the sex ratio of India was 943 females per 1000 males, an improvement over previous decades.$x$, $x$Community Health Nursing$x$, $x$easy$x$),
  (20, $x$A population pyramid with a broad base and a rapidly tapering top is characteristic of a population that is$x$, $x$["declining with a low birth rate","expanding with a high birth rate","ageing with a shrinking young population","stationary with equal births and deaths"]$x$, 1, $x$A broad-based, triangular pyramid indicates an expanding population with high birth and death rates, typical of developing countries. A bell-shaped pyramid suggests a stationary population, while a narrowing base indicates a declining one.$x$, $x$Community Health Nursing$x$, $x$hard$x$),
  (21, $x$In a slow sand filter, the layer chiefly responsible for the purification of water is the$x$, $x$["under-drainage system","supernatant raw water","layer of gravel at the base","vital layer, or schmutzdecke"]$x$, 3, $x$The slow sand filter purifies water mainly through the vital layer, or schmutzdecke, a slimy biological film of algae, plankton, bacteria and diatoms forming on the sand surface, which removes organic matter and micro-organisms.$x$, $x$Community Health Nursing$x$, $x$hard$x$),
  (22, $x$In water disinfection, the break-point of chlorination represents the stage at which$x$, $x$["the chlorine demand is fully met and free residual chlorine appears","all suspended matter settles","chlorine is completely removed from water","the water becomes turbid"]$x$, 0, $x$The break-point is the stage at which the chlorine demand of water, exerted by organic matter and ammonia, has been fully satisfied. Chlorine added beyond this point appears as free residual chlorine, which is available for effective disinfection.$x$, $x$Community Health Nursing$x$, $x$hard$x$),
  (23, $x$In the Holder, or vat, method of milk pasteurisation, milk is heated to$x$, $x$["125 degrees for a few seconds","63 to 66 degrees for 30 minutes","72 degrees for 15 seconds","100 degrees for 1 minute"]$x$, 1, $x$In the Holder method, milk is heated to 63 to 66 degrees and held for 30 minutes, then rapidly cooled. The flash or HTST method uses 72 degrees for 15 seconds, while UHT uses around 125 degrees for a few seconds. Success is checked by the phosphatase test.$x$, $x$Community Health Nursing$x$, $x$hard$x$),
  (24, $x$Chikungunya fever, characterised by severe and often persistent joint pains, is transmitted by$x$, $x$["the tsetse fly","the female Anopheles mosquito","the sandfly","the Aedes aegypti mosquito"]$x$, 3, $x$Chikungunya is a viral disease caused by an alphavirus and transmitted by Aedes aegypti and Aedes albopictus mosquitoes, the same vectors as dengue. It is clinically marked by abrupt fever and severe, sometimes chronic, joint pain.$x$, $x$Community Health Nursing$x$, $x$medium$x$),
  (25, $x$Scrub typhus, caused by Orientia tsutsugamushi, is transmitted to humans through the bite of$x$, $x$["the rat flea","the hard tick","the body louse","the larval trombiculid mite, or chigger"]$x$, 3, $x$Scrub typhus is transmitted by the bite of the larval stage, or chigger, of trombiculid mites. A characteristic painless eschar at the site of the bite, along with fever and lymphadenopathy, is an important diagnostic clue.$x$, $x$Community Health Nursing$x$, $x$hard$x$),
  (26, $x$The incubation period of chickenpox, or varicella, is usually$x$, $x$["7 to 10 days","1 to 3 days","about 14 to 16 days","30 to 40 days"]$x$, 2, $x$Chickenpox, caused by the varicella-zoster virus, has an incubation period of about 14 to 16 days, with a range of 10 to 21 days. Its rash is centripetal in distribution and appears in successive crops, showing pleomorphism at any one time.$x$, $x$Community Health Nursing$x$, $x$hard$x$),
  (27, $x$The Integrated Disease Surveillance Programme, launched in India in 2004, primarily aims to$x$, $x$["provide free medicines to all citizens","detect and respond to early warning signals of epidemics","train multipurpose health workers","construct sub-centres in rural areas"]$x$, 1, $x$IDSP is a decentralised, state-based surveillance programme launched in 2004 to strengthen disease surveillance and detect early warning signals of outbreaks, enabling a timely public health response.$x$, $x$Community Health Nursing$x$, $x$medium$x$)
) as v(pos, question, options, ci, exp, topic, diff);

-- 24-medsurg-haem-shock.txt — 28 questions
with b as (
  insert into tests (title, topic, difficulty, duration_minutes)
  values ($x$w2-medsurg-c — ingested draft, verify before trusting$x$, $x$Medical-Surgical Nursing$x$, 'medium', 60)
  returning id
)
insert into questions (test_id, position, question, options, correct_index, explanation, topic, difficulty)
select b.id, v.pos::int, v.question, v.options::jsonb, v.ci::int, v.exp, v.topic, v.diff
from b, (values
  (0, $x$A 30-year-old woman with heavy menstrual bleeding has anaemia. The expected red cell morphology on her peripheral smear is$x$, $x$["Normocytic normochromic","Macrocytic normochromic","Microcytic hypochromic","Macrocytic megaloblastic"]$x$, 2, $x$Iron deficiency, the most common anaemia, produces small pale red cells that are microcytic and hypochromic with low MCV and MCH. Serum ferritin and iron fall while total iron-binding capacity rises.$x$, $x$Medical-Surgical Nursing$x$, $x$easy$x$),
  (1, $x$A patient with megaloblastic anaemia also complains of paraesthesia and impaired position sense. The most likely deficiency is$x$, $x$["Folic acid","Vitamin B12, or cobalamin","Iron","Vitamin C"]$x$, 1, $x$Both B12 and folate deficiency cause macrocytic megaloblastic anaemia, but only vitamin B12 deficiency produces neurological signs such as paraesthesia and loss of proprioception from subacute combined degeneration. Folate deficiency lacks these neurological features.$x$, $x$Medical-Surgical Nursing$x$, $x$medium$x$),
  (2, $x$The characteristic blood picture in aplastic anaemia is$x$, $x$["Microcytic anaemia with target cells","Leukocytosis with circulating blasts","Isolated anaemia with a high reticulocyte count","Pancytopenia due to bone marrow hypoplasia"]$x$, 3, $x$Aplastic anaemia results from bone marrow failure, so all cell lines fall, producing pancytopenia of red cells, white cells and platelets. The reticulocyte count is low because the hypoplastic marrow cannot regenerate cells.$x$, $x$Medical-Surgical Nursing$x$, $x$medium$x$),
  (3, $x$During a sickle cell vaso-occlusive crisis, priority nursing management includes$x$, $x$["Restricting all fluids to reduce oedema","Encouraging vigorous physical activity","Hydration, oxygen and adequate analgesia","Applying cold packs to the painful joints"]$x$, 2, $x$A vaso-occlusive crisis is managed with generous hydration, supplemental oxygen, warmth and effective analgesia to relieve pain and limit further sickling. Cold application and dehydration promote sickling and must be avoided.$x$, $x$Medical-Surgical Nursing$x$, $x$medium$x$),
  (4, $x$The type of leukaemia most commonly seen in young children is$x$, $x$["Chronic myeloid leukaemia","Hairy cell leukaemia","Chronic lymphocytic leukaemia","Acute lymphoblastic leukaemia"]$x$, 3, $x$Acute lymphoblastic leukaemia is the commonest leukaemia and malignancy of childhood, with a peak incidence between 2 and 5 years of age. Chronic lymphocytic leukaemia, by contrast, is a disease of older adults.$x$, $x$Medical-Surgical Nursing$x$, $x$medium$x$),
  (5, $x$The pathognomonic cell used to diagnose Hodgkin lymphoma on lymph node biopsy is the$x$, $x$["Auer rod","Smudge cell","Reed-Sternberg cell","Heinz body"]$x$, 2, $x$The Reed-Sternberg cell is a large binucleate owl-eye cell whose presence is the diagnostic hallmark of Hodgkin lymphoma. Its absence, along with a more disseminated nodal pattern, characterises non-Hodgkin lymphoma.$x$, $x$Medical-Surgical Nursing$x$, $x$hard$x$),
  (6, $x$Haemophilia A results from a deficiency of clotting$x$, $x$["Fibrinogen","Factor IX","Factor VIII","Factor XI"]$x$, 2, $x$Haemophilia A is an X-linked recessive disorder caused by a deficiency of factor VIII, leading to prolonged bleeding and haemarthrosis. Haemophilia B, or Christmas disease, results instead from factor IX deficiency.$x$, $x$Medical-Surgical Nursing$x$, $x$medium$x$),
  (7, $x$Idiopathic or immune thrombocytopenic purpura is caused by$x$, $x$["Increased platelet production in the marrow","A deficiency of factor VIII","Autoimmune destruction of circulating platelets","Aplasia of the bone marrow"]$x$, 2, $x$In immune thrombocytopenic purpura, autoantibodies, usually IgG, coat the platelets, which are then destroyed in the spleen, producing a low platelet count. Patients typically present with petechiae, purpura and easy bruising.$x$, $x$Medical-Surgical Nursing$x$, $x$medium$x$),
  (8, $x$A hallmark laboratory finding in disseminated intravascular coagulation is$x$, $x$["An isolated microcytic anaemia","High fibrinogen with a low D-dimer","Prolonged PT and PTT, low fibrinogen and elevated D-dimer","Normal PT and PTT with a high platelet count"]$x$, 2, $x$DIC involves simultaneous widespread clotting and bleeding that consumes platelets and clotting factors. This produces prolonged PT and PTT, low fibrinogen and platelets, and elevated D-dimer and fibrin degradation products.$x$, $x$Medical-Surgical Nursing$x$, $x$hard$x$),
  (9, $x$Platelet concentrates for transfusion are correctly stored at$x$, $x$["37 degrees in an incubator","2 to 6 degrees without agitation","20 to 24 degrees with continuous gentle agitation","minus 18 degrees in a frozen state"]$x$, 2, $x$Platelets are kept at room temperature, 20 to 24 degrees, with constant gentle agitation to preserve their function, and have a short shelf life of about five days. Refrigeration damages platelets, unlike packed red cells which are stored at 2 to 6 degrees.$x$, $x$Medical-Surgical Nursing$x$, $x$hard$x$),
  (10, $x$In an HIV-positive adult, AIDS is diagnosed when the CD4 count falls below$x$, $x$["800 cells per cubic mm","200 cells per cubic mm","500 cells per cubic mm","1000 cells per cubic mm"]$x$, 1, $x$A CD4 T-lymphocyte count below 200 cells per cubic mm, or an AIDS-defining opportunistic illness, marks progression from HIV infection to AIDS. HIV selectively destroys CD4 helper T-cells, producing profound immunosuppression.$x$, $x$Medical-Surgical Nursing$x$, $x$medium$x$),
  (11, $x$Zidovudine, used in the treatment of HIV, belongs to which drug class?$x$, $x$["Protease inhibitor","Fusion inhibitor","Integrase inhibitor","Nucleoside reverse transcriptase inhibitor"]$x$, 3, $x$Zidovudine is a nucleoside reverse transcriptase inhibitor that blocks reverse transcriptase, preventing conversion of viral RNA into DNA. Combination antiretroviral therapy combines several drug classes to suppress viral replication and preserve immunity.$x$, $x$Medical-Surgical Nursing$x$, $x$hard$x$),
  (12, $x$Anaphylaxis is an example of which type of hypersensitivity reaction?$x$, $x$["Type I, immediate and IgE-mediated","Type II, cytotoxic","Type III, immune complex","Type IV, delayed and cell-mediated"]$x$, 0, $x$Anaphylaxis is a Type I immediate hypersensitivity reaction driven by IgE-triggered degranulation of mast cells and basophils, releasing histamine. Type IV delayed reactions, such as the Mantoux test and contact dermatitis, are T-cell mediated instead.$x$, $x$Medical-Surgical Nursing$x$, $x$hard$x$),
  (13, $x$A classic clinical feature of systemic lupus erythematosus is$x$, $x$["A butterfly or malar rash over the cheeks and nose","Painless enlargement of the neck lymph nodes","Silvery scaling plaques on the extensor surfaces","Bronze pigmentation of the skin"]$x$, 0, $x$SLE is an autoimmune disorder that classically produces a photosensitive butterfly-shaped malar rash across the cheeks and bridge of the nose. A positive antinuclear antibody and anti-double-stranded DNA antibody support the diagnosis.$x$, $x$Medical-Surgical Nursing$x$, $x$medium$x$),
  (14, $x$The single most important first-line drug in the emergency management of anaphylaxis is$x$, $x$["An oral antihistamine","Intramuscular adrenaline, or epinephrine","Intravenous hydrocortisone","Nebulised salbutamol"]$x$, 1, $x$Intramuscular adrenaline is the first and most vital drug in anaphylaxis; it reverses bronchospasm and vasodilation and supports the blood pressure. Antihistamines and corticosteroids are only adjuncts given after adrenaline.$x$, $x$Medical-Surgical Nursing$x$, $x$easy$x$),
  (15, $x$Which set of findings is most characteristic of neurogenic shock?$x$, $x$["Fever with a bounding pulse","Hypertension with bradycardia","Hypotension with bradycardia and warm, dry skin","Tachycardia with cold, clammy skin"]$x$, 2, $x$Neurogenic shock, often from spinal cord injury, causes loss of sympathetic tone, producing hypotension with bradycardia and warm, dry, flushed skin. This differs from hypovolaemic shock, in which the skin is cold and clammy with tachycardia.$x$, $x$Medical-Surgical Nursing$x$, $x$medium$x$),
  (16, $x$The earliest stage of shock, in which blood pressure is still maintained by sympathetic compensation, is the$x$, $x$["Compensatory or initial stage","Progressive stage","Refractory or irreversible stage","Terminal necrotic stage"]$x$, 0, $x$In the compensatory stage the body preserves blood pressure through vasoconstriction, increased heart rate and shunting of blood to vital organs. If uncorrected, shock advances to the progressive stage and finally the irreversible stage.$x$, $x$Medical-Surgical Nursing$x$, $x$hard$x$),
  (17, $x$In the early, or warm, phase of septic shock, the patient's skin is typically$x$, $x$["Cyanotic and mottled","Cold, pale and clammy","Deeply jaundiced","Warm, flushed and dry"]$x$, 3, $x$Early septic shock is a distributive shock with massive vasodilation, producing warm, flushed, dry skin and a bounding pulse. As compensation fails, perfusion drops and the skin becomes cold and clammy.$x$, $x$Medical-Surgical Nursing$x$, $x$hard$x$),
  (18, $x$A burn that destroys the whole epidermis and dermis and appears dry, leathery and painless is classified as$x$, $x$["Deep partial-thickness burn","Superficial partial-thickness burn","Superficial, or first-degree, burn","Full-thickness, or third-degree, burn"]$x$, 3, $x$Full-thickness or third-degree burns destroy the entire epidermis and dermis, including nerve endings, so they look dry, leathery, white or charred and are painless. Superficial burns remain red and painful because sensory endings are intact.$x$, $x$Medical-Surgical Nursing$x$, $x$easy$x$),
  (19, $x$A pressure injury showing full-thickness skin loss with visible subcutaneous fat, but no exposed bone, tendon or muscle, is classified as$x$, $x$["Stage 1","Stage 4","Stage 2","Stage 3"]$x$, 3, $x$A Stage 3 pressure injury involves full-thickness skin loss with visible subcutaneous fat, but bone, tendon and muscle are not exposed. Stage 4 injuries extend deeper, exposing bone, tendon or muscle.$x$, $x$Medical-Surgical Nursing$x$, $x$medium$x$),
  (20, $x$Psoriasis is typically characterised by$x$, $x$["Well-defined plaques covered with silvery scales","Fluid-filled vesicles along a dermatome","A single honey-coloured crusted lesion","Hypopigmented, anaesthetic patches"]$x$, 0, $x$Psoriasis is a chronic immune-mediated skin disorder producing sharply demarcated erythematous plaques topped with silvery-white scales, usually on extensor surfaces. Removing the scale may cause pinpoint bleeding, known as the Auspitz sign.$x$, $x$Medical-Surgical Nursing$x$, $x$easy$x$),
  (21, $x$With respect to surgical informed consent, the nurse's primary role is to$x$, $x$["Explain the surgical procedure and its risks","Sign the consent form on the patient's behalf","Decide whether the surgery should proceed","Witness the patient's signature and confirm understanding"]$x$, 3, $x$Explaining the procedure, risks and alternatives to obtain informed consent is the surgeon's responsibility. The nurse witnesses the signature, confirms that the patient understands, and ensures the consent form is complete before surgery.$x$, $x$Medical-Surgical Nursing$x$, $x$easy$x$),
  (22, $x$If a postoperative abdominal wound eviscerates with loops of bowel protruding, the nurse should first$x$, $x$["Push the organs back into the abdomen","Cover the organs with sterile saline-soaked gauze","Leave the wound open and exposed to air","Apply a dry, firm pressure dressing"]$x$, 1, $x$In evisceration the nurse covers the protruding viscera with sterile gauze moistened in normal saline to keep them moist, places the patient supine with knees flexed, and notifies the surgeon for emergency repair. The organs are never pushed back in.$x$, $x$Medical-Surgical Nursing$x$, $x$medium$x$),
  (23, $x$In the post-anaesthesia care unit, the highest nursing priority for a patient recovering from general anaesthesia is$x$, $x$["Reorienting the patient to time and place","Assessing the surgical dressing","Maintaining a patent airway and adequate ventilation","Managing postoperative pain"]$x$, 2, $x$Airway and breathing take top priority in recovery because residual anaesthesia can cause airway obstruction and respiratory depression. Once airway, breathing and circulation are secured, the nurse addresses pain, dressings and orientation.$x$, $x$Medical-Surgical Nursing$x$, $x$medium$x$),
  (24, $x$Cataract is best defined as$x$, $x$["Inflammation of the conjunctiva","Opacification or clouding of the lens","A raised intraocular pressure that damages the optic nerve","Separation of the retina from the underlying layer"]$x$, 1, $x$A cataract is a clouding or opacification of the normally transparent crystalline lens, causing progressive painless blurring of vision and glare. Treatment is surgical removal of the lens with implantation of an intraocular lens.$x$, $x$Medical-Surgical Nursing$x$, $x$easy$x$),
  (25, $x$A patient presents with a sudden red, painful eye, halos around lights, a mid-dilated fixed pupil and nausea. This is most consistent with$x$, $x$["Acute angle-closure glaucoma","Bacterial conjunctivitis","Chronic open-angle glaucoma","Senile cataract"]$x$, 0, $x$Acute angle-closure glaucoma is an emergency causing a sudden painful red eye, blurred vision with halos, a fixed mid-dilated pupil and often nausea from a rapid rise in intraocular pressure. Open-angle glaucoma, by contrast, is painless and gradual.$x$, $x$Medical-Surgical Nursing$x$, $x$hard$x$),
  (26, $x$Correct first aid for a venomous snake bite to the leg includes$x$, $x$["Immobilising the limb at or below heart level and keeping the patient calm","Applying a tight arterial tourniquet above the bite","Applying ice and encouraging the patient to walk","Incising the wound and sucking out the venom"]$x$, 0, $x$Current guidelines advise keeping the patient calm and still, immobilising the bitten limb at or below heart level, and transporting urgently for antivenom. Tourniquets, incision, suction and ice cause harm and are no longer recommended.$x$, $x$Medical-Surgical Nursing$x$, $x$medium$x$),
  (27, $x$A Glasgow Coma Scale score of 8 or less generally indicates$x$, $x$["A moderate head injury","A mild head injury with full alertness","A severe head injury or coma requiring airway protection","A completely normal neurological status"]$x$, 2, $x$The Glasgow Coma Scale ranges from 3 in deep coma to 15 when fully alert. A score of 8 or less denotes severe brain injury or coma, and such patients usually need intubation to protect the airway; 9 to 12 is moderate and 13 to 15 is mild.$x$, $x$Medical-Surgical Nursing$x$, $x$hard$x$)
) as v(pos, question, options, ci, exp, topic, diff);

-- 25-obg-labour-neonate.txt — 29 questions
with b as (
  insert into tests (title, topic, difficulty, duration_minutes)
  values ($x$w2-obg-b — ingested draft, verify before trusting$x$, $x$Obstetrics & Child Health$x$, 'medium', 60)
  returning id
)
insert into questions (test_id, position, question, options, correct_index, explanation, topic, difficulty)
select b.id, v.pos::int, v.question, v.options::jsonb, v.ci::int, v.exp, v.topic, v.diff
from b, (values
  (0, $x$A student nurse is asked to list the cardinal movements of labour in order. Which sequence is correct?$x$, $x$["Engagement, descent, flexion, internal rotation, extension, restitution and external rotation, expulsion","Engagement, flexion, extension, descent, internal rotation, expulsion","Flexion, engagement, descent, extension, internal rotation, expulsion","Descent, engagement, extension, flexion, internal rotation, expulsion"]$x$, 0, $x$The cardinal movements occur in sequence: engagement, descent, flexion, internal rotation, extension, restitution with external rotation, and finally expulsion. These allow the smallest fetal head diameters to negotiate the maternal pelvis.$x$, $x$Obstetrics & Child Health$x$, $x$easy$x$),
  (1, $x$Engagement of the fetal head is said to have occurred when$x$, $x$["The occiput rotates anteriorly to the symphysis","The head reaches the pelvic floor","The head becomes visible at the vulva","The biparietal diameter of the head passes through the pelvic inlet"]$x$, 3, $x$Engagement is defined as passage of the biparietal diameter, the widest transverse diameter of the head, through the pelvic inlet. In primigravidae it usually occurs during the last few weeks before labour.$x$, $x$Obstetrics & Child Health$x$, $x$medium$x$),
  (2, $x$Internal rotation of the fetal head during normal labour is brought about chiefly by the$x$, $x$["Bony pelvic inlet","Uterine contractions acting alone","Maternal bearing-down efforts","Gutter-shaped levator ani of the pelvic floor"]$x$, 3, $x$Internal rotation brings the occiput anteriorly beneath the symphysis and is produced chiefly by the gutter-shaped, forward-sloping levator ani of the pelvic floor. The uterine forces drive the head down onto this pelvic floor to effect rotation.$x$, $x$Obstetrics & Child Health$x$, $x$hard$x$),
  (3, $x$In the mechanism of labour, restitution refers to$x$, $x$["Rotation of the shoulders within the pelvis","Untwisting of the head to restore its natural relationship with the shoulders after the head is born","Anterior rotation of the occiput to the symphysis","Downward movement of the presenting part"]$x$, 1, $x$Restitution is the passive untwisting of the fetal neck once the head is delivered, restoring its natural alignment with the shoulders. It is followed by external rotation as the shoulders rotate internally into the anteroposterior diameter.$x$, $x$Obstetrics & Child Health$x$, $x$medium$x$),
  (4, $x$Which feature best distinguishes true labour from false labour?$x$, $x$["Complete absence of any bloody show","Irregular contractions relieved by rest or sedation","Pain confined to the lower abdomen with no cervical change","Regular painful contractions producing progressive cervical effacement and dilatation"]$x$, 3, $x$True labour is marked by regular, progressively stronger painful contractions that produce demonstrable effacement and dilatation of the cervix. False, or Braxton Hicks, contractions are irregular, do not dilate the cervix, and ease with rest.$x$, $x$Obstetrics & Child Health$x$, $x$easy$x$),
  (5, $x$Cervical effacement during labour refers to$x$, $x$["Spontaneous rupture of the membranes","Descent of the presenting part","Shortening and thinning, or taking up, of the cervical canal","Opening of the external cervical os"]$x$, 2, $x$Effacement is the shortening and thinning, or taking up, of the cervical canal so that it merges with the lower uterine segment. Dilatation is a separate process describing the opening of the external os, measured in centimetres.$x$, $x$Obstetrics & Child Health$x$, $x$medium$x$),
  (6, $x$In a low-risk woman during the first stage of labour, the fetal heart by intermittent auscultation should be checked$x$, $x$["Every 30 minutes, just after a contraction","Only once every hour","Every 5 minutes","Continuously by scalp electrode in all cases"]$x$, 0, $x$In low-risk labour the fetal heart is auscultated every 30 minutes during the first stage, ideally just after a contraction, and every 5 minutes or after each contraction in the second stage. This timing helps detect fetal compromise early.$x$, $x$Obstetrics & Child Health$x$, $x$medium$x$),
  (7, $x$The most effective and titratable method of regional analgesia for pain relief in labour is$x$, $x$["Lumbar epidural analgesia","Inhaled nitrous oxide","Intramuscular pethidine","Paracervical block"]$x$, 0, $x$Lumbar epidural analgesia provides the most effective and titratable pain relief in labour by blocking pain transmission at the spinal nerve roots. It preserves maternal consciousness while allowing continuous analgesia through the indwelling catheter.$x$, $x$Obstetrics & Child Health$x$, $x$medium$x$),
  (8, $x$A woman in obstructed labour suddenly develops cessation of contractions, severe abdominal pain, maternal shock, and easily palpable fetal parts through the abdomen. The most likely diagnosis is$x$, $x$["Placental abruption","Uterine inversion","Amniotic fluid embolism","Rupture of the uterus"]$x$, 3, $x$Rupture of the uterus classically follows obstructed labour and presents with sudden cessation of contractions, severe pain, maternal shock, and easily palpable fetal parts as the fetus escapes into the abdomen. It is an emergency requiring immediate laparotomy.$x$, $x$Obstetrics & Child Health$x$, $x$hard$x$),
  (9, $x$Sudden cardiorespiratory collapse with hypoxia, hypotension and disseminated intravascular coagulation occurring during labour or immediately after delivery is most characteristic of$x$, $x$["Amniotic fluid embolism","Vasovagal syncope","Mendelson's syndrome","Deep vein thrombosis"]$x$, 0, $x$Amniotic fluid embolism presents as sudden collapse with hypoxia, hypotension and disseminated intravascular coagulation during labour or immediately postpartum. It is a rare but often fatal anaphylactoid reaction to amniotic fluid entering the maternal circulation.$x$, $x$Obstetrics & Child Health$x$, $x$hard$x$),
  (10, $x$The recommended first-line manoeuvre for the management of shoulder dystocia is$x$, $x$["McRoberts manoeuvre with suprapubic pressure","Immediate caesarean section","Fundal pressure","Zavanelli manoeuvre as the initial step"]$x$, 0, $x$The McRoberts manoeuvre, sharp hyperflexion of the maternal thighs against the abdomen, combined with suprapubic pressure is the first-line response to shoulder dystocia. Fundal pressure is contraindicated because it worsens the shoulder impaction.$x$, $x$Obstetrics & Child Health$x$, $x$medium$x$),
  (11, $x$Acute inversion of the uterus is most commonly caused by$x$, $x$["Prolonged second stage of labour","Multiple pregnancy","Improper third-stage management such as cord traction on a relaxed uterus","Precipitate labour"]$x$, 2, $x$Acute uterine inversion most often results from mismanaged third stage, particularly cord traction with fundal pressure applied to a relaxed uterus carrying a fundal placenta. It causes profound neurogenic shock and requires immediate replacement of the uterus.$x$, $x$Obstetrics & Child Health$x$, $x$hard$x$),
  (12, $x$The modified Bishop score used to assess cervical favourability for induction includes all of the following except$x$, $x$["Fetal heart rate","Cervical dilatation","Station of the presenting part","Cervical consistency"]$x$, 0, $x$The modified Bishop score assesses cervical dilatation, effacement, consistency, position, and the station of the presenting part to judge favourability for induction. Fetal heart rate is not one of its five components.$x$, $x$Obstetrics & Child Health$x$, $x$hard$x$),
  (13, $x$An advantage of obstetric forceps over the ventouse, or vacuum, is that forceps$x$, $x$["Are contraindicated in face presentation","Cause less maternal soft-tissue trauma","Can be applied before full cervical dilatation","Can be used when the mother is unable to bear down, such as under general anaesthesia"]$x$, 3, $x$Forceps can deliver the head when the mother cannot bear down, as under general anaesthesia or with maternal exhaustion, because they provide traction independent of maternal effort. The ventouse, in contrast, needs the mother's expulsive effort to succeed.$x$, $x$Obstetrics & Child Health$x$, $x$medium$x$),
  (14, $x$The puerperium is conventionally defined as lasting approximately$x$, $x$["2 weeks","4 weeks","6 weeks","12 weeks"]$x$, 2, $x$The puerperium is the period after delivery during which the reproductive organs return towards their non-pregnant state, lasting about six weeks or 42 days. Most of the involutionary changes are largely complete by the end of this time.$x$, $x$Obstetrics & Child Health$x$, $x$easy$x$),
  (15, $x$The hormone chiefly responsible for the synthesis and secretion of milk by the breast alveoli is$x$, $x$["Progesterone","Oxytocin","Prolactin","Oestrogen"]$x$, 2, $x$Prolactin, secreted by the anterior pituitary, stimulates the alveolar cells of the breast to synthesise and secrete milk. Its milk-producing action becomes unopposed after delivery once placental oestrogen and progesterone levels fall.$x$, $x$Obstetrics & Child Health$x$, $x$easy$x$),
  (16, $x$The let-down, or milk-ejection, reflex during breastfeeding is mediated by$x$, $x$["Oxytocin acting on the myoepithelial cells around the alveoli","Prolactin acting on the ductal cells","Human placental lactogen","Progesterone withdrawal"]$x$, 0, $x$The let-down or milk-ejection reflex is mediated by oxytocin released from the posterior pituitary in response to suckling. Oxytocin contracts the myoepithelial cells surrounding the alveoli, ejecting stored milk into the ducts.$x$, $x$Obstetrics & Child Health$x$, $x$medium$x$),
  (17, $x$Menorrhagia is best defined as$x$, $x$["Complete absence of menstruation","Bleeding occurring between periods","Regular cyclical menstrual bleeding that is excessive in amount or duration","Painful menstruation"]$x$, 2, $x$Menorrhagia denotes cyclical, regular menstrual bleeding that is excessive in amount, over 80 mL, or in duration. Bleeding between periods is termed metrorrhagia, while painful menstruation is dysmenorrhoea.$x$, $x$Obstetrics & Child Health$x$, $x$medium$x$),
  (18, $x$Primary dysmenorrhoea is primarily caused by$x$, $x$["Excess endometrial prostaglandin production","Endometriosis","Uterine fibroids","Pelvic inflammatory disease"]$x$, 0, $x$Primary dysmenorrhoea occurs without underlying pelvic pathology and is caused by excessive endometrial prostaglandin, which provokes painful uterine hypercontractility and ischaemia. This explains why prostaglandin-inhibiting NSAIDs relieve the pain.$x$, $x$Obstetrics & Child Health$x$, $x$easy$x$),
  (19, $x$According to the Rotterdam criteria, polycystic ovary syndrome is diagnosed by at least two of$x$, $x$["Amenorrhoea, galactorrhoea and infertility","Oligo- or anovulation, hyperandrogenism, and polycystic ovaries on ultrasound","Hypertension, obesity and hirsutism","Raised prolactin, low FSH and high TSH"]$x$, 1, $x$The Rotterdam criteria diagnose PCOS when at least two of three features are present: oligo- or anovulation, clinical or biochemical hyperandrogenism, and polycystic ovarian morphology on ultrasound. Other endocrine causes must first be excluded.$x$, $x$Obstetrics & Child Health$x$, $x$medium$x$),
  (20, $x$The single most important aetiological agent in carcinoma of the cervix is$x$, $x$["Herpes simplex virus type 1","Persistent infection with high-risk HPV types 16 and 18","Chlamydia trachomatis","Human immunodeficiency virus"]$x$, 1, $x$Persistent infection with high-risk human papillomavirus, especially types 16 and 18, is the central cause of cervical cancer and its precursor lesions. This understanding underlies both HPV vaccination and Pap-smear screening programmes.$x$, $x$Obstetrics & Child Health$x$, $x$medium$x$),
  (21, $x$Which reflex is elicited by stroking the corner of a newborn's mouth or cheek, making the baby turn its head toward the stimulus?$x$, $x$["Palmar grasp reflex","Rooting reflex","Moro reflex","Babinski reflex"]$x$, 1, $x$The rooting reflex is elicited by stroking the corner of the newborn's mouth or cheek, causing the baby to turn the head toward the stimulus in search of the nipple. It is a normal primitive reflex that helps initiate breastfeeding.$x$, $x$Obstetrics & Child Health$x$, $x$easy$x$),
  (22, $x$Koplik's spots on the buccal mucosa are pathognomonic of$x$, $x$["Scarlet fever","Measles, or rubeola","Chickenpox","Rubella"]$x$, 1, $x$Koplik's spots are small white lesions on the buccal mucosa opposite the molar teeth and are pathognomonic of measles, appearing during the prodrome before the skin rash. Their recognition helps distinguish measles from other childhood exanthems.$x$, $x$Obstetrics & Child Health$x$, $x$easy$x$),
  (23, $x$During neonatal resuscitation, the recommended chest compression to ventilation ratio is$x$, $x$["15 to 2","30 to 2","5 to 1","3 to 1, giving about 90 compressions and 30 breaths per minute"]$x$, 3, $x$Neonatal resuscitation uses a 3 to 1 compression-to-ventilation ratio, delivering about 90 chest compressions and 30 breaths each minute. This higher ventilation emphasis reflects the predominantly respiratory or asphyxial origin of most newborn arrests.$x$, $x$Obstetrics & Child Health$x$, $x$hard$x$),
  (24, $x$Respiratory distress syndrome, or hyaline membrane disease, in the preterm newborn results from$x$, $x$["Congenital bacterial pneumonia","Congenital diaphragmatic hernia","Deficiency of pulmonary surfactant","Aspiration of meconium"]$x$, 2, $x$Respiratory distress syndrome of the preterm neonate is due to deficiency of pulmonary surfactant produced by type II pneumocytes. Lack of surfactant causes progressive alveolar collapse, hypoxia and characteristic grunting respiration.$x$, $x$Obstetrics & Child Health$x$, $x$medium$x$),
  (25, $x$Which statement correctly distinguishes a cephalhaematoma from a caput succedaneum?$x$, $x$["A cephalhaematoma is maximal at birth and resolves within 24 hours","A cephalhaematoma is bounded by suture lines and does not cross them, whereas caput succedaneum crosses suture lines","A cephalhaematoma crosses suture lines whereas caput does not","Caput succedaneum is a subperiosteal haemorrhage"]$x$, 1, $x$A cephalhaematoma is a subperiosteal bleed limited by the cranial suture lines, so it never crosses sutures and resolves over weeks. Caput succedaneum is diffuse scalp oedema that does cross suture lines and settles within a few days.$x$, $x$Obstetrics & Child Health$x$, $x$hard$x$),
  (26, $x$Early-onset neonatal sepsis, occurring within the first 72 hours of life, is most commonly acquired$x$, $x$["From nursery equipment in the hospital environment","From the maternal genital tract during birth","By droplet spread from visitors","Through breast milk"]$x$, 1, $x$Early-onset neonatal sepsis, arising within the first 72 hours, is usually acquired vertically from the maternal genital tract, with organisms such as Group B Streptococcus and E. coli. Late-onset sepsis is more often nosocomial or community-acquired.$x$, $x$Obstetrics & Child Health$x$, $x$medium$x$),
  (27, $x$Retinopathy of prematurity is most strongly associated with$x$, $x$["Neonatal hyperbilirubinaemia","Birth asphyxia","Maternal rubella infection","Prematurity with exposure to high concentrations of supplemental oxygen"]$x$, 3, $x$Retinopathy of prematurity is a vasoproliferative retinal disorder linked strongly to prematurity and exposure to high concentrations of supplemental oxygen. Careful oxygen control and screening of preterm infants help prevent progression to blindness.$x$, $x$Obstetrics & Child Health$x$, $x$hard$x$),
  (28, $x$A 4-week-old male infant presents with progressive non-bilious projectile vomiting after feeds and a palpable olive-shaped mass in the epigastrium. The most likely diagnosis is$x$, $x$["Gastro-oesophageal reflux","Intussusception","Hypertrophic pyloric stenosis","Duodenal atresia"]$x$, 2, $x$Infantile hypertrophic pyloric stenosis typically presents around three to six weeks with progressive non-bilious projectile vomiting and a palpable olive-shaped epigastric mass. Hypertrophy of the pyloric muscle produces gastric outlet obstruction.$x$, $x$Obstetrics & Child Health$x$, $x$hard$x$)
) as v(pos, question, options, ci, exp, topic, diff);

-- 26-basic-systems.txt — 30 questions
with b as (
  insert into tests (title, topic, difficulty, duration_minutes)
  values ($x$w2-basic-b — ingested draft, verify before trusting$x$, $x$Basic Sciences$x$, 'medium', 60)
  returning id
)
insert into questions (test_id, position, question, options, correct_index, explanation, topic, difficulty)
select b.id, v.pos::int, v.question, v.options::jsonb, v.ci::int, v.exp, v.topic, v.diff
from b, (values
  (0, $x$Which type of muscle tissue is striated in appearance yet functions under involuntary control?$x$, $x$["Smooth muscle","Skeletal muscle","Both skeletal and smooth","Cardiac muscle"]$x$, 3, $x$Cardiac muscle shows cross-striations like skeletal muscle but, like smooth muscle, is controlled involuntarily by the autonomic nervous system and intrinsic pacemakers. Skeletal muscle is striated and voluntary, while smooth muscle is non-striated and involuntary.$x$, $x$Basic Sciences$x$, $x$easy$x$),
  (1, $x$The functional contractile unit of skeletal muscle, lying between two adjacent Z-lines, is the$x$, $x$["Sarcomere","Myofibril","Sarcoplasmic reticulum","Sarcolemma"]$x$, 0, $x$The sarcomere is the region between two Z-lines and is the basic repeating contractile unit of striated muscle. According to the sliding filament theory, actin and myosin filaments slide past one another to shorten each sarcomere during contraction.$x$, $x$Basic Sciences$x$, $x$medium$x$),
  (2, $x$The carpometacarpal joint at the base of the thumb is classified as which type of synovial joint?$x$, $x$["Pivot joint","Saddle joint","Hinge joint","Ball-and-socket joint"]$x$, 1, $x$The thumb carpometacarpal joint is the classic example of a saddle joint, whose reciprocally concave and convex surfaces allow flexion, extension, abduction, adduction and opposition. This wide range of movement gives humans their characteristic thumb dexterity.$x$, $x$Basic Sciences$x$, $x$medium$x$),
  (3, $x$Which cranial nerve carries impulses for the special sense of vision?$x$, $x$["Oculomotor nerve, III","Abducens nerve, VI","Optic nerve, II","Trochlear nerve, IV"]$x$, 2, $x$The optic nerve, cranial nerve II, is purely sensory and transmits visual impulses from the retina to the brain. The oculomotor, trochlear and abducens nerves are motor nerves that move the eyeball rather than mediate vision itself.$x$, $x$Basic Sciences$x$, $x$easy$x$),
  (4, $x$The principal nerve carrying sensation from the face and supplying the muscles of mastication is the$x$, $x$["Glossopharyngeal nerve, IX","Facial nerve, VII","Trigeminal nerve, V","Vagus nerve, X"]$x$, 2, $x$The trigeminal nerve is the chief sensory nerve of the face and also provides motor supply to the muscles of mastication. The facial nerve, in contrast, supplies the muscles of facial expression rather than chewing.$x$, $x$Basic Sciences$x$, $x$medium$x$),
  (5, $x$Which of the following is an effect of parasympathetic, or vagal, stimulation?$x$, $x$["Dilation of the pupil","Bronchodilation","Increased gastrointestinal motility and secretion","Acceleration of heart rate"]$x$, 2, $x$Parasympathetic activity promotes rest-and-digest functions, increasing gut motility, glandular secretion and salivation. It also constricts the pupil, slows the heart and causes bronchoconstriction, which are the opposite of sympathetic actions.$x$, $x$Basic Sciences$x$, $x$medium$x$),
  (6, $x$The outermost and toughest of the three meningeal layers covering the brain and spinal cord is the$x$, $x$["Arachnoid mater","Choroid plexus","Dura mater","Pia mater"]$x$, 2, $x$The three meninges from outside inward are the dura mater, arachnoid mater and pia mater. The dura is the thick, fibrous outermost layer, while the delicate pia mater adheres closely to the surface of the brain and cord.$x$, $x$Basic Sciences$x$, $x$easy$x$),
  (7, $x$Coordination of voluntary movements and maintenance of posture and balance is chiefly the function of the$x$, $x$["Medulla oblongata","Cerebellum","Hypothalamus","Thalamus"]$x$, 1, $x$The cerebellum coordinates the timing and smoothness of voluntary movement and helps maintain equilibrium and posture. Damage to it produces ataxia, incoordination and disturbances of balance rather than paralysis.$x$, $x$Basic Sciences$x$, $x$easy$x$),
  (8, $x$Which sequence correctly represents the components of a typical reflex arc?$x$, $x$["Receptor, afferent neuron, centre, efferent neuron, effector","Effector, efferent neuron, centre, afferent neuron, receptor","Afferent neuron, receptor, centre, effector, efferent neuron","Receptor, efferent neuron, centre, afferent neuron, effector"]$x$, 0, $x$A reflex arc begins at a receptor, travels along an afferent or sensory neuron to an integrating centre, then out via an efferent or motor neuron to an effector such as a muscle or gland. This pathway allows rapid, involuntary responses to stimuli.$x$, $x$Basic Sciences$x$, $x$hard$x$),
  (9, $x$After originating in the SA node, the normal sequence of cardiac impulse conduction is$x$, $x$["Purkinje fibres, AV node, bundle of His","AV node, Purkinje fibres, bundle of His","AV node, bundle of His, Purkinje fibres","Bundle of His, AV node, Purkinje fibres"]$x$, 2, $x$The impulse passes from the atrioventricular node to the bundle of His, then along its branches to the Purkinje fibres that excite the ventricular myocardium. The AV node introduces a brief delay allowing the atria to empty before the ventricles contract.$x$, $x$Basic Sciences$x$, $x$hard$x$),
  (10, $x$Starling's law of the heart states that, within physiological limits, the force of ventricular contraction is$x$, $x$["Directly proportional to the end-diastolic length of cardiac muscle fibres","Independent of the initial fibre length","Determined solely by the heart rate","Inversely proportional to venous return"]$x$, 0, $x$Starling's law states that the greater the end-diastolic stretch of cardiac muscle fibres, the greater the force of the subsequent contraction. This intrinsic mechanism allows the heart to match its output to increases in venous return.$x$, $x$Basic Sciences$x$, $x$hard$x$),
  (11, $x$Mean arterial blood pressure is principally determined by the product of$x$, $x$["Venous return and lung compliance","Heart rate and blood viscosity","Cardiac output and systemic vascular resistance","Stroke volume and haematocrit"]$x$, 2, $x$Mean arterial pressure is the product of cardiac output and systemic vascular resistance. A rise in either the amount of blood pumped or the resistance of the peripheral vessels will therefore raise the arterial blood pressure.$x$, $x$Basic Sciences$x$, $x$medium$x$),
  (12, $x$The basic rhythm of breathing is generated by the respiratory centres located mainly in the$x$, $x$["Cerebellum","Medulla oblongata and pons","Thalamus","Hypothalamus"]$x$, 1, $x$The medulla oblongata contains the fundamental rhythm-generating centres for respiration, with the pons providing fine modulation through its pneumotaxic and apneustic areas. These centres adjust ventilation in response to chemical and neural signals.$x$, $x$Basic Sciences$x$, $x$medium$x$),
  (13, $x$The Hering-Breuer inflation reflex, which limits over-distension of the lungs, is mediated by afferent fibres travelling in the$x$, $x$["Intercostal nerves","Vagus nerve","Phrenic nerve","Glossopharyngeal nerve"]$x$, 1, $x$Stretch receptors in the airways detect lung inflation and send impulses along the vagus nerve to the respiratory centre, inhibiting further inspiration. This Hering-Breuer reflex protects the lungs from excessive expansion.$x$, $x$Basic Sciences$x$, $x$hard$x$),
  (14, $x$Gastrin, secreted by the G cells of the gastric antrum, chiefly stimulates$x$, $x$["Contraction of the gall bladder","Secretion of pancreatic bicarbonate","Secretion of hydrochloric acid by parietal cells","Release of insulin from the pancreas"]$x$, 2, $x$Gastrin is released by antral G cells and stimulates the parietal cells to secrete hydrochloric acid, promoting gastric digestion. It also increases gastric motility and mucosal growth as part of preparing the stomach for a meal.$x$, $x$Basic Sciences$x$, $x$medium$x$),
  (15, $x$Secretin, released from the duodenal mucosa in response to acidic chyme, stimulates the pancreas to secrete a fluid rich in$x$, $x$["Digestive enzymes","Bicarbonate","Insulin","Bile pigments"]$x$, 1, $x$Secretin is released when acidic chyme enters the duodenum and drives the pancreas and biliary system to secrete a bicarbonate-rich alkaline fluid. This neutralises gastric acid and provides the optimal pH for intestinal enzymes.$x$, $x$Basic Sciences$x$, $x$hard$x$),
  (16, $x$Which of the following hormones is secreted by the anterior lobe of the pituitary gland?$x$, $x$["Oxytocin","Antidiuretic hormone","Melatonin","Growth hormone"]$x$, 3, $x$The anterior pituitary secretes growth hormone along with several other trophic hormones such as ACTH, TSH, FSH, LH and prolactin. Oxytocin and antidiuretic hormone are released from the posterior pituitary, and melatonin comes from the pineal gland.$x$, $x$Basic Sciences$x$, $x$medium$x$),
  (17, $x$Calcitonin, secreted by the parafollicular or C cells of the thyroid gland, acts primarily to$x$, $x$["Raise plasma calcium concentration","Lower plasma calcium concentration","Increase intestinal absorption of calcium","Stimulate osteoclastic bone resorption"]$x$, 1, $x$Calcitonin lowers plasma calcium by inhibiting osteoclastic bone resorption and promoting calcium deposition in bone. Its action opposes that of parathyroid hormone, helping to fine-tune calcium balance when levels rise.$x$, $x$Basic Sciences$x$, $x$medium$x$),
  (18, $x$In the human female, primary oocytes remain arrested for years in which stage of meiosis until ovulation?$x$, $x$["Anaphase I","Prophase I","Metaphase II","Telophase II"]$x$, 1, $x$Primary oocytes enter meiosis before birth and are held in prophase I until the follicle is stimulated to mature near ovulation. The secondary oocyte then arrests again in metaphase II and only completes meiosis if fertilisation occurs.$x$, $x$Basic Sciences$x$, $x$hard$x$),
  (19, $x$Which plasma lipoprotein is commonly termed bad cholesterol owing to its role in depositing cholesterol in arterial walls?$x$, $x$["Low-density lipoprotein","Chylomicron","Intermediate-density lipoprotein","High-density lipoprotein"]$x$, 0, $x$Low-density lipoprotein carries cholesterol to tissues and, in excess, deposits it in arterial walls, promoting atherosclerosis. High-density lipoprotein is protective because it transports cholesterol back to the liver for disposal.$x$, $x$Basic Sciences$x$, $x$easy$x$),
  (20, $x$Deficiency of thiamine, vitamin B1, classically produces which disease?$x$, $x$["Pellagra","Night blindness","Rickets","Beriberi"]$x$, 3, $x$Thiamine deficiency causes beriberi, which may present with peripheral neuropathy in the dry form or cardiac failure and oedema in the wet form. Thiamine acts as a coenzyme in carbohydrate metabolism, so nervous and cardiac tissues are especially affected.$x$, $x$Basic Sciences$x$, $x$easy$x$),
  (21, $x$In eukaryotic cells, the reactions of the citric acid, or Krebs, cycle take place in the$x$, $x$["Cytosol","Rough endoplasmic reticulum","Nucleus","Mitochondrial matrix"]$x$, 3, $x$The enzymes of the citric acid cycle are located in the mitochondrial matrix, where acetyl-CoA is oxidised to carbon dioxide. The reduced coenzymes produced then feed the electron transport chain on the inner mitochondrial membrane.$x$, $x$Basic Sciences$x$, $x$easy$x$),
  (22, $x$The net gain of ATP from the anaerobic glycolysis of one molecule of glucose to pyruvate is$x$, $x$["4 ATP","2 ATP","36 ATP","8 ATP"]$x$, 1, $x$Glycolysis produces four ATP by substrate-level phosphorylation but consumes two in the early steps, giving a net gain of two ATP per glucose. Additional ATP is generated only when pyruvate is further oxidised under aerobic conditions.$x$, $x$Basic Sciences$x$, $x$hard$x$),
  (23, $x$Which of the following is an essential amino acid that cannot be synthesised by the human body?$x$, $x$["Glutamic acid","Lysine","Serine","Alanine"]$x$, 1, $x$Lysine is one of the essential amino acids that must be supplied in the diet because the body cannot synthesise it. Alanine, glutamic acid and serine are non-essential amino acids that can be made from metabolic intermediates.$x$, $x$Basic Sciences$x$, $x$medium$x$),
  (24, $x$Which genus of bacteria forms heat-resistant endospores and includes the causative agent of tetanus?$x$, $x$["Clostridium","Streptococcus","Staphylococcus","Escherichia"]$x$, 0, $x$Clostridium species are Gram-positive anaerobes that produce highly resistant endospores, and Clostridium tetani causes tetanus. Endospores allow these organisms to survive heat, drying and disinfectants for long periods in soil.$x$, $x$Basic Sciences$x$, $x$medium$x$),
  (25, $x$Administration of preformed antibodies, such as anti-tetanus immunoglobulin, confers which type of immunity?$x$, $x$["Cell-mediated immunity","Innate immunity","Active natural immunity","Passive immunity"]$x$, 3, $x$Giving ready-made antibodies provides passive immunity, which acts immediately but lasts only a few weeks because the host makes no memory cells. Active immunity, by contrast, develops slowly after infection or vaccination but is long-lasting.$x$, $x$Basic Sciences$x$, $x$medium$x$),
  (26, $x$Tetanus and diphtheria vaccines, prepared from inactivated bacterial exotoxins, are examples of which type of vaccine?$x$, $x$["Live attenuated vaccine","Toxoid vaccine","Conjugate polysaccharide vaccine","Killed whole-cell vaccine"]$x$, 1, $x$Toxoid vaccines use bacterial exotoxins that have been chemically inactivated so they induce protective antibodies without causing disease. Tetanus and diphtheria toxoids are the classic examples given in routine immunisation schedules.$x$, $x$Basic Sciences$x$, $x$medium$x$),
  (27, $x$Furosemide, a widely used prototype diuretic, belongs to which pharmacological class?$x$, $x$["Proton pump inhibitor","Beta-adrenergic blocker","Opioid analgesic","Loop diuretic"]$x$, 3, $x$Furosemide is a loop diuretic that acts on the thick ascending limb to block sodium, potassium and chloride reabsorption, producing a powerful diuresis. It is widely used in oedema and heart failure to remove excess fluid.$x$, $x$Basic Sciences$x$, $x$easy$x$),
  (28, $x$A drug such as digoxin is said to have a low, or narrow, therapeutic index, meaning that$x$, $x$["Its effective dose lies far below the toxic dose","It produces no toxic effects at any dose","It has an extremely wide margin of safety","Its toxic dose is very close to its therapeutic dose"]$x$, 3, $x$A narrow therapeutic index means the toxic dose is only slightly greater than the effective dose, leaving little margin of safety. Such drugs, including digoxin, require careful dosing and often plasma-level monitoring to avoid toxicity.$x$, $x$Basic Sciences$x$, $x$hard$x$),
  (29, $x$Which drug is the classic teratogen historically responsible for limb malformations, or phocomelia, in the fetus?$x$, $x$["Thalidomide","Insulin","Penicillin","Paracetamol"]$x$, 0, $x$Thalidomide, once used for morning sickness, caused severe limb-reduction defects known as phocomelia and became the classic example of a teratogen. Its tragedy led to far stricter regulation of drug use during pregnancy.$x$, $x$Basic Sciences$x$, $x$medium$x$)
) as v(pos, question, options, ci, exp, topic, diff);

